def create_index_chart(ticker, name):
    try:
        df = fdr.DataReader(ticker, start=(datetime.now() - timedelta(days=100)))
        mc = mpf.make_marketcolors(up='r', down='b', inherit=True)
        s  = mpf.make_mpf_style(marketcolors=mc, gridstyle=':', y_on_right=False)
        fname = f"{name}.png"
        mpf.plot(df, type='candle', style=s, title=f"\n{name} Index", savefig=fname, figsize=(8, 4))
        return fname
    except: return None

def send_telegram_photo(message, image_paths=[]):
    target_chat_ids, mode_label = get_target_chat_ids()

    if not TELEGRAM_TOKEN:
        log_error('⚠️ TELEGRAM_TOKEN 없음 — 텔레그램 전송 생략')
        return

    if mode_label == 'test_missing':
        log_error('⚠️ TEST_MODE=True 이지만 TELEGRAM_TEST_CHAT_ID가 없어 테스트방 전송을 생략합니다.')
        return

    if not target_chat_ids:
        log_error('⚠️ 전송 대상 chat_id 없음 — TELEGRAM_CHAT_ID / TELEGRAM_TEST_CHAT_ID를 확인하세요.')
        return

    url_p = f"https://api.telegram.org/bot{TELEGRAM_TOKEN}/sendPhoto"
    url_t = f"https://api.telegram.org/bot{TELEGRAM_TOKEN}/sendMessage"

    text_to_send = message or ''
    if TEST_MODE:
        text_to_send = '[TEST]\n' + text_to_send if text_to_send else '[TEST]'

    for chat_id in target_chat_ids:
        try:
            if text_to_send:
                requests.post(
                    url_t,
                    data={'chat_id': chat_id, 'text': text_to_send[:4000]},
                    timeout=15,
                )

            for img in image_paths:
                if img and os.path.exists(img):
                    with open(img, 'rb') as f:
                        requests.post(
                            url_p,
                            data={'chat_id': chat_id},
                            files={'photo': f},
                            timeout=30,
                        )
        except Exception as e:
            log_error(f'⚠️ 텔레그램 전송 실패 ({chat_id}): {e}')

    for img in image_paths:
        if img and os.path.exists(img):
            try:
                os.remove(img)
            except Exception:
                pass



    def send_telegram_document(file_path: str, caption: str = ''):
        target_chat_ids, mode_label = get_target_chat_ids()

        if not TELEGRAM_TOKEN:
            log_error('⚠️ TELEGRAM_TOKEN 없음 — HTML 리포트 문서 전송 생략')
            return

        if mode_label == 'test_missing':
            log_error('⚠️ TEST_MODE=True 이지만 TELEGRAM_TEST_CHAT_ID가 없어 HTML 리포트 전송을 생략합니다.')
            return

        if not target_chat_ids:
            log_error('⚠️ 전송 대상 chat_id 없음 — HTML 리포트 문서 전송 생략')
            return

        if not file_path or not os.path.exists(file_path):
            log_error(f'⚠️ HTML 리포트 파일이 없어 전송 생략: {file_path}')
            return

        url_d = f"https://api.telegram.org/bot{TELEGRAM_TOKEN}/sendDocument"
        cap = caption or ''
        if TEST_MODE:
            cap = ('[TEST]\n' + cap).strip() if cap else '[TEST]'

        for chat_id in target_chat_ids:
            try:
                with open(file_path, 'rb') as f:
                    requests.post(
                        url_d,
                        data={'chat_id': chat_id, 'caption': cap[:1024]},
                        files={'document': f},
                        timeout=60,
                    )
            except Exception as e:
                log_error(f'⚠️ HTML 리포트 문서 전송 실패 ({chat_id}): {e}')


def send_telegram_chunks(message: str, title: str = '', max_len: int = 3800):
    """
    긴 메시지를 카드 단위로 나눠서 텔레그램 전송.
    종목 카드가 청크 경계에서 붙어 보이지 않도록 구분선을 유지한다.
    """
    message = str(message or '').replace('\r\n', '\n').strip()
    if not message:
        return

    divider = '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━'
    section_prefixes = ('🍉 [', '🧭 [', '🚀 [', '🔬 [', '🛡️ [', '📢 [', '👀 [', '🤖 [', '🔄 [', '🌍 [', '📰 [', '🇺🇸➡🇰🇷 [')

    sections = []
    current_header = ''
    current_lines = []
    for line in message.split('\n'):
        s = line.rstrip()
        if s.startswith(section_prefixes):
            if current_header or current_lines:
                sections.append((current_header, '\n'.join(current_lines).strip()))
            current_header = s
            current_lines = []
            continue
        current_lines.append(s)
    if current_header or current_lines:
        sections.append((current_header, '\n'.join(current_lines).strip()))

    cards = []
    for header, body in sections:
        body = body.strip()
        if not body:
            cards.append(header)
            continue
        parts = [part.strip() for part in body.split(divider) if part.strip()]
        if not parts:
            cards.append((header + '\n\n' + body).strip())
            continue
        for i, part in enumerate(parts):
            cards.append((header + '\n\n' + part).strip() if i == 0 else part)

    chunks = []
    current = (title.strip() + '\n\n') if title else ''
    for card in cards:
        card_text = f"{divider}\n{card.strip()}\n{divider}\n\n"
        if len(current) + len(card_text) > max_len and current.strip():
            chunks.append(current.strip())
            current = ((title.strip() + '\n\n') if title else '') + card_text
        else:
            current += card_text
    if current.strip():
        chunks.append(current.strip())

    total = len(chunks)
    for idx, chunk in enumerate(chunks, 1):
        if total > 1:
            chunk = f"({idx}/{total})\n" + chunk
        send_telegram_photo(chunk, [])

def send_tournament_results(tournament_report: str):
    """
    AI 토너먼트 결과를 AI별로 분리해서 개별 전송.
    각 AI 코멘트가 길면 추가 분할.
    """
    if not tournament_report:
        return

    # AI별 섹션 분리 마커
    markers = [
        ('🧠 [GPT-4o]',        '🧠 GPT-4o 분석'),
        ('🤖 [Claude-Sonnet]', '🤖 Claude-Sonnet 분석'),
        ('♊ [Gemini-Flash]',  '♊ Gemini-Flash 분석'),
        ('⚡ [Groq-Llama]',    '⚡ Groq-Llama 분석'),
    ]

    # 헤더 분리
    header_end = tournament_report.find('\n\n🧠')
    for _mark in ['\n\n🤖', '\n\n♊', '\n\n⚡']:
        if header_end == -1:
            header_end = tournament_report.find(_mark)

    header = tournament_report[:header_end].strip() if header_end > 0 else '🏆 AI 토너먼트 결과'

    # 헤더 먼저 전송
    send_telegram_photo(header, [])

    # 각 AI 섹션 찾아서 개별 전송
    sent_any = False
    for marker, title in markers:
        start = tournament_report.find(marker)
        if start == -1:
            continue

        # 다음 AI 섹션 시작 위치 찾기
        end = len(tournament_report)
        for other_marker, _ in markers:
            if other_marker == marker:
                continue
            pos = tournament_report.find(other_marker, start + len(marker))
            if pos != -1 and pos < end:
                end = pos

        section = tournament_report[start:end].strip()
        if section:
            send_telegram_chunks(section, title=title, max_len=3500)
            sent_any = True

    # 마커를 못 찾으면 전체를 분할 전송
    if not sent_any:
        send_telegram_chunks(tournament_report, max_len=3500)

