        prev_5 = df.iloc[-5]
        prev_10 = df.iloc[-10]
        curr_idx = df.index[-1]

        close_p = row['Close']
        close_chg_pct = ((row['Close'] - prev['Close']) / prev['Close'] * 100) if prev['Close'] > 0 else 0.0
        fear_info = detect_fear_absorption(ticker, row['Close'], close_chg_pct)
        open_p = row['Open']
        high_p = row['High']
        low_p = row['Low']

        raw_idx = len(df) - 1
        temp_df = df.iloc[:raw_idx + 1].copy()
        temp_df = add_white_cloud_candidates(temp_df)

        # HTS 정합성 확보:
