                item['수급5일누적'] = supply_prof.get('cum5_text') or fb_prof.get('cum5_text', item.get('수급5일누적', ''))
                item['수급연속'] = supply_prof.get('streak_text') or fb_prof.get('streak_text', item.get('수급연속', ''))
