def _to_bool_value(v):
    try:
        if isinstance(v, str):
            return v.strip().lower() in ("1", "true", "t", "y", "yes")
        return bool(v)
    except Exception:
        return False


def _pre_dolbanji_quality_score(row: pd.Series, mode: str = "broad") -> int:
    score = 0

    def _b(v):
        try:
            if isinstance(v, str):
                return v.strip().lower() in ("1", "true", "t", "y", "yes")
            return bool(v)
        except Exception:
            return False

    def _i(v, d=0):
        try:
            return int(float(v))
        except Exception:
            return d

    wm_state = str(row.get('수박최종상태', '') or row.get('수박상태명', '') or '').strip()
    cloud_state = str(row.get('저항구름상태', '') or '').strip()
    stage = str(row.get('단계상태', '') or '').strip()
    combo = " ".join([
        str(row.get('N조합', '') or ''),
        str(row.get('예비돌반지태그', '') or ''),
        str(row.get('신규예비돌반지Lite태그', '') or ''),
        str(row.get('예비돌반지HTS정확태그', '') or ''),
    ])

    if _b(row.get('예비돌반지확인', False)):
        score += 4
    if _b(row.get('신규예비돌반지Lite확인', False)):
        score += 3
    if _b(row.get('예비돌반지HTS정확복제', False)):
        score += 5
    if _b(row.get('5일재안착', False)):
        score += 2
    elif _b(row.get('5일재안착예비', False)):
        score += 1
    if _b(row.get('수박정제통과', False)):
        score += 2
    elif _b(row.get('수박정제관찰', False)):
        score += 1
    elif _b(row.get('수박정제주의', False)):
        score -= 2
    if stage in ('PASS_A', 'PASS_B'):
        score += 1
    if '돌반지' in combo:
        score += 1
    if '삼각' in combo:
        score += 1
    if '종베' in combo:
        score += 1
    if _i(row.get('안전점수', 0)) >= 60:
        score += 1
    if _i(row.get('N점수', 0)) >= 80:
        score += 1
    if wm_state == '후행수박':
        score -= 3
    elif wm_state == 'Blue-1단기':
        score -= 2
    elif wm_state in ('초입수박', '눌림수박', 'Blue-2예비'):
        score += 1
    if cloud_state == '저항돌파' and mode != 'exact':
        score -= 2
    elif cloud_state in ('저항전', '저항테스트'):
        score += 1
    if _b(row.get('수박디버그_late', False)):
        score -= 2
    return score


def _filter_pre_dolbanji_candidates(df: pd.DataFrame, mode: str = "broad") -> pd.DataFrame:
    if df is None or df.empty:
        return pd.DataFrame()

    work = df.copy()
    work['_pred_q'] = work.apply(lambda r: _pre_dolbanji_quality_score(r, mode=mode), axis=1)

    if mode == 'exact':
        score_series = pd.to_numeric(work.get('예비돌반지HTS정확점수', 0), errors='coerce').fillna(0)
        mask = (score_series >= 7) & (work['_pred_q'] >= 4)
    elif mode == 'lite':
        score_series = pd.to_numeric(work.get('신규예비돌반지Lite점수', 0), errors='coerce').fillna(0)
        confirmed = work['신규예비돌반지Lite확인'].apply(_to_bool_value) if '신규예비돌반지Lite확인' in work.columns else False
        mask = ((score_series >= 4) & (work['_pred_q'] >= 2)) | confirmed
    else:
        score_series = pd.to_numeric(work.get('예비돌반지점수', 0), errors='coerce').fillna(0)
        confirmed = work['예비돌반지확인'].apply(_to_bool_value) if '예비돌반지확인' in work.columns else False
        mask = ((score_series >= 5) & (work['_pred_q'] >= 3)) | confirmed

    filtered = work[mask].copy()
    if filtered.empty:
        return filtered
    return filtered.drop(columns=['_pred_q'], errors='ignore')


def build_pre_dolbanji_top5(df: pd.DataFrame):
    """
    예비돌반지 계열을 메인 TOP15와 별도로 추리기
    - 너무 이상적이거나 현재 구조와 맞지 않는 신호는 과감히 제외
    - 대신 확인형/정제통과/재안착 등 맥락이 맞는 후보는 살린다
    반환:
      pre_top5         : 전체 예비돌반지(기존 + Lite + HTS정확복제)
      exact_top5       : HTS 정확복제형 TOP5
      broad_only_top5  : 기존 예비돌반지(정확복제/Lite 제외) TOP5
      lite_top5        : 신규예비돌반지 Lite TOP5
    """
    if df is None or df.empty:
        empty = pd.DataFrame()
        return empty, empty, empty, empty

    work = df.copy()

    broad_cols = ['예비돌반지', 'pre_dolbanji', '예비돌반지복제형', '예비돌반지유사형']
    lite_cols = ['신규예비돌반지Lite', 'pre_dolbanji_lite']
    exact_cols = ['예비돌반지HTS정확복제', 'pre_dolbanji_hts_exact']

    broad_mask = pd.Series(False, index=work.index)
    for c in broad_cols:
        if c in work.columns:
            broad_mask = broad_mask | work[c].apply(_to_bool_value)

    lite_mask = pd.Series(False, index=work.index)
    for c in lite_cols:
        if c in work.columns:
            lite_mask = lite_mask | work[c].apply(_to_bool_value)

    exact_mask = pd.Series(False, index=work.index)
    for c in exact_cols:
        if c in work.columns:
            exact_mask = exact_mask | work[c].apply(_to_bool_value)

    base_sort_cols = [c for c in ['단계랭크', '안전점수', 'N점수'] if c in work.columns]
    base_ascending = [False] * len(base_sort_cols)

    broad_only_top5 = _filter_pre_dolbanji_candidates(work[broad_mask & ~exact_mask & ~lite_mask].copy(), mode='broad')
    if not broad_only_top5.empty:
        if '예비돌반지점수' in broad_only_top5.columns and base_sort_cols:
            broad_only_top5 = broad_only_top5.sort_values(by=['예비돌반지점수'] + base_sort_cols, ascending=[False] + base_ascending).head(5).reset_index(drop=True)
        elif base_sort_cols:
            broad_only_top5 = broad_only_top5.sort_values(by=base_sort_cols, ascending=base_ascending).head(5).reset_index(drop=True)

    exact_top5 = _filter_pre_dolbanji_candidates(work[exact_mask].copy(), mode='exact')
    if not exact_top5.empty:
        if '예비돌반지HTS정확점수' in exact_top5.columns and base_sort_cols:
            exact_top5 = exact_top5.sort_values(by=['예비돌반지HTS정확점수'] + base_sort_cols, ascending=[False] + base_ascending).head(5).reset_index(drop=True)
        elif base_sort_cols:
            exact_top5 = exact_top5.sort_values(by=base_sort_cols, ascending=base_ascending).head(5).reset_index(drop=True)

    lite_top5 = _filter_pre_dolbanji_candidates(work[lite_mask].copy(), mode='lite')
    if not lite_top5.empty:
        if '신규예비돌반지Lite점수' in lite_top5.columns and base_sort_cols:
            lite_top5 = lite_top5.sort_values(by=['신규예비돌반지Lite점수'] + base_sort_cols, ascending=[False] + base_ascending).head(5).reset_index(drop=True)
        elif base_sort_cols:
            lite_top5 = lite_top5.sort_values(by=base_sort_cols, ascending=base_ascending).head(5).reset_index(drop=True)

    pre_top5 = pd.concat([exact_top5, broad_only_top5, lite_top5], ignore_index=True, sort=False)
    if not pre_top5.empty:
        pre_sort_cols = []
        pre_asc = []
        if '예비돌반지HTS정확점수' in pre_top5.columns:
            pre_sort_cols.append('예비돌반지HTS정확점수'); pre_asc.append(False)
        if '예비돌반지점수' in pre_top5.columns:
            pre_sort_cols.append('예비돌반지점수'); pre_asc.append(False)
        if '신규예비돌반지Lite점수' in pre_top5.columns:
            pre_sort_cols.append('신규예비돌반지Lite점수'); pre_asc.append(False)
        pre_sort_cols += base_sort_cols
        pre_asc += base_ascending
        if pre_sort_cols:
            pre_top5 = pre_top5.sort_values(by=pre_sort_cols, ascending=pre_asc)
        subset_cols = [c for c in ['code', '종목명'] if c in pre_top5.columns]
        if subset_cols:
            pre_top5 = pre_top5.drop_duplicates(subset=subset_cols, keep='first')
        pre_top5 = pre_top5.head(5).reset_index(drop=True)

    return pre_top5, exact_top5, broad_only_top5, lite_top5


def build_pre_dolbanji_block(title: str, df: pd.DataFrame, exact_mode: bool = False) -> str:
    if df is None or df.empty:
        return f"💍 [{title}]\n- 해당 종목 없음\n"

    lines = [f"💍 [{title}]\n"]
    for rank, (_, row) in enumerate(df.iterrows(), 1):
        name = str(row.get('종목명', ''))
        code = str(row.get('code', ''))
        combo = str(row.get('N조합', ''))
        safe_score = safe_int(row.get('안전점수', 0))
        n_score = safe_int(row.get('N점수', 0))
        stage = str(row.get('단계상태', ''))
        stage_tag = str(row.get('단계태그', ''))
        rn_tag = str(row.get('라운드넘버태그', '') or '').strip()
        rn_comment = str(row.get('라운드넘버코멘트', '') or '').strip()

        if exact_mode:
            p_score = safe_int(row.get('예비돌반지HTS정확점수', 0))
            p_tag = str(row.get('예비돌반지HTS정확태그', ''))
            label, label_comment = describe_dolbanji_label(exact_mode=True, lite_mode=False)
        elif bool(row.get('신규예비돌반지Lite', False)) and not bool(row.get('예비돌반지', False)):
            p_score = safe_int(row.get('신규예비돌반지Lite점수', 0))
            p_tag = str(row.get('신규예비돌반지Lite태그', ''))
            label, label_comment = describe_dolbanji_label(exact_mode=False, lite_mode=True)
        else:
            p_score = safe_int(row.get('예비돌반지점수', 0))
            p_tag = str(row.get('예비돌반지태그', ''))
            label, label_comment = describe_dolbanji_label(exact_mode=False, lite_mode=False)

        lines.append(
            f"{rank}) [{name}]({code})\n"
            f"- 조합: {combo}\n"
            f"- 단계: {describe_stage_status(stage)} | {stage_tag}\n"
            f"- 패턴: {label} | {label_comment}\n"
            f"- {label}점수: {p_score} | 안전:{safe_score} | N점수:{n_score}\n"
            + (f"- 라운드가격: {rn_tag} | {rn_comment}\n" if rn_tag else "")
            + f"- 태그: {p_tag}\n"
            f"----------------------------"
        )

    return "\n".join(lines) + "\n"


    def _html_escape(value) -> str:
        try:
            return html.escape(str(value if value is not None else ''))
        except Exception:
            return ''


    def _fmt_money_text(value, suffix='') -> str:
        try:
            iv = int(round(float(value)))
            return f"{iv:,}{suffix}"
        except Exception:
            return '-'

    def _mobile_key_tags(item: dict) -> str:
        try:
            raw_tags = str(item.get('N구분', '') or '').split()
            priority_kw = ['🍉', '💍', '🐍', '🕳️', '💛', '🎯', '💎', '🟣', '📊OBV']
            tags = []
            for kw in priority_kw:
                for tag in raw_tags:
                    if kw in tag and tag not in tags:
                        tags.append(tag)
                        break
            for tag in raw_tags:
                if tag not in tags and len(tags) < 4:
                    tags.append(tag)
            return ' '.join(tags[:4])
        except Exception:
            return ''


    def _mobile_action_meta(final_label: str) -> dict:
        label = str(final_label or '').strip() or '관망'
        mapping = {
            '즉시 대응': {'cls': 'action-now', 'card': 'tone-now', 'emoji': '🟢', 'short': '바로 대응'},
            '즉시 관찰': {'cls': 'action-watch', 'card': 'tone-watch', 'emoji': '🟡', 'short': '바로 관찰'},
            '선취 가능': {'cls': 'action-pre', 'card': 'tone-pre', 'emoji': '🟣', 'short': '선취 가능'},
            '선취 관찰': {'cls': 'action-pre', 'card': 'tone-pre', 'emoji': '🟣', 'short': '선취 관찰'},
            '눌림 대기': {'cls': 'action-pullback', 'card': 'tone-pullback', 'emoji': '🔵', 'short': '눌림 대기'},
            '돌파 확인': {'cls': 'action-breakout', 'card': 'tone-breakout', 'emoji': '🟦', 'short': '돌파 확인'},
            '보유자 대응': {'cls': 'action-hold', 'card': 'tone-hold', 'emoji': '🟠', 'short': '보유자 대응'},
            '추격 금지': {'cls': 'action-stop', 'card': 'tone-stop', 'emoji': '🔴', 'short': '추격 금지'},
            '관망': {'cls': 'action-wait', 'card': 'tone-wait', 'emoji': '⚪', 'short': '관망'},
        }
        return mapping.get(label, {'cls': 'action-wait', 'card': 'tone-wait', 'emoji': '⚪', 'short': label})


    def build_mobile_stock_card_html(item, rank=None, compact=False) -> str:
        try:
            item = dict(item) if isinstance(item, dict) else item.to_dict()
        except Exception:
            item = dict(item)

        try:
            item2 = enrich_row_with_human_commentary(item)
        except Exception:
            item2 = item

        name = str(item.get('종목명', '') or '').strip()
        code = str(item.get('code', '') or '').strip()
        rec_phase = str(item.get('추천단계', '') or item.get('수박최종상태', '') or '').strip()
        state = str(item.get('수박최종상태', '') or item.get('수박상태명', '') or '').strip()
        final_label = str(item2.get('final_label', '') or '').strip() or str(item.get('최종판정', '') or '').strip() or '관망'
        action_meta = _mobile_action_meta(final_label)
        n_grade_raw = item.get('N등급', '')
        try:
            n_grade = _cap_grade_label(n_grade_raw, _recommendation_max_grade(item))
        except Exception:
            n_grade = str(n_grade_raw or '')

        current_price = _fmt_money_text(item.get('현재가', 0), '원')
        safe_score = safe_int(item.get('안전점수', 0), 0)
        n_score = safe_int(item.get('N점수', 0), 0)
        ai_conf = safe_int(item.get('AI확신도', 0), 0)
        ai_verdict = str(item.get('AI최종판정', '') or '').strip()
        ai_judge = str(item.get('AI심판요약', '') or '').strip()
        ai_reason = str(item.get('AI강한근거', '') or '').strip()
        n_combo = str(item.get('N조합', '') or '').strip()
        key_tags = _mobile_key_tags(item)

        stage = str(item.get('단계상태', '') or '').strip()
        try:
            stage_desc = describe_stage_status(stage) if stage else ''
        except Exception:
            stage_desc = stage

        supply_flow = str(item.get('수급판정', '') or '').strip()
        supply_warn = str(item.get('수급경고', '') or '').strip()
        supply_today = str(item.get('수급당일', '') or '').strip()
        supply_3d = str(item.get('수급3일누적', '') or '').strip()
        supply_5d = str(item.get('수급5일누적', '') or '').strip()

        interp = str(item2.get('interpretation_block', '') or '').strip()
        need_check = str(item2.get('need_check', '') or '').strip()
        action_summary = str(item2.get('action_summary', '') or '').strip()
        easy_text = str(item2.get('easy_interpretation', '') or '').strip()

        ma5_tag = str(item.get('5일재안착태그', '') or '').strip()
        cloud_tag = str(item.get('저항구름태그', '') or '').strip()
        refine_tag = str(item.get('수박정제태그', '') or '').strip()

        target1 = safe_int(item.get('🎯목표타점', 0), 0)
        target2 = safe_int(item.get('🎯목표2차', 0), 0)
        stop_p = safe_int(item.get('🚨손절가', 0), 0)
        rr_ratio = safe_float(item.get('RR비율', 0), 0.0)

        badge_html = []
        label_badge_class = f"badge strong {action_meta['cls']}"
        badge_html.append(f'<span class="{label_badge_class}">{_html_escape(action_meta["emoji"] + " " + final_label)}</span>')
        for badge in [n_grade, rec_phase, state]:
            if str(badge).strip():
                badge_html.append(f'<span class="badge">{_html_escape(badge)}</span>')

        banner_text = action_meta['short']
        if action_summary:
            banner_text += ' · ' + action_summary
        elif need_check:
            banner_text += ' · ' + need_check

        meta_rows = [
            f'<div class="metric"><span>현재가</span><strong>{_html_escape(current_price)}</strong></div>',
            f'<div class="metric"><span>안전점수</span><strong>{safe_score}</strong></div>',
            f'<div class="metric"><span>N점수</span><strong>{n_score}</strong></div>',
        ]
        if ai_conf > 0:
            meta_rows.append(f'<div class="metric"><span>AI확신도</span><strong>{ai_conf}</strong></div>')

        bullets = []
        for label, value in [
            ('핵심조합', n_combo), ('핵심태그', key_tags), ('단계', stage_desc),
            ('최근1일', supply_today), ('최근3일', supply_3d), ('최근5일', supply_5d),
            ('수급판정', supply_flow), ('수급경고', supply_warn), ('재안착', ma5_tag),
            ('저항구름', cloud_tag), ('정제', refine_tag), ('확인 기준', need_check),
            ('대응', action_summary), ('쉬운 해설', easy_text),
            ('AI판정', (ai_verdict + (f' {ai_conf}점' if ai_conf > 0 else '')) if ai_verdict else ''),
            ('AI근거', ai_reason or ai_judge),
        ]:
            if str(value).strip():
                bullets.append(f'<div class="info-row"><span>{_html_escape(label)}</span><b>{_html_escape(value)}</b></div>')

        if target1 > 0 and stop_p > 0:
            t = f'목표1 {target1:,} / 손절 {stop_p:,}'
            if target2 > 0:
                t = f'목표1 {target1:,} → 목표2 {target2:,} / 손절 {stop_p:,}'
            if rr_ratio > 0:
                t += f' / RR {rr_ratio:.1f}'
            bullets.append(f'<div class="info-row"><span>타점</span><b>{_html_escape(t)}</b></div>')

        details_html = ''
        if interp and not compact:
            details_html = f'<details class="detail"><summary>해석 펼치기</summary><pre>{_html_escape(interp)}</pre></details>'

        rank_html = f'<div class="rank">#{rank}</div>' if rank else ''
        return f'''<article id="stock-{_html_escape(code)}" class="stock-card {action_meta['card']}">
<div class="action-banner {action_meta['cls']}">{_html_escape(action_meta['emoji'] + ' ' + final_label)}<small>{_html_escape(banner_text)}</small></div>
<div class="stock-top">{rank_html}<div class="stock-head"><h3>{_html_escape(name)}<small>({_html_escape(code)})</small></h3><div class="badges">{''.join(badge_html)}</div></div></div><div class="metrics">{''.join(meta_rows)}</div><div class="info-grid">{''.join(bullets)}</div>{details_html}</article>'''


    def _mobile_action_priority(label: str) -> int:
        mapping = {
            '즉시 대응': 0,
            '즉시 관찰': 1,
            '선취 가능': 2,
            '선취 관찰': 3,
            '눌림 대기': 4,
            '돌파 확인': 5,
            '보유자 대응': 6,
            '추격 금지': 7,
            '관망': 8,
        }
        return mapping.get(str(label or '').strip(), 9)


    def _sort_mobile_section_df(df: pd.DataFrame, limit: int = None) -> pd.DataFrame:
        if df is None or len(df) == 0:
            return df
        try:
            work = df.copy()
            action_labels = []
            action_priorities = []
            for _, row in work.iterrows():
                try:
                    row_dict = dict(row) if isinstance(row, dict) else row.to_dict()
                    human = enrich_row_with_human_commentary(row_dict)
                    label = str(human.get('final_label', '') or row_dict.get('최종판정', '') or '').strip() or '관망'
                except Exception:
                    label = '관망'
                action_labels.append(label)
                action_priorities.append(_mobile_action_priority(label))
            work['_mobile_action_label'] = action_labels
            work['_mobile_action_priority'] = action_priorities

            sort_cols = ['_mobile_action_priority']
            ascending = [True]
            for col in ['즉시진입점수', '안전점수', 'N점수', '수박공격점수', 'AI확신도']:
                if col in work.columns:
                    sort_cols.append(col)
                    ascending.append(False)
            work = work.sort_values(by=sort_cols, ascending=ascending, na_position='last')
            if limit:
                work = work.head(limit)
            return work
        except Exception:
            return df.head(limit) if limit else df


    def build_mobile_section_html(title: str, df: pd.DataFrame, subtitle: str = '', limit: int = 5, compact: bool = False, prioritize_actions: bool = True) -> str:
        subtitle_html = f'<p>{_html_escape(subtitle)}</p>' if subtitle else ''
        if df is None or len(df) == 0:
            return f'''<section class="section"><div class="section-head"><h2>{_html_escape(title)}</h2>{subtitle_html}</div><div class="empty">해당 종목 없음</div></section>'''
        view_df = _sort_mobile_section_df(df, limit=limit) if prioritize_actions else df.head(limit)
        cards = []
        for idx, (_, row) in enumerate(view_df.iterrows(), 1):
            cards.append(build_mobile_stock_card_html(row, rank=idx, compact=compact))
        return f'''<section class="section"><div class="section-head"><h2>{_html_escape(title)}</h2>{subtitle_html}</div><div class="stock-list">{''.join(cards)}</div></section>'''


    def build_mobile_text_panel_html(title: str, body: str, open_default: bool = False) -> str:
        if not str(body or '').strip():
            return ''
        open_attr = ' open' if open_default else ''
        return f'''<details class="text-panel"{open_attr}><summary>{_html_escape(title)}</summary><pre>{_html_escape(body)}</pre></details>'''


    def get_mobile_report_public_url(filename: str = 'main7_mobile_latest.html'):
        base = (os.getenv('REPORT_BASE_URL') or os.getenv('GITHUB_PAGES_URL') or '').strip()
        if not base:
            return ''
        return base.rstrip('/') + '/' + filename.lstrip('/')


    def send_mobile_report_link(url: str, report_date: str = ''):
        if not url:
            return False
        title = '📎 모바일 HTML 링크' + (f' | {report_date}' if report_date else '')
        body = title + "\n" + url
        try:
            send_telegram_message(body)
            return True
        except Exception:
            return False


