def calc_recent_accum_candle(df, lookback=20):
    empty = {
        'found': False, 'score': 0, 'grade': '없음', 'label': '매집봉 없음',
        'high': 0.0, 'low': 0.0, 'close': 0.0, 'open': 0.0,
        'desc': '데이터 부족', 'idx': None,
    }
    try:
        if df is None or len(df) < 10:
            return empty
        cols = _acc_price_cols(df)
        if not cols['open'] or not cols['high'] or not cols['low'] or not cols['close']:
            return empty

        start = max(1, len(df) - lookback)
        best = None
        for idx in range(start, len(df) - 1):
            row = df.iloc[idx]
            prev = df.iloc[max(0, idx - 20):idx]
            o = _acc_safe_float(row[cols['open']])
            h = _acc_safe_float(row[cols['high']])
            l = _acc_safe_float(row[cols['low']])
            c = _acc_safe_float(row[cols['close']])
            v = _acc_safe_float(row[cols['volume']]) if cols['volume'] else 0.0
            rng = max(h - l, 1e-6)
            body = abs(c - o)
            lower = max(min(o, c) - l, 0.0) / rng
            upper = max(h - max(o, c), 0.0) / rng
            close_pos = (c - l) / rng
            body_ratio = body / rng
            vma20 = _acc_safe_float(prev[cols['volume']].mean(), 0.0) if cols['volume'] and len(prev) > 0 else 0.0
            vol_ratio = (v / vma20) if vma20 > 0 else 0.0

            score = 0
            reasons = []
            if lower >= 0.35:
                score += 25; reasons.append('아래꼬리흡수강')
            elif lower >= 0.20:
                score += 15; reasons.append('아래꼬리흡수보통')
            elif lower >= 0.10:
                score += 5; reasons.append('아래꼬리약')
            if close_pos >= 0.75:
                score += 20; reasons.append('고가권마감')
            elif close_pos >= 0.60:
                score += 12; reasons.append('회복양호')
            elif close_pos >= 0.50:
                score += 5; reasons.append('회복보통')
            if body_ratio >= 0.35:
                score += 12; reasons.append('몸통확인')
            elif body_ratio >= 0.20:
                score += 6; reasons.append('몸통보통')
            if upper >= 0.35:
                score -= 10; reasons.append('윗꼬리과다')
            elif upper >= 0.25:
                score -= 5; reasons.append('윗꼬리주의')
            if vol_ratio >= 2.0:
                score += 22; reasons.append('거래량강')
            elif vol_ratio >= 1.4:
                score += 14; reasons.append('거래량증가')
            elif vol_ratio >= 1.1:
                score += 6; reasons.append('거래량보통')

            future_df = df.iloc[idx + 1:min(len(df), idx + 4)]
            if len(future_df) > 0:
                acc_mid = (h + l) / 2.0
                fut_close_min = _acc_safe_float(future_df[cols['close']].min(), -1e9)
                fut_low_min = _acc_safe_float(future_df[cols['low']].min(), -1e9)
                if fut_close_min >= acc_mid:
                    score += 18; reasons.append('후속유지강')
                elif fut_low_min >= l:
                    score += 10; reasons.append('후속유지보통')
                else:
                    score -= 5; reasons.append('후속확인약')

            score = max(0, min(100, int(round(score))))
            if score >= 70:
                grade, label, found = '강함', '매집봉 강함', True
            elif score >= 40:
                grade, label, found = '보통', '매집봉 보통', True
            elif score >= 20:
                grade, label, found = '약함', '매집봉 약함', False
            else:
                grade, label, found = '없음', '매집봉 없음', False

            info = {
                'found': found, 'score': score, 'grade': grade, 'label': label,
                'high': h, 'low': l, 'close': c, 'open': o,
                'desc': ' / '.join(reasons), 'idx': idx,
            }
            if best is None or info['score'] > best['score']:
                best = info
        return best or empty
    except Exception:
        return empty


def build_wave_levels(df, accum_info, lookback=60):
    out = {
        'small_low': 0.0, 'small_high': 0.0, 'small_mid': 0.0,
        'mid_low': 0.0, 'mid_high': 0.0, 'mid_mid': 0.0,
        'small_state': '', 'mid_state': '', 'small_desc': '', 'mid_desc': '',
        'blue_zone_low': 0.0, 'blue_zone_high': 0.0,
    }
    try:
        cols = _acc_price_cols(df)
        if not cols['high'] or not cols['low'] or not cols['close']:
            return out
        c = _acc_safe_float(df.iloc[-1][cols['close']]) if len(df) else 0.0
        if accum_info.get('found'):
            sl = _acc_safe_float(accum_info.get('low', 0))
            sh = _acc_safe_float(accum_info.get('high', 0))
            sm = (sl + sh) / 2.0
            out['small_low'], out['small_high'], out['small_mid'] = sl, sh, sm
            if c < sm:
                out['small_state'] = '소파동 하단'
                out['small_desc'] = '아직 소파동 중간 아래. 확인 전 선취/관찰 구간'
            elif c < sh:
                out['small_state'] = '소파동 상단 접근'
                out['small_desc'] = '전고점 재도전 구간. 파란타점 후보로 해석 가능'
            else:
                out['small_state'] = '소파동 전고점 돌파'
                out['small_desc'] = '소파동 돌파 확인 구간. 이후 눌림 지지 여부가 중요'
            out['blue_zone_low'] = round(sl + (sh - sl) * 0.55, 2)
            out['blue_zone_high'] = round(sl + (sh - sl) * 0.92, 2)
        recent = df.iloc[max(0, len(df) - lookback):]
        if len(recent) > 0:
            ml = _acc_safe_float(recent[cols['low']].min(), 0.0)
            mh = _acc_safe_float(recent[cols['high']].max(), 0.0)
            mm = (ml + mh) / 2.0
            out['mid_low'], out['mid_high'], out['mid_mid'] = ml, mh, mm
            if c < mm:
                out['mid_state'] = '중파동 하단'
                out['mid_desc'] = '중기 구조상 아직 하단. 선취 또는 관찰 구간'
            elif c < mh:
                out['mid_state'] = '중파동 상단 접근'
                out['mid_desc'] = '중기 전고점 재도전 구간'
            else:
                out['mid_state'] = '중파동 전고점 돌파'
                out['mid_desc'] = '중파동 돌파 확인 구간'
        return out
    except Exception:
        return out


def evaluate_acc_position(df):
    out = {
        'score': 0, 'label': '자리 정보 부족', 'desc': '',
        'pullback_score': 0, 'pullback_label': '', 'd150': 0.0, 'd200': 0.0,
        'drawdown_score': 0, 'drawdown_label': '', 'drawdown_pct': 0.0,
        'overheat_penalty': 0, 'overheat_label': '', 'disparity': 100.0,
    }
    try:
        cols = _acc_price_cols(df)
        if df is None or len(df) < 25 or not cols['close']:
            return out
        close_s = df[cols['close']].astype(float)
        c = _acc_safe_float(close_s.iloc[-1])
        ma150 = close_s.rolling(150).mean() if len(df) >= 150 else pd.Series([c]*len(df), index=df.index)
        ma200 = close_s.rolling(200).mean() if len(df) >= 200 else pd.Series([c]*len(df), index=df.index)
        m150 = _acc_safe_float(ma150.iloc[-1], c)
        m200 = _acc_safe_float(ma200.iloc[-1], c)
        d150 = (c / m150 - 1.0) * 100 if m150 > 0 else 0.0
        d200 = (c / m200 - 1.0) * 100 if m200 > 0 else 0.0
        pullback_score = 0
        if -3.0 <= d150 <= 8.0: pullback_score += 18
        elif -6.0 <= d150 <= 12.0: pullback_score += 10
        if -3.0 <= d200 <= 10.0: pullback_score += 18
        elif -6.0 <= d200 <= 15.0: pullback_score += 10
        pullback_label = '장기눌림 우수' if pullback_score >= 30 else ('장기눌림 보통' if pullback_score >= 15 else '장기눌림 약함')

        high_col = _acc_col(df, 'High', '고가')
        recent = df.iloc[max(0, len(df) - 120):]
        recent_high = _acc_safe_float(recent[high_col].max(), c) if high_col else c
        dd = (c / recent_high - 1.0) * 100 if recent_high > 0 else 0.0
        if -25 <= dd <= -8:
            drawdown_score, drawdown_label = 28, '조정률 우수'
        elif -35 <= dd < -25 or -8 < dd <= -3:
            drawdown_score, drawdown_label = 18, '조정률 보통'
        elif dd > -3:
            drawdown_score, drawdown_label = 5, '고점근접'
        else:
            drawdown_score, drawdown_label = 10, '과조정'

        ma20 = close_s.rolling(20).mean()
        m20 = _acc_safe_float(ma20.iloc[-1], c)
        disparity = (c / m20) * 100 if m20 > 0 else 100.0
        overheat_penalty = 0
        if disparity >= 130:
            overheat_penalty = -32
        elif disparity >= 122:
            overheat_penalty = -22
        elif disparity >= 116:
            overheat_penalty = -12
        elif disparity >= 112:
            overheat_penalty = -6
        overheat_label = '과열주의' if overheat_penalty < 0 else '과열양호'

        raw_score = pullback_score + drawdown_score + overheat_penalty
        score = max(0, min(100, raw_score + 40))
        label = '자리 매우 좋음' if score >= 75 else ('자리 양호' if score >= 55 else ('자리 보통' if score >= 35 else '자리 불리'))

        out.update({
            'score': int(round(score)), 'label': label,
            'desc': f"{pullback_label} / {drawdown_label} / {overheat_label}",
            'pullback_score': int(pullback_score), 'pullback_label': pullback_label,
            'd150': round(d150, 1), 'd200': round(d200, 1),
            'drawdown_score': int(drawdown_score), 'drawdown_label': drawdown_label, 'drawdown_pct': round(dd, 1),
            'overheat_penalty': int(overheat_penalty), 'overheat_label': overheat_label, 'disparity': round(disparity, 1),
        })
        return out
    except Exception:
        return out


def build_accumulation_package(df):
    try:
        accum = calc_recent_accum_candle(df, lookback=20)
        waves = build_wave_levels(df, accum, lookback=60)
        pos = evaluate_acc_position(df)
        return {'accum': accum, 'waves': waves, 'position': pos}
    except Exception:
        return {
            'accum': {'found': False, 'score': 0, 'grade': '없음', 'label': '매집봉 없음', 'high': 0.0, 'low': 0.0, 'close': 0.0, 'open': 0.0, 'desc': ''},
            'waves': {'small_low': 0.0, 'small_high': 0.0, 'small_mid': 0.0, 'mid_low': 0.0, 'mid_high': 0.0, 'mid_mid': 0.0, 'small_state': '', 'mid_state': '', 'small_desc': '', 'mid_desc': '', 'blue_zone_low': 0.0, 'blue_zone_high': 0.0},
            'position': {'score': 0, 'label': '자리 정보 부족', 'desc': '', 'pullback_score': 0, 'pullback_label': '', 'd150': 0.0, 'd200': 0.0, 'drawdown_score': 0, 'drawdown_label': '', 'drawdown_pct': 0.0, 'overheat_penalty': 0, 'overheat_label': '', 'disparity': 100.0},
        }


def _build_accumulation_overlay_lines(pkg):
    lines = []
    try:
        accum = (pkg or {}).get('accum', {}) or {}
        waves = (pkg or {}).get('waves', {}) or {}
        pos = (pkg or {}).get('position', {}) or {}

        accum_tag = str(accum.get('label', '') or '').strip()
        accum_score = int(float(accum.get('score', 0) or 0))
        accum_comment = str(accum.get('desc', '') or '').strip()
        if accum_tag and accum_tag != '매집봉 없음':
            line = f"🪵 매집봉: {accum_tag} ({accum_score})"
            if accum_comment:
                line += f" | {accum_comment}"
            lines.append(line)

        small_low = int(float(waves.get('small_low', 0) or 0))
        small_high = int(float(waves.get('small_high', 0) or 0))
        small_state = str(waves.get('small_state', '') or '').strip()
        small_desc = str(waves.get('small_desc', '') or '').strip()
        if (small_low > 0 and small_high > 0) or small_state or small_desc:
            line = f"〰️ 소파동: 저점 {small_low:,} → 전고점 {small_high:,}" if (small_low > 0 and small_high > 0) else '〰️ 소파동: 계산됨 [BOOTCHECK]'
            if small_state:
                line += f" | {small_state}"
            if small_desc:
                line += f" | {small_desc}"
            lines.append(line)

        mid_low = int(float(waves.get('mid_low', 0) or 0))
        mid_high = int(float(waves.get('mid_high', 0) or 0))
        mid_state = str(waves.get('mid_state', '') or '').strip()
        mid_desc = str(waves.get('mid_desc', '') or '').strip()
        if (mid_low > 0 and mid_high > 0) or mid_state or mid_desc:
            line = f"📶 중파동: 저점 {mid_low:,} → 전고점 {mid_high:,}" if (mid_low > 0 and mid_high > 0) else '📶 중파동: 계산됨 [BOOTCHECK]'
            if mid_state:
                line += f" | {mid_state}"
            if mid_desc:
                line += f" | {mid_desc}"
            lines.append(line)

        bz_low = int(float(waves.get('blue_zone_low', 0) or 0))
        bz_high = int(float(waves.get('blue_zone_high', 0) or 0))
        if bz_low > 0 and bz_high > 0:
            lines.append(f"🔵 파란타점 영역: {bz_low:,} ~ {bz_high:,} | 점이 아니라 지지 확인 구간")

        pos_label = str(pos.get('label', '') or '').strip()
        pos_score = int(float(pos.get('score', 0) or 0))
        pos_desc = str(pos.get('desc', '') or '').strip()
        if pos_label:
            line = f"🪑 자리평가: {pos_label} ({pos_score})"
            if pos_desc:
                line += f" | {pos_desc}"
            lines.append(line)

        pull_label = str(pos.get('pullback_label', '') or '').strip()
        pull_score = int(float(pos.get('pullback_score', 0) or 0))
        dd_label = str(pos.get('drawdown_label', '') or '').strip()
        dd_score = int(float(pos.get('drawdown_score', 0) or 0))
        dd_pct = float(pos.get('drawdown_pct', 0.0) or 0.0)
        hot_penalty = int(float(pos.get('overheat_penalty', 0) or 0))
        hot_label = str(pos.get('overheat_label', '') or '').strip()
        detail_parts = []
        if pull_label:
            detail_parts.append(f"장기눌림:{pull_label}({pull_score})")
        if dd_label:
            detail_parts.append(f"조정률:{dd_label}({dd_score},{dd_pct:.1f}%)")
        if hot_label:
            detail_parts.append(f"과열:{hot_label}({hot_penalty})")
        if detail_parts:
            lines.append('🧮 자리세부: ' + ' | '.join(detail_parts))
    except Exception:
        return []
    return lines




# =============================================================
# ✅ CONTEXT TRACE COMPLETE PATCH v1
# - DROP 표현을 사용자 관점의 "구조관찰"로 완화
# - 최근 정제수박 이력 / 세력매집 흔적 / 재료잔존 점수화
# - 후행형을 단순 후행이 아니라 유형별 대응으로 분리
# =============================================================
CONTEXT_TRACE_PATCH_VERSION = "context_trace_complete_v2"


def _ctx_bool(v) -> bool:
    try:
        if isinstance(v, str):
            return v.strip().lower() in ("1", "true", "yes", "y", "ok", "통과", "true")
        return bool(v)
    except Exception:
        return False


def _ctx_float(v, default=0.0) -> float:
    try:
        if v is None:
            return default
        if isinstance(v, str):
            v = v.replace(',', '').replace('%', '').strip()
            if v == '':
                return default
        return float(v)
    except Exception:
        return default


def _ctx_int(v, default=0) -> int:
    try:
        return int(float(v))
    except Exception:
        return default


def _ctx_text(row, *keys) -> str:
    vals = []
    for k in keys:
        try:
            if isinstance(row, dict):
                v = row.get(k, '')
            else:
                v = row.get(k, '')
        except Exception:
            v = ''
        if v is None:
            continue
        s = str(v).strip()
        if s and s not in ('nan', 'None'):
            vals.append(s)
    return ' | '.join(vals)


def calc_recent_refined_watermelon_trace(df, current_bundle=None, lookback: int = 10) -> dict:
    result = {
        'recent_refine_found': False,
        'recent_refine_days_ago': 999,
        'recent_refine_count': 0,
        'recent_refine_weak_count': 0,
        'recent_refine_score': 0,
        'recent_refine_tag': '',
        'recent_refine_comment': '',
    }
    try:
        if df is None or len(df) < 20:
            return result
        n = len(df)
        start = max(0, n - int(lookback))
        found_days = []
        weak_days = []
        last_ok_score = 0
        for i in range(start, n):
            days_ago = (n - 1) - i
            try:
                if i == n - 1 and isinstance(current_bundle, dict):
                    rb = current_bundle
                else:
                    try:
                        wc = detect_white_cloud_vote(df, i)
                    except Exception:
                        wc = {'state': '', 'tag': '', 'comment': ''}
                    try:
                        ma5 = detect_ma5_reclaim_signal(df, i)
                    except Exception:
                        ma5 = {'ok': False, 'reclaim': False, 'tag': '', 'comment': '', 'score': 0}
                    rb = detect_refined_watermelon_filter(df, i, white_cloud_bundle=wc, ma5_reclaim_bundle=ma5)
                ok = bool(rb.get('ok', False))
                weak = bool(rb.get('weak', False))
                caution = bool(rb.get('caution', False))
                sc = _ctx_int(rb.get('score', 0), 0)
                if ok:
                    found_days.append(days_ago)
                    last_ok_score = max(last_ok_score, sc)
                elif weak and not caution:
                    weak_days.append(days_ago)
            except Exception:
                continue
        if found_days:
            latest = min(found_days)
            cnt = len(found_days)
            if latest == 0:
                score = 12
            elif latest <= 2:
                score = 8
            elif latest <= 5:
                score = 5
            else:
                score = 3
            if cnt >= 2:
                score += 2
            if last_ok_score >= 70:
                score += 2
            result.update({
                'recent_refine_found': True,
                'recent_refine_days_ago': latest,
                'recent_refine_count': cnt,
                'recent_refine_weak_count': len(weak_days),
                'recent_refine_score': min(18, int(score)),
                'recent_refine_tag': '✅오늘 정제수박' if latest == 0 else f'✅최근 {latest}일 전 정제수박',
                'recent_refine_comment': f'최근 {lookback}일 중 정제수박 {cnt}회 발생. 오늘 신호가 약해도 구조 품질 이력은 긍정으로 반영합니다.',
            })
        elif weak_days:
            latest = min(weak_days)
            cnt = len(weak_days)
            score = 3 if latest <= 5 else 1
            result.update({
                'recent_refine_found': False,
                'recent_refine_days_ago': latest,
                'recent_refine_count': 0,
                'recent_refine_weak_count': cnt,
                'recent_refine_score': score,
                'recent_refine_tag': f'🟨최근 {latest}일 전 관찰수박',
                'recent_refine_comment': f'정제수박 완성은 아니지만 최근 관찰수박 {cnt}회. 거래량·재안착 추가 확인이 필요합니다.',
            })
    except Exception as e:
        result['recent_refine_comment'] = f'정제이력 계산 오류: {e}'
    return result


def calc_force_accumulation_trace(df, accumulation_pkg=None, ma5_reclaim_bundle=None, wm_bundle=None) -> dict:
    result = {
        'force_trace_score': 0,
        'force_trace_tag': '',
        'force_trace_comment': '',
        'force_trace_grade': '없음',
    }
    try:
        if df is None or len(df) < 20:
            return result
        cur = df.iloc[-1]
        prev_close = _ctx_float(df.iloc[-2].get('Close', 0), 0) if len(df) >= 2 else 0
        close = _ctx_float(cur.get('Close', 0), 0)
        high = _ctx_float(cur.get('High', 0), 0)
        low = _ctx_float(cur.get('Low', 0), 0)
        vol = _ctx_float(cur.get('Volume', 0), 0)
        vma20 = _ctx_float(cur.get('VMA20', 0), 0)
        obv_slope = _ctx_float(cur.get('OBV_Slope', cur.get('OBV기울기', 0)), 0)
        score = 0
        reasons = []
        acc = accumulation_pkg.get('accum', {}) if isinstance(accumulation_pkg, dict) else {}
        acc_score = _ctx_int(acc.get('score', 0), 0)
        acc_label = str(acc.get('label', '') or '').strip()
        if acc_score >= 60 or ('매집' in acc_label and '없음' not in acc_label):
            score += min(25, max(10, acc_score // 4))
            reasons.append(acc_label or '최근 매집봉')
        elif acc_score >= 30:
            score += 8
            reasons.append('약한 매집봉')
        try:
            recent = df.tail(8).copy()
            amount = recent['Close'] * recent['Volume'] if {'Close','Volume'}.issubset(recent.columns) else None
            if amount is not None and len(amount) >= 3:
                vol_ratio = _ctx_float(vol / max(1.0, vma20), 0) if vma20 > 0 else 0
                if vol_ratio >= 2.0 and close >= prev_close * 0.97:
                    score += 12
                    reasons.append(f'거래량 {vol_ratio:.1f}배 후 가격유지')
                idx_max = amount.idxmax()
                max_close = _ctx_float(df.loc[idx_max].get('Close', 0), 0)
                if max_close > 0 and close >= max_close * 0.92:
                    score += 8
                    reasons.append('고거래량봉 이후 가격방어')
        except Exception:
            pass
        if obv_slope > 0:
            score += 10
            reasons.append('OBV 우상향')
        if _ctx_bool(ma5_reclaim_bundle.get('ok', False) if isinstance(ma5_reclaim_bundle, dict) else False):
            score += 8
            reasons.append('5일재안착')
        if isinstance(wm_bundle, dict) and (wm_bundle.get('wm_blue2_hold') or wm_bundle.get('wm_blue1_hold')):
            score += 8
            reasons.append('파란점 재점화')
        if high > low:
            body_top = max(_ctx_float(cur.get('Open', 0), 0), close)
            upper_wick = max(0, high - body_top) / max(1e-9, high - low)
            if upper_wick >= 0.55 and close < (low + (high-low)*0.55):
                score -= 8
                reasons.append('윗꼬리 부담')
        score = max(0, min(80, int(score)))
        if score >= 55:
            grade, tag = '강함', '🔥세력흔적강'
        elif score >= 35:
            grade, tag = '보통', '🧲세력흔적보통'
        elif score >= 15:
            grade, tag = '약함', '👀세력흔적약함'
        else:
            grade, tag = '없음', ''
        result.update({
            'force_trace_score': score,
            'force_trace_tag': tag,
            'force_trace_comment': ' / '.join(reasons[:5]) if reasons else '뚜렷한 매집 흔적은 약함',
            'force_trace_grade': grade,
        })
    except Exception as e:
        result['force_trace_comment'] = f'세력흔적 계산 오류: {e}'
    return result


def calc_material_survival_score(item) -> dict:
    text = _ctx_text(item, 'news_sentiment', '최근뉴스', '뉴스', '뉴스제목', '공시태그', '공시내용', 'AI재료분류', 'N조합', 'N구분')
    low = text.lower()
    score = 0
    reasons = []
    positive_kw = ['수주','계약','공급','실적','흑자','증가','수출','승인','허가','임상','특허','합병','인수','투자','증설','정책','국책','ai','반도체','로봇','전력','원전','방산','데이터센터','냉각','hbm','온디바이스']
    dead_kw = ['조회공시','풍문','부인','해명','무관','없다','소송','상장폐지','관리종목','감사의견','횡령','배임','유상증자','감자','불성실']
    for kw in positive_kw:
        if kw.lower() in low:
            score += 6
            reasons.append(kw)
    for kw in dead_kw:
        if kw.lower() in low:
            score -= 12
            reasons.append(f'주의:{kw}')
    if str(item.get('공시태그', '') or '').strip() not in ('', '없음', '공시없음', '⚙️미조회'):
        score += 10
        reasons.append('공시확인')
    if _ctx_bool(item.get('악재공시', False)):
        score -= 30
        reasons.append('악재공시')
    disparity = _ctx_float(item.get('이격', 0), 0)
    obv = _ctx_float(item.get('OBV기울기', 0), 0)
    supply = str(item.get('수급요약', item.get('수급판정', '')) or '')
    if 98 <= disparity <= 115:
        score += 8
        reasons.append('가격부담관리')
    elif disparity >= 125:
        score -= 12
        reasons.append('과열부담')
    if obv > 0:
        score += 8
        reasons.append('OBV방어')
    if any(k in supply for k in ['개인매도흡수','동반매수','강매집','외인매수','기관매수']):
        score += 10
        reasons.append('수급동행')
    score = max(0, min(100, int(score)))
    if score >= 70:
        tag = '🔥재료생존'; comment = '후속 뉴스/공시 또는 테마·수급 동행이 살아 있습니다.'
    elif score >= 40:
        tag = '🟡재료확인'; comment = '재료는 남아 있으나 후속 뉴스·섹터 동행 확인이 필요합니다.'
    elif score >= 20:
        tag = '⚪재료약함'; comment = '단기 재료성은 있으나 강한 후속성은 아직 약합니다.'
    else:
        tag = '⚠️재료소멸주의'; comment = '재료가 약하거나 이미 가격에 반영됐을 가능성이 있습니다.'
    if reasons:
        comment += ' 근거: ' + ' / '.join(reasons[:5])
    return {'material_score': score, 'material_tag': tag, 'material_comment': comment}


def calc_context_bonus_score(item) -> int:
    # v2: 맥락보너스는 '정렬 보정'이지 매수점수 본체가 아니므로 과대 반영을 제한한다.
    acc = _ctx_int(item.get('세력흔적점수', item.get('force_trace_score', 0)), 0)
    ref = _ctx_int(item.get('정제이력점수', item.get('recent_refine_score', 0)), 0)
    mat = _ctx_int(item.get('재료잔존점수', item.get('material_score', 0)), 0)
    wm_state = str(item.get('수박최종상태', item.get('수박상태명', '')) or '')
    phase = str(item.get('추천단계', item.get('유형', '')) or '')
    raw = acc * 0.24 + ref * 0.95 + mat * 0.12
    cap = 32
    # 후행형은 구조가 좋아도 신규 진입점수로 오해하면 안 되므로 보정폭을 더 제한한다.
    if '후행' in wm_state or '후행' in phase:
        cap = 22 if mat >= 40 else 16
    return max(0, int(min(cap, raw)))


def apply_material_survival_to_df(df, *args, **kwargs):
    try:
        if df is None or df.empty:
            return df
        out = df.copy()
        for idx, row in out.iterrows():
            item = row.to_dict()
            m = calc_material_survival_score(item)
            out.at[idx, '재료잔존점수'] = int(m['material_score'])
            out.at[idx, '재료잔존태그'] = m['material_tag']
            out.at[idx, '재료잔존코멘트'] = m['material_comment']
            out.at[idx, '맥락보너스점수'] = calc_context_bonus_score({**item, '재료잔존점수': int(m['material_score'])})
        return out
    except Exception:
        return df

try: _ORIG_calc_pass_stage = calc_pass_stage
except Exception: _ORIG_calc_pass_stage = None
try: _ORIG_build_score_summary = build_score_summary
except Exception: _ORIG_build_score_summary = None
try: _ORIG_decide_final_label = decide_final_label
except Exception: _ORIG_decide_final_label = None
try: _ORIG_build_easy_interpretation = build_easy_interpretation
except Exception: _ORIG_build_easy_interpretation = None
try: _ORIG_enrich_row_with_human_commentary = enrich_row_with_human_commentary
except Exception: _ORIG_enrich_row_with_human_commentary = None


def describe_stage_status(stage_status: str) -> str:
    if stage_status == 'PASS_A': return '✅ PASS_A | 매집→응축→돌파준비 3단계 통과'
    if stage_status == 'PASS_B': return '🟣 PASS_B | 응축→재파동 2단계 통과'
    if stage_status in ('DROP', 'WATCH', '', None): return '👀 밴드외 구조관찰 | 핵심 밴드 타점 미충족'
    return '👀 관찰 | 단계 확인 필요'


def calc_pass_stage(row) -> str:
    try:
        p = _ORIG_calc_pass_stage(row) if _ORIG_calc_pass_stage else 'WATCH'
        return 'WATCH' if p == 'DROP' else p
    except Exception:
        return 'WATCH'


def get_pass_stage_bundle(row) -> dict:
    pass_stage = calc_pass_stage(row)
    if pass_stage == 'PASS_B':
        return {'pass_stage': pass_stage, 'pass_title': '📶 PASS_B | 강화 확인 구조 통과', 'pass_desc': '기본 3단계 통과 후 재안착·거래량·저항 위치까지 추가 확인된 실전 우선 구조입니다.'}
    if pass_stage == 'PASS_A':
        return {'pass_stage': pass_stage, 'pass_title': '✅ PASS_A | 매집→응축→돌파준비 3단계 통과', 'pass_desc': '매집 + 응축 + 돌파준비 흐름이 순서대로 맞는 기본 구조 통과 상태입니다.'}
    return {'pass_stage': 'WATCH', 'pass_title': '👀 밴드외 구조관찰 | 핵심 밴드 타점 미충족', 'pass_desc': '핵심 밴드/단계 조건은 완전 통과가 아니지만, 수박상태·저항구름·정제이력·세력흔적으로 별도 관찰합니다.'}


def _ctx_band(v, a, b, c, labels):
    v = _ctx_int(v, 0)
    if v >= a: return labels[0]
    if v >= b: return labels[1]
    if v >= c: return labels[2]
    return labels[3]


def build_score_summary(row) -> str:
    base = _ORIG_build_score_summary(row) if _ORIG_build_score_summary else ''
    acc = _ctx_int(_rc_get(row, '세력흔적점수', _rc_get(row, 'force_trace_score', 0)), 0)
    ref = _ctx_int(_rc_get(row, '정제이력점수', _rc_get(row, 'recent_refine_score', 0)), 0)
    mat = _ctx_int(_rc_get(row, '재료잔존점수', _rc_get(row, 'material_score', 0)), 0)
    wm_state = str(_rc_get(row, '수박최종상태', _rc_get(row, '수박상태명', '')) or '')
    phase = str(_rc_get(row, '추천단계', _rc_get(row, '유형', '')) or '')
    bonus = calc_context_bonus_score({**(row if isinstance(row, dict) else {}), '세력흔적점수': acc, '정제이력점수': ref, '재료잔존점수': mat})
    extras = []
    if acc: extras.append('흔적:' + _ctx_band(acc, 55, 35, 15, ['강함', '보통', '약함', '없음']))
    if ref: extras.append('정제이력:' + _ctx_band(ref, 12, 8, 3, ['강함', '양호', '참고', '약함']))
    if mat: extras.append('재료:' + _ctx_band(mat, 70, 40, 20, ['생존', '확인', '약함', '소멸주의']))
    if '후행' in wm_state or '후행' in phase:
        extras.append('후행:신규추격주의')
    if bonus: extras.append(f'맥락보너스:+{bonus}')
    return (base + ' | ' if base and extras else base) + ' | '.join(extras)


def classify_late_response_type(row) -> dict:
    wm_state = str(_rc_get(row, '수박최종상태', _rc_get(row, '수박상태명', '')) or '').strip()
    phase = str(_rc_get(row, '추천단계', '') or '').strip()
    if wm_state != '후행수박' and phase != '후행형':
        return {'late_type': '', 'late_action': ''}
    disparity = _ctx_float(_rc_get(row, '이격', 0), 0)
    ref = _ctx_int(_rc_get(row, '정제이력점수', 0), 0)
    acc = _ctx_int(_rc_get(row, '세력흔적점수', 0), 0)
    material = _ctx_int(_rc_get(row, '재료잔존점수', 0), 0)
    pattern = _ctx_text(row, '주패턴', '패턴가드', 'N조합', 'N구분')
    if disparity >= 118:
        return {'late_type': '과열후행형', 'late_action': '신규 추격 금지, 보유자는 분할 익절·5일선 이탈 관리'}
    if '후눌림' in pattern or '리테스트' in pattern:
        return {'late_type': '리테스트후행형', 'late_action': '돌파선/구름 상단 재지지 확인 후만 대응'}
    if acc >= 45 and ref >= 5 and material >= 40:
        return {'late_type': '재료잔존후행형', 'late_action': '신규 추격보다 눌림 재확인, 재돌파 양봉 시 분할 대응'}
    if acc >= 35 or ref >= 5:
        return {'late_type': '보유관리후행형', 'late_action': '보유자는 이탈선 관리, 신규는 눌림 후 재안착 대기'}
    return {'late_type': '단순후행형', 'late_action': '좋아 보여도 한 박자 늦은 자리, 신규는 원칙적 관망'}


def decide_final_label(row) -> str:
    base = _ORIG_decide_final_label(row) if _ORIG_decide_final_label else '관망'
    acc = _ctx_int(_rc_get(row, '세력흔적점수', 0), 0)
    ref = _ctx_int(_rc_get(row, '정제이력점수', 0), 0)
    mat = _ctx_int(_rc_get(row, '재료잔존점수', 0), 0)
    fake = '가짜수박' in str(_rc_get(row, '수박정제태그', '') or '') or _ctx_bool(_rc_get(row, '수박정제주의', False))
    disparity = _ctx_float(_rc_get(row, '이격', 0), 0)
    ctx = calc_context_bonus_score({'세력흔적점수': acc, '정제이력점수': ref, '재료잔존점수': mat})
    if base == '추격 금지':
        if not fake and disparity < 118 and (acc >= 45 or ref >= 8) and mat >= 40:
            return '눌림 대기'
        return base
    if base == '관망' and ctx >= 25: return '선취 관찰'
    if base == '보유자 대응' and acc >= 45 and ref >= 5 and mat >= 40 and disparity < 118: return '눌림 대기'
    if base == '눌림 대기' and acc >= 55 and ref >= 8 and mat >= 60 and disparity <= 115: return '즉시 관찰'
    return base


def _build_context_trace_lines(row):
    lines = []
    acc_score = _ctx_int(_rc_get(row, '세력흔적점수', _rc_get(row, 'force_trace_score', 0)), 0)
    acc_tag = str(_rc_get(row, '세력흔적태그', _rc_get(row, 'force_trace_tag', '')) or '').strip()
    acc_comment = str(_rc_get(row, '세력흔적코멘트', _rc_get(row, 'force_trace_comment', '')) or '').strip()
    if acc_score > 0 or acc_tag:
        lines.append(f"🧲 세력흔적: {acc_tag or '👀흔적참고'} {acc_score}점" + (f" | {acc_comment[:46]}" if acc_comment else ''))
    ref_score = _ctx_int(_rc_get(row, '정제이력점수', _rc_get(row, 'recent_refine_score', 0)), 0)
    ref_tag = str(_rc_get(row, '정제이력태그', _rc_get(row, 'recent_refine_tag', '')) or '').strip()
    ref_comment = str(_rc_get(row, '정제이력코멘트', _rc_get(row, 'recent_refine_comment', '')) or '').strip()
    if ref_score > 0 or ref_tag:
        lines.append(f"🧪 정제이력: {ref_tag or '최근 이력 참고'} {ref_score}점" + (f" | {ref_comment[:46]}" if ref_comment else ''))
    mat_score = _ctx_int(_rc_get(row, '재료잔존점수', _rc_get(row, 'material_score', 0)), 0)
    mat_tag = str(_rc_get(row, '재료잔존태그', _rc_get(row, 'material_tag', '')) or '').strip()
    mat_comment = str(_rc_get(row, '재료잔존코멘트', _rc_get(row, 'material_comment', '')) or '').strip()
    if mat_score > 0 or mat_tag:
        lines.append(f"📰 재료잔존: {mat_tag or '⚪미확인'} {mat_score}점" + (f" | {mat_comment[:48]}" if mat_comment else ''))
    late = classify_late_response_type(row)
    if late.get('late_type'):
        lines.append(f"🛡️ 후행유형: {late['late_type']} | {late['late_action']}")
    bonus = calc_context_bonus_score({**(row if isinstance(row, dict) else {}), '세력흔적점수': acc_score, '정제이력점수': ref_score, '재료잔존점수': mat_score})
    if bonus:
        lines.append(f"🧮 맥락보너스: +{bonus} | 오늘 신호 외 최근 흔적을 보정 반영")
    return lines


def build_easy_interpretation(row) -> dict:
    out = _ORIG_build_easy_interpretation(row) if _ORIG_build_easy_interpretation else {'easy_interpretation': '', 'action_summary': '', 'caution': '', 'final_label': decide_final_label(row), 'need_check': ''}
    acc = _ctx_int(_rc_get(row, '세력흔적점수', 0), 0)
    ref = _ctx_int(_rc_get(row, '정제이력점수', 0), 0)
    mat = _ctx_int(_rc_get(row, '재료잔존점수', 0), 0)
    extra = []
    if acc >= 35: extra.append('최근 세력매집 흔적이 있어 단순 탈락보다 눌림 후 재확인을 우선합니다')
    if ref >= 5: extra.append('최근 정제수박 이력이 있어 오늘 조건이 조금 약해도 구조 품질은 긍정으로 봅니다')
    if mat >= 70: extra.append('재료가 아직 살아 있는 편이라 섹터 동행과 후속 뉴스 확인이 중요합니다')
    elif mat and mat < 25: extra.append('재료 잔존 점수는 낮아 차트 신호만으로 추격하면 위험합니다')
    if extra:
        out['easy_interpretation'] = (str(out.get('easy_interpretation', '')).strip() + ' ' + ' '.join(_sentence(x) for x in extra)).strip()
    out['final_label'] = decide_final_label(row)
    if out['final_label'] in ('즉시 관찰', '눌림 대기') and acc >= 35 and ref >= 5:
        out['action_summary'] = '신규 추격보다 돌파선·구름 상단·5일선 중 하나의 눌림 지지를 확인하고, 재돌파 양봉에서 분할 대응합니다.'
    return out


def enrich_row_with_human_commentary(row):
    base = _ORIG_enrich_row_with_human_commentary(row) if _ORIG_enrich_row_with_human_commentary else (dict(row) if isinstance(row, dict) else row.to_dict())
    try:
        ctx_lines = _build_context_trace_lines(base)
        if ctx_lines:
            block = str(base.get('interpretation_block', '') or '')
            lines = block.splitlines() if block else []
            insert_at = len(lines)
            for i, ln in enumerate(lines):
                if ln.startswith('✅ '):
                    insert_at = i
                    break
            for ln in reversed(ctx_lines):
                if ln and ln not in lines:
                    lines.insert(insert_at, ln)
            base['interpretation_block'] = '\n'.join(lines)
        base['final_label'] = decide_final_label(base)
        base['score_summary'] = build_score_summary(base)
        # v2: 과거에 만들어진 interpretation_block 안의 구 DROP 표현도 최종 출력 직전에 정리한다.
        try:
            block = str(base.get('interpretation_block', '') or '')
            if block:
                block = block.replace('👀 밴드외 구조관찰 | 핵심 밴드 타점 미충족', '👀 밴드외 구조관찰 | 핵심 밴드 타점 미충족')
                block = block.replace('👀 구조관찰 | 단계 시퀀스 미충족', '👀 밴드외 구조관찰 | 핵심 밴드 타점 미충족')
                block = block.replace('🧩 구조 해석:', '🧩 구조 해석:')
                block = block.replace('핵심 밴드/단계 조건은 완전 통과가 아니지만, 상태·저항구름·정제이력·세력흔적을 함께 보며 관찰합니다.', '핵심 밴드/단계 조건은 완전 통과가 아니지만, 상태·저항구름·정제이력·세력흔적을 함께 보며 관찰합니다.')
                base['interpretation_block'] = block
        except Exception:
            pass
    except Exception:
        pass
    return base


def build_and_sort_candidates(all_hits_sorted, top_k=50):
    if not all_hits_sorted:
        return pd.DataFrame()
    enriched_rows = []
    for x in all_hits_sorted:
        item = dict(x)
        if '재료잔존점수' not in item:
            m = calc_material_survival_score(item)
            item['재료잔존점수'] = int(m['material_score'])
            item['재료잔존태그'] = m['material_tag']
            item['재료잔존코멘트'] = m['material_comment']
        item['맥락보너스점수'] = calc_context_bonus_score(item)
        item['맥락안전점수'] = _ctx_int(item.get('안전점수', 0), 0) + _ctx_int(item.get('맥락보너스점수', 0), 0)
        item['맥락N점수'] = _ctx_int(item.get('N점수', 0), 0) + int(_ctx_int(item.get('맥락보너스점수', 0), 0) * 0.6)
        enriched_rows.append(item)
    n_top = sorted(enriched_rows, key=lambda x: (x.get('맥락N점수', x.get('N점수', 0)), x.get('맥락안전점수', x.get('안전점수', 0))), reverse=True)[:top_k]
    ranked = sorted(n_top, key=lambda x: (x.get('단계랭크', 0), x.get('맥락안전점수', x.get('안전점수', 0)), x.get('맥락N점수', x.get('N점수', 0))), reverse=True)
    return pd.DataFrame(ranked)



