def _v5_trade_safe_str(x, default=''):
    try:
        if x is None:
            return default
        return str(x).strip()
    except Exception:
        return default


def _v5_trade_replace_ambiguous(text):
    s = _v5_trade_safe_str(text)
    try:
        if 'replace_ambiguous_trade_words' in globals():
            s = replace_ambiguous_trade_words(s)
    except Exception:
        pass
    s = s.replace(
        '중간 구간으로 진입보다는 구름 상단 안착과 재돌파 확인이 필요하다.',
        '구조상 돌파/테스트는 보였지만 지금 매매는 추격이 아니라 구름상단·5일선 눌림 후 재양봉 확인입니다.'
    )
    s = s.replace(
        '구름 상단 안착, 거래량 재유입, 재안착 신호가 나오는지 더 지켜봅니다.',
        '구름상단 지지 + 5일선 재안착 + 재양봉 + 거래량 재유입 중 2개 이상 확인될 때 대응합니다.'
    )
    return s


def _v5_trade_block(row):
    try:
        if 'build_trade_clarity_block' in globals():
            block = build_trade_clarity_block(row, compact=True)
            if '✅ 구조판정' in str(block):
                return str(block).strip()
    except Exception:
        pass

    # 폴백: 최소한 구조판정/매매판정은 무조건 출력
    try:
        data = row.to_dict() if hasattr(row, 'to_dict') else dict(row or {})
    except Exception:
        data = {}
    text = ' '.join(str(data.get(k, '') or '') for k in [
        '수박최종상태', '수박상태명', '상태', '최종상태', '추천단계', '유형',
        '저항구름상태', '저항구름태그', '수박정제태그', 'final_label', '판정'
    ])
    structure = '구조관찰형'
    if '저항돌파' in text:
        structure = '저항구름 돌파확인형'
    elif '저항테스트' in text:
        structure = '저항구름 돌파테스트형'
    elif '저항전' in text:
        structure = '저항 전 선취관찰형'
    elif 'Blue-2' in text or '재점화' in text:
        structure = '재점화 확인형'

    action = '관찰'
    if '추격 금지' in text or '과열후행형' in text or '가짜수박주의' in text:
        action = '추격 금지' if '과열' in text else '확인 대기'
    elif '후행' in text or '보유자 대응' in text:
        action = '보유자 대응'
    elif '눌림' in text or '저항돌파' in text:
        action = '눌림 대기'
    elif '선취' in text or '초입' in text:
        action = '선취 관찰'

    return '\n'.join([
        f'✅ 구조판정: {structure}',
        f'⏳ 매매판정: {action}',
        '📌 실행조건: 구름상단 지지 / 5일선 재안착 / 재양봉 / 거래량 재유입',
        '⚠️ 주의: 돌파 직후 추격 부담 / 구름상단 이탈 시 가짜돌파 가능',
        '🧠 의미: 구조판정은 차트 위치이고, 매매판정은 지금 행동입니다. 돌파확인형이어도 매매는 눌림 확인 후 대응할 수 있습니다.',
    ])


def _v5_append_trade_block_once(text, row):
    out = _v5_trade_replace_ambiguous(text)
    tb = _v5_trade_block(row)
    if tb and '✅ 구조판정' not in out:
        out = out.rstrip() + '\n\n' + tb.strip()
    return out.rstrip() + '\n'


def enrich_row_with_human_commentary(row):
    if _V5_BASE_ENRICH_ROW_WITH_HUMAN_COMMENTARY:
        try:
            base = _V5_BASE_ENRICH_ROW_WITH_HUMAN_COMMENTARY(row)
        except Exception:
            try:
                base = row.to_dict() if hasattr(row, 'to_dict') else dict(row or {})
            except Exception:
                base = {}
    else:
        try:
            base = row.to_dict() if hasattr(row, 'to_dict') else dict(row or {})
        except Exception:
            base = {}

    try:
        tb = _v5_trade_block(base)
        if 'build_trade_clarity_view' in globals():
            view = build_trade_clarity_view(base)
            base['구조판정'] = view.get('structure', '')
            base['매매판정'] = view.get('action', '')
            base['매매레벨'] = view.get('level', '')
        base['매매관점블록'] = tb
        old = _v5_trade_replace_ambiguous(base.get('interpretation_block', ''))
        if tb and '✅ 구조판정' not in old:
            base['interpretation_block'] = (old.rstrip() + '\n' + tb).strip() if old else tb
        else:
            base['interpretation_block'] = old
        for key in ['easy_interpretation', 'action_summary', 'caution', 'need_check']:
            if isinstance(base.get(key), str):
                base[key] = _v5_trade_replace_ambiguous(base.get(key))
    except Exception as _v5_e:
        try:
            base['interpretation_block'] = (str(base.get('interpretation_block', '') or '').strip() + f'\n⚠️ 매매관점 V5 보정 실패: {_v5_e}').strip()
        except Exception:
            pass
    return base


def append_interpretation_to_block(block, row):
    out = str(block or '')
    if _V5_BASE_APPEND_INTERPRETATION_TO_BLOCK:
        try:
            out = _V5_BASE_APPEND_INTERPRETATION_TO_BLOCK(out, row)
        except Exception:
            pass
    return _v5_append_trade_block_once(out, row)


def _v5_refine_validation(row):
    try:
        if 'build_refine_validation_text' in globals():
            return str(build_refine_validation_text(row) or '').strip()
    except Exception:
        pass
    return ''


def _v5_wrap_card(text, rank=1):
    try:
        if '_wrap_stock_card' in globals():
            return _wrap_stock_card(text, rank=rank)
    except Exception:
        pass
    div = '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━'
    return f'{div}\n{str(text).strip()}\n{div}\n\n'


def _v5_block_header(icon, title):
    try:
        if '_text_block_header' in globals():
            return _text_block_header(icon, title)
    except Exception:
        pass
    return f'{icon} [{title}]\n\n'


def build_watermelon_state_block(title: str, df):
    """수박 상태 블록 복구판: 빨강/파란/초입/눌림/후행 모든 카드에 매매관점 줄을 강제 표시."""
    try:
        df = _filter_fake_rows_for_actionable_block(df, title) if '_filter_fake_rows_for_actionable_block' in globals() else df
    except Exception:
        pass
    if df is None or getattr(df, 'empty', False):
        return f'🍉 [{title}]\n- 해당 종목 없음\n'

    lines = [_v5_block_header('🍉', title)]
    try:
        iterator = df.head(5).iterrows()
    except Exception:
        iterator = []

    for rank, (_, row) in enumerate(iterator, 1):
        human = enrich_row_with_human_commentary(row)
        name = _v5_trade_safe_str(human.get('종목명', human.get('name', '')))
        code = _v5_trade_safe_str(human.get('code', human.get('종목코드', '')))
        state = _v5_trade_safe_str(human.get('수박최종상태', human.get('수박상태명', human.get('wm_state_name', ''))))
        grade = _v5_trade_safe_str(human.get('수박상태등급', human.get('wm_state_grade', '')))
        cloud_tag = _v5_trade_safe_str(human.get('저항구름태그', ''))
        cloud_comment = _v5_trade_safe_str(human.get('저항구름코멘트', ''))
        refine_tag = _v5_trade_safe_str(human.get('수박정제태그', ''))
        refine_comment = _v5_trade_safe_str(human.get('수박정제코멘트', ''))
        ma5_tag = _v5_trade_safe_str(human.get('5일재안착태그', ''))
        ma5_comment = _v5_trade_safe_str(human.get('5일재안착코멘트', ''))
        time_comment = _v5_trade_safe_str(human.get('time_sym_comment', ''))
        tags = human.get('수박상태태그', human.get('wm_state_tags', ''))
        if isinstance(tags, list):
            tags = ' '.join([str(x) for x in tags])
        tags = _v5_trade_safe_str(tags)
        b = human.get('수박기반점수', human.get('wm_base_score', 0))
        p = human.get('수박포켓점수', human.get('wm_pocket_score', 0))
        a = human.get('수박공격점수', human.get('wm_attack_score', 0))
        blue = human.get('수박파란점선점수', human.get('wm_blue_score', 0))
        blue1 = human.get('파란점선1단기점수', human.get('wm_blue1_score', 0))
        blue2 = human.get('파란점선2스윙점수', human.get('wm_blue2_score', 0))
        easy = _v5_trade_replace_ambiguous(human.get('easy_interpretation', ''))
        need_check = _v5_trade_replace_ambiguous(human.get('need_check', ''))
        action_summary = _v5_trade_replace_ambiguous(human.get('action_summary', ''))
        caution = _v5_trade_replace_ambiguous(human.get('caution', ''))
        final_label = _v5_trade_safe_str(human.get('final_label', ''))
        score_summary = _v5_trade_safe_str(human.get('score_summary', human.get('점수해석', '')))
        refine_check = _v5_refine_validation(human)

        card = (
            f'{rank}) {name}' + (f'({code})' if code else '') + '\n'
            f'- 상태: {state} | 등급:{grade}\n'
            f'- 점수: 기반{b} / 포켓{p} / 공격{a} / 파란{blue} (B1:{blue1}, B2:{blue2})\n'
            + (f'- 태그: {tags}\n' if tags else '')
            + (f'- 시간창: {time_comment}\n' if time_comment and ('근접' in time_comment or '예비' in time_comment) else '')
            + (f'- 재안착: {ma5_tag} | {ma5_comment}\n' if ma5_tag else '')
            + (f'- 저항구름: {cloud_tag}' + (f' | {cloud_comment}' if cloud_comment else '') + '\n' if cloud_tag else '')
            + (f'- 정제: {refine_tag}' + (f' | {refine_comment}' if refine_comment else '') + '\n' if refine_tag else '')
            + (f'- 정제검증: {refine_check}\n' if refine_check else '')
            + (f'- 쉬운 해설: {easy}\n' if easy else '')
            + (f'- 확인 필요: {need_check}\n' if need_check and ('관찰수박' in refine_tag or '가짜수박주의' in refine_tag or state in ('초입수박', '눌림수박', 'Blue-2예비', 'Blue-2스윙', 'Blue-1단기', '후행수박')) else '')
            + (f'- 대응 요약: {action_summary}\n' if action_summary else '')
            + (f'- 주의 포인트: {caution}\n' if caution else '')
            + (f'- 최종 판정: {final_label}\n' if final_label else '')
            + (f'- 점수 해석: {score_summary}\n' if score_summary else '')
        )
        card = _v5_append_trade_block_once(card, human)
        lines.append(_v5_wrap_card(card, rank=rank))
    return ''.join(lines).rstrip() + '\n'


def build_trading_view_compressed(report_text: str) -> str:
    try:
        if _V5_BASE_BUILD_TRADING_VIEW_COMPRESSED:
            out = _V5_BASE_BUILD_TRADING_VIEW_COMPRESSED(report_text)
        else:
            out = ''
    except Exception as e:
        out = f'━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n🎯 [오늘의 매매관점 압축]\n- 생성 실패: {e}\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━'
    out = _v5_trade_replace_ambiguous(out)
    guide = (
        '\n\n📘 용어정리\n'
        '- 구조판정: 차트가 어디까지 왔는지입니다. 예: 돌파확인형, 저항테스트형.\n'
        '- 매매판정: 지금 행동입니다. 예: 조건부 실행, 눌림 대기, 보유자 대응, 추격 금지.\n'
        '- 돌파확인형 + 눌림대기 = 이미 저항은 넘었지만 현재가 추격은 피하고, 구름상단/5일선 지지 후 재양봉을 기다린다는 뜻입니다.'
    )
    if '📘 용어정리' not in out:
        out = out.rstrip() + guide
    return out

