print("✅ EXPECT_V7 = 매매관점압축직접삽입 / 가짜수박오탐보정 / final_block복구")


def _v7_s(x, default=''):
    try:
        if x is None:
            return default
        return str(x).strip()
    except Exception:
        return default


def _v7_bool(x):
    """문자열 'False'가 bool(True)로 처리되는 문제 방지."""
    try:
        if x is None:
            return False
        if isinstance(x, bool):
            return x
        s = str(x).strip().lower()
        if s in ('', '0', 'false', 'none', 'nan', 'no', 'n', 'off'):
            return False
        if s in ('1', 'true', 'yes', 'y', 'on'):
            return True
        try:
            return float(s) != 0.0
        except Exception:
            return False
    except Exception:
        return False


def _tv_detect_refine(row):
    """V7: 실제 정제 태그를 최우선으로 보고, 수박정제주의 오탐을 보정한다."""
    refine_text = ' '.join([
        _tv_safe_str(_tv_pick(row, '수박정제태그', default='')),
        _tv_safe_str(_tv_pick(row, '수박정제코멘트', default='')),
        _tv_safe_str(_tv_pick(row, '정제', '정제상태', 'refine', default='')),
    ])
    if '정제수박' in refine_text:
        return '정제수박'
    if '관찰수박' in refine_text:
        return '관찰수박'
    if '가짜수박주의' in refine_text or '가짜수박' in refine_text:
        return '가짜수박주의'
    if _v7_bool(_tv_pick(row, '수박정제통과', default=False)):
        return '정제수박'
    if _v7_bool(_tv_pick(row, '수박정제관찰', default=False)):
        return '관찰수박'
    if _v7_bool(_tv_pick(row, '수박정제주의', default=False)):
        return '가짜수박주의'
    return '정제불명'


def _v7_df_rows(df, limit=5):
    if df is None:
        return []
    try:
        if getattr(df, 'empty', False):
            return []
        rows = []
        for _, row in df.head(limit).iterrows():
            try:
                rows.append(enrich_row_with_human_commentary(row))
            except Exception:
                rows.append(row)
        return rows
    except Exception:
        return []


def _v7_code(row):
    code = _v7_s(_tv_pick(row, 'code', '종목코드', 'Code', default=''))
    return code.zfill(6) if code and code.isdigit() else code


def _v7_name(row):
    return _v7_s(_tv_pick(row, '종목명', 'Name', 'name', default=''))


def _v7_state(row):
    return _v7_s(_tv_pick(row, '수박최종상태', '수박상태명', '상태', '추천단계', default='-')) or '-'


def _v7_score_text(row):
    parts = []
    for label, keys in [
        ('돌파', ('돌파점수',)),
        ('선취', ('선취점수', '단테점수')),
        ('안전', ('안전점수',)),
        ('N', ('N점수',)),
    ]:
        val = _tv_pick(row, *keys, default='')
        if _v7_s(val) not in ('', '0', '0.0'):
            try:
                parts.append(f"{label}{int(float(val))}")
            except Exception:
                parts.append(f"{label}{_v7_s(val)}")
    return ' / '.join(parts[:3])


def _v7_trade_view(row):
    try:
        return build_trade_clarity_view(row)
    except Exception:
        return {'structure':'구조관찰형','action':'관찰','level':'observe','meaning':'구조 확인이 더 필요합니다.'}


def _v7_reason(row):
    for k in ['easy_interpretation', 'action_summary', '선정이유', '선취이유', '돌파이유', 'N조합']:
        v = _v7_s(_tv_pick(row, k, default=''))
        if v:
            return v[:110]
    v = _v7_trade_view(row)
    return v.get('meaning', '구조·정제·저항구름 조합 기준')


def _v7_add_unique(bucket, row, used):
    name = _v7_name(row)
    code = _v7_code(row)
    if not name:
        return False
    key = code or name
    if key in used:
        return False
    used.add(key)
    bucket.append(row)
    return True


def _v7_format_bucket(rows):
    if not rows:
        return '- 해당 종목 없음'
    out = []
    for idx, row in enumerate(rows, 1):
        name = _v7_name(row)
        code = _v7_code(row)
        state = _v7_state(row)
        v = _v7_trade_view(row)
        score = _v7_score_text(row)
        score_txt = f" | 점수:{score}" if score else ''
        out.append(
            f"{idx}) {name}" + (f"({code})" if code else '') +
            f" / 매매:{v.get('action','관찰')} / 구조:{v.get('structure','-')} / 상태:{state}{score_txt}\n"
            f"   → {_v7_reason(row)}"
        )
    return '\n'.join(out)


def build_trade_action_summary_block_from_frames(
    telegram_targets=None,
    wm_red_top5=None,
    wm_blue_top5=None,
    dante_pick_df=None,
    dante_watch_df=None,
    breakout_pick_df=None,
    breakout_watch_df=None,
    wm_pullback_top5=None,
    wm_late_top5=None,
    dante_ex_df=None,
):
    """V7: final_block 앞에 반드시 들어가는 매매관점 압축 블록."""
    used = set()
    run, pre, pull, hold, avoid = [], [], [], [], []

    for df in [wm_blue_top5, wm_red_top5, breakout_pick_df, telegram_targets]:
        for row in _v7_df_rows(df, 10):
            v = _v7_trade_view(row)
            state_txt = _tv_state_text(row)
            if v.get('action') == '조건부 실행' or ('Blue-2' in state_txt and v.get('action') not in ('추격 금지','보유자 대응')):
                _v7_add_unique(run, row, used)
            if len(run) >= 3:
                break
        if len(run) >= 3:
            break

    for df in [dante_pick_df, dante_watch_df, wm_pullback_top5, telegram_targets]:
        for row in _v7_df_rows(df, 10):
            v = _v7_trade_view(row)
            state_txt = _tv_state_text(row)
            if v.get('action') == '선취 관찰' or '선취' in state_txt or '눌림수박' in state_txt:
                _v7_add_unique(pre, row, used)
            if len(pre) >= 3:
                break
        if len(pre) >= 3:
            break

    for df in [breakout_watch_df, breakout_pick_df, wm_pullback_top5, telegram_targets]:
        for row in _v7_df_rows(df, 12):
            v = _v7_trade_view(row)
            if v.get('action') in ('눌림 대기', '돌파확인 대기', '확인 대기'):
                _v7_add_unique(pull, row, used)
            if len(pull) >= 3:
                break
        if len(pull) >= 3:
            break

    for df in [wm_late_top5, telegram_targets]:
        for row in _v7_df_rows(df, 12):
            if _v7_trade_view(row).get('action') == '보유자 대응':
                _v7_add_unique(hold, row, used)
            if len(hold) >= 4:
                break
        if len(hold) >= 4:
            break

    for df in [dante_ex_df, wm_late_top5, telegram_targets]:
        for row in _v7_df_rows(df, 12):
            if _v7_trade_view(row).get('action') == '추격 금지':
                _v7_add_unique(avoid, row, used)
            if len(avoid) >= 4:
                break
        if len(avoid) >= 4:
            break

    conclusion_run = _v7_name(run[0]) if run else '없음'
    conclusion_pre = _v7_name(pre[0]) if pre else '없음'

    return f"""━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
🎯 [오늘의 매매관점 압축]

✅ 1순위 실행 후보
{_v7_format_bucket(run)}

🧭 2순위 선취 후보
{_v7_format_bucket(pre)}

👀 3순위 눌림/돌파확인 관찰
{_v7_format_bucket(pull)}

🛡️ 보유자 대응
{_v7_format_bucket(hold)}

⛔ 추격 금지
{_v7_format_bucket(avoid)}

📌 오늘 결론
- 실행 우선: {conclusion_run}
- 선취 관찰: {conclusion_pre}
- 돌파확인형은 구조명이고, 실제 매매는 눌림·안착·재양봉 확인 뒤 대응
- 후행형/과열형은 신규보다 보유관리 또는 추격금지
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"""

