def run_ai_tournament(candidate_list, issues):
    if _V8_BASE_RUN_AI_TOURNAMENT is None:
        return "⚠️ AI 토너먼트 함수 없음"
    safe_candidates = _v8_filter_ai_candidate_list(candidate_list)
