def _run_main7_ai_debate(ai_candidates_df, issues=None, market_news=None):
    """AI 토론은 안전 후보로만 돌리되, 결과 병합은 원본 후보 표에 되돌린다."""
    if _V8_BASE_MAIN7_AI_DEBATE is None:
        return ai_candidates_df, '', []
    safe_df = _v8_filter_ai_candidate_list(ai_candidates_df)
    merged_safe, telegram_text, debate_rows = _V8_BASE_MAIN7_AI_DEBATE(safe_df, issues=issues, market_news=market_news)
    try:
        if debate_rows and '_merge_debate_rows_into_candidates' in globals():
            merged_full = _merge_debate_rows_into_candidates(ai_candidates_df, debate_rows)
            return merged_full, telegram_text, debate_rows
    except Exception:
        pass
    return ai_candidates_df, telegram_text, debate_rows


