def _v82_fmt_price(v):
    try:
        v = float(v or 0)
        if v <= 0:
            return '-'
        return f"{int(round(v)):,}"
    except Exception:
        return '-'


def _v82_wave_box_info(df, cols, period=20, label='소파동'):
    out = {
        'low': 0.0, 'high': 0.0, 'mid': 0.0,
        'state': f'{label} 미검출', 'desc': '',
        'box_dir': '미검출', 'angle': 0.0, 'slope_pct': 0.0,
        'pos_pct': 0.0, 'pos_label': '미검출',
    }
    try:
        if df is None or len(df) < max(5, min(period, 10)):
            out['desc'] = f'{period}봉 데이터 부족'
            return out
        high_col, low_col, close_col = cols.get('high'), cols.get('low'), cols.get('close')
        if not high_col or not low_col or not close_col:
            out['desc'] = '가격 컬럼 부족'
            return out
        recent = df.iloc[max(0, len(df)-int(period)):].copy()
        if recent.empty:
            out['desc'] = f'{period}봉 구간 없음'
            return out
        highs = recent[high_col].astype(float)
        lows = recent[low_col].astype(float)
        closes = recent[close_col].astype(float)
        low = _acc_safe_float(lows.min(), 0.0)
        high = _acc_safe_float(highs.max(), 0.0)
        close = _acc_safe_float(closes.iloc[-1], 0.0)
        if low <= 0 or high <= 0 or high <= low or close <= 0:
            out['desc'] = '고저/종가 계산 부족'
            return out
        mid = (low + high) / 2.0
        rng = max(high - low, 1e-9)
        pos_pct = (close - low) / rng * 100.0
        if pos_pct < 0:
            pos_label = '박스 하향이탈'
        elif pos_pct <= 25:
            pos_label = '하단권'
        elif pos_pct <= 60:
            pos_label = '중단권'
        elif pos_pct <= 85:
            pos_label = '상단권'
        elif pos_pct <= 100:
            pos_label = '전고점 근접'
        else:
            pos_label = '박스 상향돌파'

        half = max(2, len(recent)//2)
        first = recent.iloc[:half]
        second = recent.iloc[-half:]
        first_center = (_acc_safe_float(first[high_col].astype(float).max(), high) + _acc_safe_float(first[low_col].astype(float).min(), low)) / 2.0
        second_center = (_acc_safe_float(second[high_col].astype(float).max(), high) + _acc_safe_float(second[low_col].astype(float).min(), low)) / 2.0
        denom = max(abs(first_center), 1e-9)
        slope_pct = ((second_center / denom) - 1.0) * 100.0 / max(1, half)
        try:
            angle = math.degrees(math.atan(slope_pct))
        except Exception:
            angle = 0.0
        if slope_pct >= 0.25:
            box_dir = '상향박스'
        elif slope_pct >= 0.08:
            box_dir = '완만상향'
        elif slope_pct <= -0.25:
            box_dir = '하향박스'
        elif slope_pct <= -0.08:
            box_dir = '완만하향'
        else:
            box_dir = '횡보박스'

        if pos_label == '박스 상향돌파':
            state = f'{label} 상향돌파'
        elif pos_label == '박스 하향이탈':
            state = f'{label} 하향이탈'
        else:
            state = f'{label} {pos_label}'

        if '상향' in box_dir and pos_pct <= 85:
            desc = f'{box_dir} 안에서 {pos_label}. 눌림 지지 확인 시 재상승 관찰'
        elif '상향' in box_dir and pos_pct > 85:
            desc = f'{box_dir} 상단부. 돌파는 좋지만 추격보다 안착 확인'
        elif '하향' in box_dir:
            desc = f'{box_dir}. 반등보다 하락각 둔화와 박스 재진입 확인 우선'
        else:
            desc = f'{box_dir}. 박스 하단 매수/상단 매도 성격, 돌파 전까지 확인 필요'

        out.update({
            'low': low, 'high': high, 'mid': mid,
            'state': state, 'desc': desc,
            'box_dir': box_dir, 'angle': round(angle, 1), 'slope_pct': round(slope_pct, 3),
            'pos_pct': round(pos_pct, 1), 'pos_label': pos_label,
        })
        return out
    except Exception as e:
        out['desc'] = f'box calc error: {e}'
        return out


def build_wave_levels(df, accum_info=None, lookback=60):
    out = {
        'small_low': 0.0, 'small_high': 0.0, 'small_mid': 0.0,
        'mid_low': 0.0, 'mid_high': 0.0, 'mid_mid': 0.0,
        'small_state': '소파동 미검출', 'mid_state': '중파동 미검출',
        'small_desc': '', 'mid_desc': '',
        'small_box_dir': '미검출', 'mid_box_dir': '미검출',
        'small_angle': 0.0, 'mid_angle': 0.0,
        'small_slope_pct': 0.0, 'mid_slope_pct': 0.0,
        'small_pos_pct': 0.0, 'mid_pos_pct': 0.0,
        'small_pos_label': '미검출', 'mid_pos_label': '미검출',
        'blue_zone_low': 0.0, 'blue_zone_high': 0.0,
        'debug_note': '', 'debug_cols': '', 'debug_len': 0,
        'accum_found': False,
    }
    try:
        if df is None or len(df) == 0:
            out['debug_note'] = 'df empty'
            return out
        cols = _acc_price_cols(df)
        out['debug_cols'] = f"high={cols.get('high','')} low={cols.get('low','')} close={cols.get('close','')}"
        out['debug_len'] = int(len(df))
        if not cols.get('high') or not cols.get('low') or not cols.get('close'):
            out['debug_note'] = 'price cols missing'
            return out
        small = _v82_wave_box_info(df, cols, period=20, label='소파동')
        mid = _v82_wave_box_info(df, cols, period=int(lookback or 60), label='중파동')
        out.update({
            'small_low': small['low'], 'small_high': small['high'], 'small_mid': small['mid'],
            'small_state': small['state'], 'small_desc': small['desc'],
            'small_box_dir': small['box_dir'], 'small_angle': small['angle'], 'small_slope_pct': small['slope_pct'],
            'small_pos_pct': small['pos_pct'], 'small_pos_label': small['pos_label'],
            'mid_low': mid['low'], 'mid_high': mid['high'], 'mid_mid': mid['mid'],
            'mid_state': mid['state'], 'mid_desc': mid['desc'],
            'mid_box_dir': mid['box_dir'], 'mid_angle': mid['angle'], 'mid_slope_pct': mid['slope_pct'],
            'mid_pos_pct': mid['pos_pct'], 'mid_pos_label': mid['pos_label'],
        })
        # 파란타점은 소파동 박스의 55~92% 영역으로 우선 표시하되, 돌파 후에는 눌림확인 구간으로만 해석한다.
        sl, sh = float(small.get('low', 0) or 0), float(small.get('high', 0) or 0)
        if sl > 0 and sh > sl:
            out['blue_zone_low'] = round(sl + (sh - sl) * 0.55, 2)
            out['blue_zone_high'] = round(sl + (sh - sl) * 0.92, 2)
        out['accum_found'] = bool((accum_info or {}).get('found'))
        out['debug_note'] = 'v8.2 box wave ok'
        return out
    except Exception as e:
        out['debug_note'] = f'build_wave_levels v8.2 error: {e}'
        return out


def _v82_wave_line(prefix, waves, low_key, high_key, state_key, desc_key, dir_key, angle_key, slope_key, pos_key, pos_label_key):
    low = float(waves.get(low_key, 0) or 0)
    high = float(waves.get(high_key, 0) or 0)
    state = str(waves.get(state_key, '') or '').strip()
    desc = str(waves.get(desc_key, '') or '').strip()
    box_dir = str(waves.get(dir_key, '') or '').strip()
    angle = float(waves.get(angle_key, 0) or 0)
    slope = float(waves.get(slope_key, 0) or 0)
    pos = float(waves.get(pos_key, 0) or 0)
    pos_label = str(waves.get(pos_label_key, '') or '').strip()
    if low > 0 and high > 0:
        line = f"{prefix}: 박스 {_v82_fmt_price(low)}~{_v82_fmt_price(high)}"
        if pos_label:
            line += f" | 위치 {pos:.0f}%({pos_label})"
        if box_dir:
            line += f" | {box_dir} {angle:+.1f}°({slope:+.2f}%/봉)"
        if state:
            line += f" | {state}"
        if desc:
            line += f" | {desc}"
        return line
    return f"{prefix}: 박스 미검출"


def _build_accumulation_overlay_lines(pkg):
    lines = []
    try:
        accum = (pkg or {}).get('accum', {}) or {}
        waves = (pkg or {}).get('waves', {}) or {}
        pos = (pkg or {}).get('position', {}) or {}

        accum_tag = str(accum.get('label', '') or '').strip()
        accum_score = int(float(accum.get('score', 0) or 0))
        accum_comment = str(accum.get('desc', '') or '').strip()
        if accum_tag and accum_tag != '매집봉 없음':
            line = f"🪵 매집봉: {accum_tag} ({accum_score})"
            if accum_comment:
                line += f" | {accum_comment}"
            lines.append(line)

        lines.append(_v82_wave_line(
            '〰️ 소파동', waves,
            'small_low', 'small_high', 'small_state', 'small_desc',
            'small_box_dir', 'small_angle', 'small_slope_pct', 'small_pos_pct', 'small_pos_label'
        ))
        lines.append(_v82_wave_line(
            '📶 중파동', waves,
            'mid_low', 'mid_high', 'mid_state', 'mid_desc',
            'mid_box_dir', 'mid_angle', 'mid_slope_pct', 'mid_pos_pct', 'mid_pos_label'
        ))

        bz_low = int(float(waves.get('blue_zone_low', 0) or 0))
        bz_high = int(float(waves.get('blue_zone_high', 0) or 0))
        if bz_low > 0 and bz_high > 0:
            lines.append(f"🔵 파란타점 영역: {bz_low:,} ~ {bz_high:,} | 박스 안 지지 확인 구간")

        # 소/중파동 조합 한 줄 해석
        sdir = str(waves.get('small_box_dir', '') or '')
        mdir = str(waves.get('mid_box_dir', '') or '')
        spos = str(waves.get('small_pos_label', '') or '')
        mpos = str(waves.get('mid_pos_label', '') or '')
        if '상향' in sdir and '상향' in mdir and ('상단' not in spos):
            lines.append('🧭 파동해석: 소파동·중파동 모두 상향, 눌림 지지 후 재상승 관찰')
        elif '상향' in sdir and ('하향' in mdir):
            lines.append('🧭 파동해석: 단기 반등은 있으나 중파동 하향, 추격보다 저항 확인')
        elif '하향' in sdir and '하향' in mdir:
            lines.append('🧭 파동해석: 소파동·중파동 모두 하향, 반등보다 하락각 둔화 확인')
        elif '상단' in spos or '전고점' in spos or '돌파' in spos:
            lines.append('🧭 파동해석: 소파동 상단부, 매수는 눌림 재안착 확인이 유리')
        elif '하단' in spos and ('상향' in mdir or '횡보' in mdir):
            lines.append('🧭 파동해석: 박스 하단권, 손절선 짧은 관찰 구간')

        pos_label = str(pos.get('label', '') or '').strip()
        pos_score = int(float(pos.get('score', 0) or 0))
        pos_desc = str(pos.get('desc', '') or '').strip()
        if pos_label:
            line = f"🪑 자리평가: {pos_label} ({pos_score})"
            if pos_desc:
                line += f" | {pos_desc}"
            lines.append(line)
        return lines
    except Exception as e:
        return [f"〰️ 소파동/📶 중파동: 계산 실패 | {e}"]


def build_accumulation_package(df):
    try:
        accum = calc_recent_accum_candle(df, lookback=20)
        waves = build_wave_levels(df, accum, lookback=60)
        pos = evaluate_acc_position(df)
        return {'accum': accum, 'waves': waves, 'position': pos}
    except Exception as e:
        return {
            'accum': {'found': False, 'score': 0, 'grade': '없음', 'label': '매집봉 없음', 'high': 0.0, 'low': 0.0, 'close': 0.0, 'open': 0.0, 'desc': f'package error: {e}'},
            'waves': {'small_low': 0.0, 'small_high': 0.0, 'small_mid': 0.0, 'mid_low': 0.0, 'mid_high': 0.0, 'mid_mid': 0.0, 'small_state': '소파동 미검출', 'mid_state': '중파동 미검출', 'small_desc': '', 'mid_desc': '', 'small_box_dir': '미검출', 'mid_box_dir': '미검출', 'small_angle': 0.0, 'mid_angle': 0.0, 'small_slope_pct': 0.0, 'mid_slope_pct': 0.0, 'small_pos_pct': 0.0, 'mid_pos_pct': 0.0, 'small_pos_label': '미검출', 'mid_pos_label': '미검출', 'blue_zone_low': 0.0, 'blue_zone_high': 0.0, 'debug_note': f'package error: {e}', 'debug_cols': '', 'debug_len': 0, 'accum_found': False},
            'position': {'score': 0, 'label': '자리 정보 부족', 'desc': '', 'pullback_score': 0, 'pullback_label': '', 'd150': 0.0, 'd200': 0.0, 'drawdown_score': 0, 'drawdown_label': '', 'drawdown_pct': 0.0, 'overheat_penalty': 0, 'overheat_label': '', 'disparity': 100.0},
        }


try:
    _V82_BASE_BUILD_WATERMELON_STATE_TOP5 = build_watermelon_state_top5
except Exception:
    _V82_BASE_BUILD_WATERMELON_STATE_TOP5 = None


def _v82_sort_top(df_in, cols):
    try:
        if df_in is None or df_in.empty:
            return pd.DataFrame()
        sort_cols = [c for c in cols if c in df_in.columns]
        if sort_cols:
            return df_in.sort_values(by=sort_cols, ascending=[False] * len(sort_cols)).head(5).reset_index(drop=True)
        return df_in.head(5).reset_index(drop=True)
    except Exception:
        return pd.DataFrame()


def build_watermelon_state_top5(df: pd.DataFrame):
    if _V82_BASE_BUILD_WATERMELON_STATE_TOP5 is None:
        empty = pd.DataFrame()
        return (empty, empty, empty, empty, empty, empty, empty, empty, empty, empty, empty, empty, empty)
    result = _V82_BASE_BUILD_WATERMELON_STATE_TOP5(df)
    try:
        (green_df, red_df, blue_df,
         intro_df, pullback_df, late_df, blue1_df, blue2_df,
         dante_pick_df, dante_watch_df, dante_ex_df,
         breakout_pick_df, breakout_watch_df) = result
        work = df.copy() if df is not None else pd.DataFrame()
        if not work.empty:
            if '수박최종상태' not in work.columns:
                work['수박최종상태'] = work.get('수박상태명', '')
            red_states = ['Blue-1단기', 'Blue-2스윙', 'Blue-2예비']
            red_fallback = _v82_sort_top(work[work['수박최종상태'].isin(red_states)].copy(), ['수박파란점선점수', '파란점선2스윙점수', '수박공격점수', '안전점수', 'N점수'])
            blue_fallback = _v82_sort_top(work[work['수박최종상태'].isin(['Blue-1단기', 'Blue-2스윙'])].copy(), ['수박파란점선점수', '파란점선2스윙점수', '수박공격점수', '안전점수', 'N점수'])
            if (red_df is None or red_df.empty) and not red_fallback.empty:
                red_df = red_fallback
            if (blue_df is None or blue_df.empty) and not blue_fallback.empty:
                blue_df = blue_fallback
        return (green_df, red_df, blue_df,
                intro_df, pullback_df, late_df, blue1_df, blue2_df,
                dante_pick_df, dante_watch_df, dante_ex_df,
                breakout_pick_df, breakout_watch_df)
    except Exception:
        return result


def _v82_format_bucket(rows):
    if not rows:
        return '- 해당 종목 없음'
    out = []
    for idx, row in enumerate(rows, 1):
        name = _v8_name(row)
        code = _v8_code(row)
        action, structure = _v8_trade_action(row)
        state = _v8_state(row)
        score = _v8_score_text(row)
        score_txt = f" | 점수:{score}" if score else ''
        code_txt = f"({code})" if code else ''
        out.append(
            f"{idx}) {name}{code_txt}\n"
            f"   - 매매:{action} / 구조:{structure} / 상태:{state}{score_txt}\n"
            f"   → {_v8_reason(row)}"
        )
    return '\n'.join(out)


# 기존 _v8_format_bucket도 링크 없는 버전으로 교체한다.
_v8_format_bucket = _v82_format_bucket


def build_trade_action_summary_block_from_frames(
    telegram_targets=None,
    wm_red_top5=None,
    wm_blue_top5=None,
    dante_pick_df=None,
    dante_watch_df=None,
    breakout_pick_df=None,
    breakout_watch_df=None,
    wm_pullback_top5=None,
    wm_late_top5=None,
    dante_ex_df=None,
):
    """V8.2: 링크/앵커 없이 텔레그램에서 바로 읽히는 오늘 매매관점 압축."""
    used = set()

    def action_of(row):
        return _v8_trade_action(row)[0]

    def not_hard_bad(row):
        bad, _ = _v8_is_hard_excluded(row, strict=True)
        return not bad

    # 매매판정이 눌림 대기라도 Blue-2/재점화는 '즉시 대응'이 아니라 우선관찰로 분리한다.
    re_fire = _v8_pick_rows(
        [wm_blue_top5, wm_red_top5, telegram_targets],
        lambda r: not_hard_bad(r) and ('Blue-2' in _v8_state(r) or '재점화' in _v8_text_blob(r)),
        used,
        limit=3,
    )

    conditional = _v8_pick_rows(
        [breakout_pick_df, telegram_targets],
        lambda r: not_hard_bad(r) and action_of(r) == '조건부 실행',
        used,
        limit=3,
    )

    pull = _v8_pick_rows(
        [breakout_pick_df, breakout_watch_df, wm_pullback_top5, telegram_targets],
        lambda r: not_hard_bad(r) and action_of(r) in ('눌림 대기', '돌파확인 대기', '확인 대기'),
        used,
        limit=4,
    )

    pre = _v8_pick_rows(
        [dante_pick_df, dante_watch_df, wm_pullback_top5, telegram_targets],
        lambda r: not_hard_bad(r) and (action_of(r) == '선취 관찰' or '선취' in _v8_text_blob(r) or '저항전' in _v8_text_blob(r)),
        used,
        limit=4,
    )

    avoid = _v8_pick_rows(
        [dante_ex_df, wm_late_top5, telegram_targets],
        lambda r: action_of(r) == '추격 금지' or _v8_is_hard_excluded(r, strict=True)[0],
        used,
        limit=5,
    )

    hold = _v8_pick_rows(
        [wm_late_top5, telegram_targets],
        lambda r: action_of(r) == '보유자 대응',
        used,
        limit=5,
    )

    top_re = _v8_name(re_fire[0]) if re_fire else '없음'
    top_cond = _v8_name(conditional[0]) if conditional else '없음'
    top_pull = _v8_name(pull[0]) if pull else '없음'
    top_pre = _v8_name(pre[0]) if pre else '없음'

    return f"""━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
🎯 [오늘 매매관점 압축]

📌 시장모드: 시장 통합 브리핑 기준 확인
📌 오늘 전략: 강한 종목 추격보다 눌림·재안착·구름상단 지지 확인 우선
📌 넥스트 주의: 09:00 이전 신호는 거래량 부족으로 속임수 가능성 있음
📌 09:15~09:18 검색 결과는 1차 검증용, 확정 매수는 09:30 이후 재확인 우대
📌 링크안내: HTML 링크와 검색 앵커는 사용하지 않고, 종목명과 코드만 표시합니다.

🔥 재점화 우선관찰 후보
{_v82_format_bucket(re_fire)}

✅ 조건부 실행 후보
{_v82_format_bucket(conditional)}

👀 눌림 대기 후보
{_v82_format_bucket(pull)}

🧭 선취 관찰 후보
{_v82_format_bucket(pre)}

⛔ 신규 추격 금지
{_v82_format_bucket(avoid)}

🛡️ 보유자 대응
{_v82_format_bucket(hold)}

🧠 오늘 핵심 한 줄
→ 재점화 구조가 보여도 매매판정이 눌림 대기면 즉시 매수가 아니라 09:30 이후 지지·재양봉 확인이 우선입니다.

📌 오늘 우선순위
- 재점화 관찰: {top_re}
- 조건부 실행: {top_cond}
- 눌림 대기: {top_pull}
- 선취 관찰: {top_pre}
- 제외 원칙: 추격금지/보유자대응/후행형/가짜수박주의/이격115↑/RSI70↑는 AI 1위 추천 금지
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"""

