def _v83_safe_float(v, default=0.0):
    try:
        if v is None:
            return default
        if isinstance(v, str):
            v = v.replace(',', '').replace('%', '').strip()
            if not v:
                return default
        return float(v)
    except Exception:
        return default

def _v83_safe_int(v, default=0):
    try:
        return int(round(_v83_safe_float(v, default)))
    except Exception:
        return default

def _v83_price(v):
    n = _v83_safe_int(v, 0)
    return f"{n:,}" if n > 0 else '-'

def _v83_row_dict(row):
    try:
        return row.to_dict() if hasattr(row, 'to_dict') else dict(row or {})
    except Exception:
        return {}

def _v83_wave_line_from_row(d, prefix, low_key, high_key, state_key, comment_key, dir_key, angle_key, slope_key, pct_key, label_key):
    low = _v83_safe_float(d.get(low_key, 0), 0.0)
    high = _v83_safe_float(d.get(high_key, 0), 0.0)
    state = str(d.get(state_key, '') or '').strip()
    comment = str(d.get(comment_key, '') or '').strip()
    box_dir = str(d.get(dir_key, '') or '').strip()
    angle = _v83_safe_float(d.get(angle_key, 0), 0.0)
    slope = _v83_safe_float(d.get(slope_key, 0), 0.0)
    pct = _v83_safe_float(d.get(pct_key, 0), 0.0)
    label = str(d.get(label_key, '') or '').strip()
    if low <= 0 or high <= 0:
        return ''
    line = f"{prefix}: 박스 {_v83_price(low)}~{_v83_price(high)}"
    if pct > 0 or label:
        line += f" | 위치 {pct:.0f}%({label})" if label and pct > 0 else (f" | 위치 {label}" if label else f" | 위치 {pct:.0f}%")
    if box_dir:
        line += f" | {box_dir}"
        if abs(angle) > 0.001 or abs(slope) > 0.001:
            line += f" {angle:+.1f}°({slope:+.2f}%/봉)"
    if state:
        line += f" | {state}"
    if comment:
        line += f" | {comment}"
    return line

def _v83_wave_lines_from_row(row):
    d = _v83_row_dict(row)
    lines = []
    s = _v83_wave_line_from_row(d, '〰️ 소파동', '소파동저점', '소파동전고점', '소파동위치', '소파동코멘트', '소파동박스방향', '소파동각도', '소파동기울기', '소파동위치퍼센트', '소파동위치권')
    if s:
        lines.append(s)
    m = _v83_wave_line_from_row(d, '📶 중파동', '중파동저점', '중파동전고점', '중파동위치', '중파동코멘트', '중파동박스방향', '중파동각도', '중파동기울기', '중파동위치퍼센트', '중파동위치권')
    if m:
        lines.append(m)
    bz_low = _v83_safe_int(d.get('파란타점영역하단', 0), 0)
    bz_high = _v83_safe_int(d.get('파란타점영역상단', 0), 0)
    if bz_low > 0 and bz_high > 0:
        lines.append(f"🔵 파란타점 영역: {bz_low:,} ~ {bz_high:,} | 점이 아니라 박스 안 지지 확인 구간")
    small_txt = ' '.join([str(d.get('소파동박스방향','')), str(d.get('소파동위치권','')), str(d.get('소파동위치',''))])
    mid_txt = ' '.join([str(d.get('중파동박스방향','')), str(d.get('중파동위치권','')), str(d.get('중파동위치',''))])
    if lines:
        if '상향' in small_txt and '상향' in mid_txt and not any(k in small_txt for k in ['전고점', '상향돌파']):
            lines.append('🧭 파동해석: 소파동·중파동 모두 상향, 눌림 지지 후 재상승 관찰')
        elif '상향' in small_txt and '하향' in mid_txt:
            lines.append('🧭 파동해석: 단기 반등은 있으나 중파동은 하향, 추격보다 저항 확인')
        elif '하향' in small_txt and '하향' in mid_txt:
            lines.append('🧭 파동해석: 소파동·중파동 모두 하향, 반등보다 하락각 둔화 확인')
        elif any(k in small_txt for k in ['상단권', '전고점', '상향돌파']):
            lines.append('🧭 파동해석: 소파동 상단부, 매수는 눌림 재안착 확인이 유리')
        elif '하단권' in small_txt:
            lines.append('🧭 파동해석: 소파동 하단권, 손절선 짧은 관찰 구간')
    return lines

