def _v5_append_trade_block_once(text, row):
    try:
        out = _V83_BASE_APPEND_TRADE_BLOCK_ONCE(text, row) if _V83_BASE_APPEND_TRADE_BLOCK_ONCE else str(text or '')
    except Exception:
        out = str(text or '')
    try:
        if '〰️ 소파동:' not in out and '📶 중파동:' not in out:
            wave_lines = _v83_wave_lines_from_row(row)
            if wave_lines:
                wave_text = '\n'.join(wave_lines)
                if '\n✅ 구조판정:' in out:
                    out = out.replace('\n✅ 구조판정:', '\n' + wave_text + '\n\n✅ 구조판정:', 1)
                elif '✅ 구조판정:' in out:
                    out = out.replace('✅ 구조판정:', wave_text + '\n\n✅ 구조판정:', 1)
                else:
                    out = out.rstrip() + '\n' + wave_text
    except Exception as e:
        try:
            out = out.rstrip() + f"\n〰️ 소파동/📶 중파동: 표시 실패 | {e}"
        except Exception:
            pass
    return out.rstrip() + '\n'

