def _v83_state_text_series(work):
    import pandas as _pd
    if work is None or work.empty:
        return _pd.Series([], dtype=str)
    cols = [c for c in ['수박최종상태','수박상태명','상태','최종상태','태그','N구분','추천단계','정제','수박태그'] if c in work.columns]
    if not cols:
        return _pd.Series([''] * len(work), index=work.index, dtype=str)
    return work[cols].astype(str).agg(' '.join, axis=1)

def build_watermelon_state_top5(df):
    if _V83_BASE_BUILD_WATERMELON_STATE_TOP5 is None:
        empty = pd.DataFrame()
        return (empty, empty, empty, empty, empty, empty, empty, empty, empty, empty, empty, empty, empty)
    result = _V83_BASE_BUILD_WATERMELON_STATE_TOP5(df)
    try:
        (green_df, red_df, blue_df, intro_df, pullback_df, late_df, blue1_df, blue2_df, dante_pick_df, dante_watch_df, dante_ex_df, breakout_pick_df, breakout_watch_df) = result
        work = df.copy() if df is not None else pd.DataFrame()
        if not work.empty:
            st = _v83_state_text_series(work)
            red_mask = st.str.contains('Blue-1|Blue-2|Blue1|Blue2|파란점선|재점화', case=False, na=False)
            blue_mask = st.str.contains('Blue-1|Blue-2|Blue1|Blue2|파란점선', case=False, na=False)
            red_fallback = _v82_sort_top(work[red_mask].copy(), ['수박파란점선점수','파란점선2스윙점수','파란점선1단기점수','수박공격점수','수박포켓점수','안전점수','N점수'])
            blue_fallback = _v82_sort_top(work[blue_mask].copy(), ['수박파란점선점수','파란점선2스윙점수','파란점선1단기점수','수박공격점수','수박포켓점수','안전점수','N점수'])
            if (red_df is None or red_df.empty) and not red_fallback.empty:
                red_df = red_fallback
            if (blue_df is None or blue_df.empty) and not blue_fallback.empty:
                blue_df = blue_fallback
        return (green_df, red_df, blue_df, intro_df, pullback_df, late_df, blue1_df, blue2_df, dante_pick_df, dante_watch_df, dante_ex_df, breakout_pick_df, breakout_watch_df)
    except Exception:
        return result

