def _v84_to_dict(row):
    try:
        if isinstance(row, dict):
            return dict(row)
        if hasattr(row, 'to_dict'):
            return row.to_dict()
        return dict(row or {})
    except Exception:
        return {}


def _v84_text(row):
    r = _v84_to_dict(row)
    keys = [
        '종목명','code','final_label','최종판정','매매판정','구조판정','추천단계','유형',
        '수박최종상태','수박상태명','수박상태태그','수박정제태그','수박정제코멘트',
        'N조합','N구분','태그','실행조건','action_summary','easy_interpretation','need_check',
        'interpretation_block','매매관점블록','저항구름태그','저항구름코멘트'
    ]
    return ' '.join(str(r.get(k, '') or '') for k in keys)


def _v84_num(v, default=0.0):
    try:
        if v is None:
            return default
        s = str(v).replace(',', '').replace('%', '').strip()
        if not s:
            return default
        # "116 ⚠️과열" 같은 문자열도 앞 숫자만 살림
        import re as _re
        m = _re.search(r'-?\d+(?:\.\d+)?', s)
        if not m:
            return default
        return float(m.group(0))
    except Exception:
        return default


def _v84_code_name(row):
    r = _v84_to_dict(row)
    code = str(r.get('code') or r.get('종목코드') or r.get('Code') or '').replace('.0','').strip()
    if code.isdigit():
        code = code.zfill(6)
    name = str(r.get('종목명') or r.get('Name') or r.get('name') or '').strip()
    return name, code


def _v84_hard_exclude_reason(row):
    r = _v84_to_dict(row)
    txt = _v84_text(r)
    disparity = _v84_num(r.get('이격') or r.get('Disparity') or r.get('과열이격도'), 100.0)
    rsi = _v84_num(r.get('RSI') or r.get('rsi'), 50.0)

    action = ''
    try:
        action, _structure = _v8_trade_action(r)
    except Exception:
        pass

    if '신규 매수 금지' in txt or '추격 금지' in txt or action == '추격 금지':
        return '추격금지/신규매수금지'
    if '보유자 대응' in txt or action == '보유자 대응':
        return '보유자대응'
    if '후행수박' in txt or '후행형' in txt:
        return '후행형'
    if '가짜수박주의' in txt:
        return '가짜수박주의'
    if disparity >= 115:
        return f'이격{disparity:.0f}↑'
    if rsi >= 70:
        return f'RSI{rsi:.0f}↑'
    return ''


def _v84_filter_ai_df_hard(df, min_keep=1):
    try:
        import pandas as _pd
        if df is None or getattr(df, 'empty', False):
            return df, []
        work = df.copy()
        keep_idx = []
        excluded = []
        for idx, row in work.iterrows():
            reason = _v84_hard_exclude_reason(row)
            if reason:
                name, code = _v84_code_name(row)
                excluded.append(f"{name}({code})/{reason}")
            else:
                keep_idx.append(idx)
        safe = work.loc[keep_idx].copy() if keep_idx else work.iloc[0:0].copy()
        try:
            log_info(f"🧹 V8.4 AI하드가드: {len(work)}개 중 {len(safe)}개 허용 | 제외 {len(excluded)}개")
            if excluded:
                log_info("🧹 V8.4 제외상위: " + ' / '.join(excluded[:8]))
        except Exception:
            pass
        return safe, excluded
    except Exception as e:
        try:
            log_error(f"⚠️ V8.4 AI하드가드 실패: {e}")
        except Exception:
            pass
        return df, []


