def get_tournament_prompt(prompt_data, comments):
    if _V84_BASE_GET_TOURNAMENT_PROMPT:
        system_prompt, user_prompt = _V84_BASE_GET_TOURNAMENT_PROMPT(prompt_data, comments)
    else:
        system_prompt, user_prompt = '', ''
    hard_rule = """

[V8.4 AI 1위 하드가드]
- 추격 금지, 신규 매수 금지, 보유자 대응, 후행수박, 후행형, 가짜수박주의 종목은 단타/스윙 1위로 절대 선정하지 마라.
- 이격 115 이상 또는 RSI 70 이상은 단타/스윙 1위 금지다. 좋아 보여도 눌림 대기 또는 주의 종목으로만 다뤄라.
- 후보가 모두 금지 조건이면 단타 1위와 스윙 1위는 반드시 '해당 없음'이라고 써라.
- 검색기 본문 판정이 눌림 대기/확인 대기면 AI가 즉시 매수로 뒤집지 마라.
- 금지 조건을 어기면 분석 실패로 본다.
"""
    return (str(system_prompt or '') + hard_rule), (str(user_prompt or '') + hard_rule)


