def _v84_wave_lines_for_detail(row):
    try:
        lines = []
        try:
            lines = _v83_wave_lines_from_row(row)
        except Exception:
            lines = []
        if lines:
            return lines
        # V8.3 이전 키만 있을 때도 최소 라인 복구
        r = _v84_to_dict(row)
        small_low = int(_v84_num(r.get('소파동저점'), 0))
        small_high = int(_v84_num(r.get('소파동전고점'), 0))
        mid_low = int(_v84_num(r.get('중파동저점'), 0))
        mid_high = int(_v84_num(r.get('중파동전고점'), 0))
        if small_low > 0 and small_high > 0:
            s = f"〰️ 소파동: 박스 {small_low:,}~{small_high:,}"
            st = str(r.get('소파동위치','') or '').strip()
            cm = str(r.get('소파동코멘트','') or '').strip()
            if st: s += f" | {st}"
            if cm: s += f" | {cm}"
            lines.append(s)
        if mid_low > 0 and mid_high > 0:
            m = f"📶 중파동: 박스 {mid_low:,}~{mid_high:,}"
            st = str(r.get('중파동위치','') or '').strip()
            cm = str(r.get('중파동코멘트','') or '').strip()
            if st: m += f" | {st}"
            if cm: m += f" | {cm}"
            lines.append(m)
        bz_low = int(_v84_num(r.get('파란타점영역하단'), 0))
        bz_high = int(_v84_num(r.get('파란타점영역상단'), 0))
        if bz_low > 0 and bz_high > 0:
            lines.append(f"🔵 파란타점 영역: {bz_low:,} ~ {bz_high:,} | 점이 아니라 박스 안 지지 확인 구간")
        return lines
    except Exception:
        return []


def enrich_row_with_human_commentary(row):
    if _V84_BASE_ENRICH_ROW_WITH_HUMAN_COMMENTARY:
        base = _V84_BASE_ENRICH_ROW_WITH_HUMAN_COMMENTARY(row)
    else:
        base = _v84_to_dict(row)
        base['interpretation_block'] = ''
    try:
        block = str(base.get('interpretation_block', '') or '')
        source = dict(_v84_to_dict(row))
        source.update(_v84_to_dict(base))
        wave_lines = _v84_wave_lines_for_detail(source)
        if wave_lines and '〰️ 소파동:' not in block and '📶 중파동:' not in block:
            wave_text = '\n'.join(wave_lines)
            if '✅ 최종 판정:' in block:
                block = block.replace('✅ 최종 판정:', wave_text + '\n✅ 최종 판정:', 1)
            elif '🧮 점수 해석:' in block:
                block = block.replace('🧮 점수 해석:', wave_text + '\n🧮 점수 해석:', 1)
            else:
                block = (block.rstrip() + '\n' + wave_text).strip()
            base['interpretation_block'] = block
    except Exception as e:
        try:
            base['interpretation_block'] = str(base.get('interpretation_block','') or '').rstrip() + f"\n〰️ 소파동/📶 중파동: 표시 실패 | {e}"
        except Exception:
            pass
    return base


