def _v87_norm_code(value):
    raw=str(value or '').strip()
    if not raw: return ''
    if _v91_re.fullmatch(r'\d+\.0+', raw): raw=raw.split('.')[0]
    if _v91_re.search(r'[A-Za-z가-힣]', raw): return ''
    digits=''.join(ch for ch in raw if ch.isdigit())
    return digits.zfill(6) if digits and len(digits)<=6 else ''
