def _build_context_trace_lines(row):
    lines=[]
    acc=_ctx_int(_rc_get(row,'세력흔적점수',_rc_get(row,'force_trace_score',0)),0); at=str(_rc_get(row,'세력흔적태그',_rc_get(row,'force_trace_tag','')) or '').strip(); ac=str(_rc_get(row,'세력흔적코멘트',_rc_get(row,'force_trace_comment','')) or '').strip()
    if acc or at: lines.append(f"🧲 세력흔적: {at or '👀흔적참고'} {acc}점"+(f" | {ac[:80]}" if ac else ''))
    ref=_ctx_int(_rc_get(row,'정제이력점수',_rc_get(row,'recent_refine_score',0)),0); rt=str(_rc_get(row,'정제이력태그',_rc_get(row,'recent_refine_tag','')) or '').strip(); rc=str(_rc_get(row,'정제이력코멘트',_rc_get(row,'recent_refine_comment','')) or '').strip()
    if ref or rt: lines.append(f"🧪 정제이력: {rt or '최근 이력 참고'} {ref}점"+(f" | {rc[:80]}" if rc else ''))
    mat=_ctx_int(_rc_get(row,'재료잔존점수',_rc_get(row,'material_score',0)),0); mt=str(_rc_get(row,'재료잔존태그',_rc_get(row,'material_tag','')) or '').strip(); mc=str(_rc_get(row,'재료잔존코멘트',_rc_get(row,'material_comment','')) or '').strip()
    direct=_ctx_int(_rc_get(row,'재료직접점수',0),0); sup=_ctx_int(_rc_get(row,'재료보조점수',0),0); neg=_ctx_int(_rc_get(row,'재료주의점수',0),0)
    if mat or mt: lines.append(f"📰 재료점수: {mt or '⚪미확인'} {mat}점 | 직접{direct}/보조{sup}/주의-{neg}"+(f" | {mc[:150]}" if mc else ''))
    try:
        late=classify_late_response_type(row)
        if late.get('late_type'): lines.append(f"🛡️ 후행유형: {late['late_type']} | {late['late_action']}")
    except Exception: pass
    try:
        bonus=calc_context_bonus_score({**(row if isinstance(row,dict) else {}),'세력흔적점수':acc,'정제이력점수':ref,'재료잔존점수':mat})
        if bonus: lines.append(f"🧮 맥락보너스: +{bonus} | 오늘 신호 외 최근 흔적을 보정 반영")
    except Exception: pass
    return lines
