def _v92_float(x, default=0.0):
    try:
        if x is None:
            return default
        if isinstance(x, str):
            x = x.replace(',', '').replace('%', '').strip()
            if not x or x.lower() in ('nan', 'none', 'null'):
                return default
        v = float(x)
        if v != v:
            return default
        return v
    except Exception:
        return default


def _v92_int(x, default=0):
    try:
        return int(round(_v92_float(x, default)))
    except Exception:
        return default


def _v92_price(x):
    v = _v92_float(x, 0.0)
    if v <= 0:
        return '0'
    return f"{int(round(v)):,}"


def _v92_row_dict(row):
    try:
        if isinstance(row, dict):
            return dict(row)
        if hasattr(row, 'to_dict'):
            return row.to_dict()
        return dict(row or {})
    except Exception:
        return {}


def _v92_pick(d, *keys, default=None):
    for k in keys:
        try:
            if k in d and d.get(k) is not None and str(d.get(k)).strip() != '':
                return d.get(k)
        except Exception:
            pass
    return default


def _v92_price_cols(df):
    cols = {}
    if df is None:
        return cols
    names = list(getattr(df, 'columns', []))
    def find(*cands):
        for c in cands:
            if c in names:
                return c
        lowmap = {str(c).lower(): c for c in names}
        for c in cands:
            if str(c).lower() in lowmap:
                return lowmap[str(c).lower()]
        return ''
    cols['open'] = find('Open', 'open', '시가')
    cols['high'] = find('High', 'high', '고가')
    cols['low'] = find('Low', 'low', '저가')
    cols['close'] = find('Close', 'close', '종가', '현재가')
    cols['volume'] = find('Volume', 'volume', '거래량')
    return cols


def _v92_series(df, col, default=0.0):
    try:
        import pandas as _pd
        if df is None or col not in df.columns:
            return _pd.Series([], dtype='float64')
        return _pd.to_numeric(df[col].astype(str).str.replace(',', '', regex=False), errors='coerce').fillna(default)
    except Exception:
        try:
            return df[col]
        except Exception:
            return []


def _v92_slope_pct(series, n=5):
    try:
        s = list(series.dropna()) if hasattr(series, 'dropna') else list(series)
        if len(s) < n + 1:
            return 0.0
        a = _v92_float(s[-n-1], 0.0)
        b = _v92_float(s[-1], 0.0)
        if a <= 0:
            return 0.0
        return (b / a - 1.0) * 100.0
    except Exception:
        return 0.0


def _v92_roll_mean(values, n):
    try:
        return values.rolling(n).mean()
    except Exception:
        return []


def _v92_calc_wave_pullback_timing(df, waves=None, position=None):
    """추세전환 후 1파 발생, 2파 눌림, 재출발 가능성을 점수화한다."""
    out = {
        'wave_stage': '데이터부족',
        'wave_score': 0,
        'trend_turn_score': 0,
        'first_wave_score': 0,
        'pullback_health_score': 0,
        'restart_score': 0,
        'best_zone_low': 0.0,
        'best_zone_high': 0.0,
        'invalid_price': 0.0,
        'pivot_high': 0.0,
        'pivot_low': 0.0,
        'pullback_pct': 0.0,
        'wave_comment': '데이터가 부족해 파동 눌림 타점을 계산하지 못했습니다.',
        'wave_action': '관찰',
        'debug': '',
    }
    try:
        if df is None or len(df) < 40:
            return out
        cols = _v92_price_cols(df)
        ccol, hcol, lcol, ocol, vcol = cols.get('close'), cols.get('high'), cols.get('low'), cols.get('open'), cols.get('volume')
        if not ccol or not hcol or not lcol:
            out['debug'] = 'price columns missing'
            return out

        close = _v92_series(df, ccol)
        high = _v92_series(df, hcol)
        low = _v92_series(df, lcol)
        open_ = _v92_series(df, ocol) if ocol else close
        volume = _v92_series(df, vcol) if vcol else close * 0
        n = len(close)
        cur = _v92_float(close.iloc[-1], 0.0)
        if cur <= 0:
            return out

        ma5 = close.rolling(5).mean()
        ma10 = close.rolling(10).mean()
        ma20 = close.rolling(20).mean()
        ma60 = close.rolling(60).mean() if n >= 60 else close.rolling(min(30, n)).mean()
        vol20 = volume.rolling(20).mean() if len(volume) else volume
        recent20_high = _v92_float(high.iloc[-20:].max(), 0.0)
        recent20_low = _v92_float(low.iloc[-20:].min(), 0.0)
        recent60_high = _v92_float(high.iloc[-60:].max(), 0.0) if n >= 60 else _v92_float(high.max(), 0.0)
        recent60_low = _v92_float(low.iloc[-60:].min(), 0.0) if n >= 60 else _v92_float(low.min(), 0.0)
        prev20_high = _v92_float(high.iloc[max(0, n-45):max(1, n-5)].max(), 0.0) if n > 10 else recent20_high

        ma5v, ma10v, ma20v, ma60v = [_v92_float(x.iloc[-1], 0.0) for x in (ma5, ma10, ma20, ma60)]
        ma20_slope = _v92_slope_pct(ma20, 5)
        ma60_slope = _v92_slope_pct(ma60, 10)
        vol_ratio = _v92_float(volume.iloc[-1], 0.0) / max(_v92_float(vol20.iloc[-1], 0.0), 1.0) if len(volume) else 0.0
        day_up = bool(cur >= _v92_float(open_.iloc[-1], cur))

        # 1) 추세전환 점수: 이평 배열, 20선 기울기, 저점 상승, 파란점선 근접/회복
        trend = 0
        if ma5v > ma20v > 0: trend += 7
        if ma10v >= ma20v * 0.995 and ma20v > 0: trend += 4
        if ma20_slope > -0.3: trend += 4
        if ma20_slope > 0.0: trend += 3
        if ma60_slope > -1.5: trend += 3
        if recent20_low >= recent60_low * 1.03 if recent60_low > 0 else False: trend += 2
        blue_line = _v92_float((waves or {}).get('blue_line_price'), 0.0)
        if blue_line > 0:
            gap = (cur / blue_line - 1.0) * 100.0
            if gap >= -2.5: trend += 2
        trend = min(25, trend)

        # 2) 1파 발생 점수: 최근 고점 돌파/거래량/강한 양봉/박스 상단 접근
        first = 0
        if prev20_high > 0 and cur >= prev20_high * 0.985: first += 7
        if recent20_high > 0 and cur >= recent20_high * 0.94: first += 3
        if vol_ratio >= 1.3: first += 5
        if vol_ratio >= 2.0: first += 3
        if day_up: first += 3
        if ma5v > ma10v > 0: first += 3
        if cur > ma20v > 0: first += 4
        first = min(25, first)

        # 1파 기준점 추정: 최근 40~60봉 저점→최근 고점
        look = min(60, n)
        base_low = _v92_float(low.iloc[-look:].min(), 0.0)
        pivot_high = _v92_float(high.iloc[-look:].max(), 0.0)
        # 최근 고점이 너무 오래 전이면 최근 20봉 고점도 보조 사용
        if recent20_high > 0 and (pivot_high <= 0 or recent20_high >= pivot_high * 0.92):
            pivot_high = max(pivot_high, recent20_high)
        wave_range = max(pivot_high - base_low, 0.0)
        retrace = ((pivot_high - cur) / wave_range * 100.0) if wave_range > 0 else 0.0
        fib38 = pivot_high - wave_range * 0.382 if wave_range > 0 else 0.0
        fib62 = pivot_high - wave_range * 0.618 if wave_range > 0 else 0.0
        zone_low = min(fib38, fib62) if fib38 > 0 and fib62 > 0 else 0.0
        zone_high = max(fib38, fib62) if fib38 > 0 and fib62 > 0 else 0.0

        # 3) 눌림 건강도: 거래량 감소, 38~62 되돌림, 20선/파란점선/돌파선 보존, 장대음봉 회피
        pull = 0
        # 1파 이후 되돌림이 8~62%면 눌림 후보. 너무 얕으면 접촉/안착, 너무 깊으면 실패위험
        if 8.0 <= retrace <= 62.0: pull += 6
        if 18.0 <= retrace <= 55.0: pull += 5
        # 거래량이 줄거나 과도하지 않으면 건강한 눌림
        if vol_ratio <= 1.15: pull += 4
        if cur >= ma20v * 0.985 if ma20v > 0 else False: pull += 4
        if blue_line > 0 and cur >= blue_line * 0.97: pull += 4
        if recent20_low > 0 and cur >= recent20_low * 1.03: pull += 2
        # 최근 3봉 중 큰 음봉이 연속이면 감점
        try:
            reds = 0
            big_red = 0
            for i in range(max(0, n-3), n):
                if _v92_float(close.iloc[i], 0) < _v92_float(open_.iloc[i], 0):
                    reds += 1
                    if _v92_float(open_.iloc[i], 0) > 0 and (_v92_float(close.iloc[i], 0) / _v92_float(open_.iloc[i], 0) - 1.0) * 100.0 <= -4.0:
                        big_red += 1
            if reds <= 1: pull += 2
            if big_red >= 1: pull -= 4
        except Exception:
            pass
        pull = max(0, min(25, pull))

        # 4) 재출발 신호: 양봉/5일선 재회복/전일고가 회복/거래량 재유입/파란점선 위
        restart = 0
        prev_high = _v92_float(high.iloc[-2], 0.0) if n >= 2 else 0.0
        prev_close = _v92_float(close.iloc[-2], 0.0) if n >= 2 else 0.0
        if day_up: restart += 5
        if ma5v > 0 and cur >= ma5v: restart += 5
        if prev_high > 0 and cur >= prev_high * 0.997: restart += 5
        if vol_ratio >= 1.1: restart += 4
        if blue_line > 0 and cur >= blue_line * 0.995: restart += 4
        if cur >= prev_close: restart += 2
        restart = min(25, restart)

        total = trend + first + pull + restart
        invalid = 0.0
        candidates = [x for x in [base_low, recent20_low, ma20v * 0.97 if ma20v > 0 else 0, blue_line * 0.97 if blue_line > 0 else 0] if x and x > 0]
        if candidates:
            invalid = max(min(candidates), recent20_low * 0.985 if recent20_low > 0 else 0)

        if total >= 82 and pull >= 17 and restart >= 15:
            stage, action = '눌림타점형', '실행 후보'
            comment = '추세 전환 뒤 1파가 확인되고, 건강한 2파 눌림 후 재출발 신호가 붙은 구간입니다.'
        elif total >= 72 and pull >= 15:
            stage, action = '눌림대기형', '눌림 확인'
            comment = '새 파동 이후 눌림 구간입니다. 파란점선·20일선·돌파선 지지와 양봉 재출발을 확인합니다.'
        elif trend >= 17 and first >= 17:
            stage, action = '1파발생형', '추격보다 눌림 대기'
            comment = '추세 전환과 1파 발생은 보이지만, 지금은 바로 추격보다 첫 눌림을 기다리는 구간입니다.'
        elif trend >= 16:
            stage, action = '추세전환형', '관찰 강화'
            comment = '하락/횡보 흐름에서 방향 전환 조짐이 있습니다. 거래량과 5일선 재안착을 더 확인합니다.'
        elif total <= 40:
            stage, action = '관찰부족형', '보수 관찰'
            comment = '아직 새 상승파동이나 건강한 눌림이 충분히 확인되지 않았습니다.'
        else:
            stage, action = '바닥응축형', '소액 관찰'
            comment = '응축은 있으나 1파·눌림·재출발 중 일부 확인이 부족합니다.'

        out.update({
            'wave_stage': stage,
            'wave_score': int(total),
            'trend_turn_score': int(trend),
            'first_wave_score': int(first),
            'pullback_health_score': int(pull),
            'restart_score': int(restart),
            'best_zone_low': round(zone_low, 2),
            'best_zone_high': round(zone_high, 2),
            'invalid_price': round(invalid, 2),
            'pivot_high': round(pivot_high, 2),
            'pivot_low': round(base_low, 2),
            'pullback_pct': round(retrace, 1),
            'wave_comment': comment,
            'wave_action': action,
            'debug': f"ma20_slope={ma20_slope:.2f}, ma60_slope={ma60_slope:.2f}, vol_ratio={vol_ratio:.2f}, retrace={retrace:.1f}, blue={blue_line:.0f}",
        })
        return out
    except Exception as e:
        out['debug'] = f'wave timing error: {e}'
        return out


try:
    _V92_BASE_BUILD_ACCUMULATION_PACKAGE = build_accumulation_package
except Exception:
    _V92_BASE_BUILD_ACCUMULATION_PACKAGE = None


def build_accumulation_package(df):
    try:
        pkg = _V92_BASE_BUILD_ACCUMULATION_PACKAGE(df) if _V92_BASE_BUILD_ACCUMULATION_PACKAGE else {}
        if not isinstance(pkg, dict):
            pkg = {}
        waves = pkg.get('waves', {}) or {}
        pos = pkg.get('position', {}) or {}
        pkg['wave_timing'] = _v92_calc_wave_pullback_timing(df, waves, pos)
        return pkg
    except Exception as e:
        return {
            'accum': {'found': False, 'score': 0, 'grade': '없음', 'label': '매집봉 없음', 'desc': f'v92 package error: {e}'},
            'waves': {}, 'position': {},
            'wave_timing': {'wave_stage': '계산실패', 'wave_score': 0, 'wave_comment': str(e), 'wave_action': '관찰'},
        }


try:
    _V92_BASE_ACCUM_LINES = _build_accumulation_overlay_lines
except Exception:
    _V92_BASE_ACCUM_LINES = None


def _v92_wave_timing_lines_from_pkg(pkg):
    wt = (pkg or {}).get('wave_timing', {}) or {}
    if not wt:
        return []
    stage = str(wt.get('wave_stage', '') or '').strip()
    score = _v92_int(wt.get('wave_score', 0), 0)
    action = str(wt.get('wave_action', '') or '').strip()
    comment = str(wt.get('wave_comment', '') or '').strip()
    zone_low = _v92_float(wt.get('best_zone_low', 0), 0)
    zone_high = _v92_float(wt.get('best_zone_high', 0), 0)
    invalid = _v92_float(wt.get('invalid_price', 0), 0)
    retrace = _v92_float(wt.get('pullback_pct', 0), 0)
    lines = []
    if stage:
        lines.append(f"🌊 파동타점: {stage} | 점수 {score}/100 | {action}")
        lines.append(
            "🧮 파동점수: "
            f"전환{_v92_int(wt.get('trend_turn_score',0))}/25 "
            f"1파{_v92_int(wt.get('first_wave_score',0))}/25 "
            f"눌림{_v92_int(wt.get('pullback_health_score',0))}/25 "
            f"재출발{_v92_int(wt.get('restart_score',0))}/25"
        )
    if zone_low > 0 and zone_high > 0:
        lines.append(f"🎯 최적눌림: {_v92_price(zone_low)}~{_v92_price(zone_high)} | 되돌림 {retrace:.1f}% | 무효화 {_v92_price(invalid)}")
    elif invalid > 0:
        lines.append(f"🎯 최적눌림: 파란점선/20일선 지지 확인 | 무효화 {_v92_price(invalid)}")
    if comment:
        lines.append(f"🧭 파동해석2: {comment}")
    return lines


def _build_accumulation_overlay_lines(pkg):
    try:
        base = _V92_BASE_ACCUM_LINES(pkg) if _V92_BASE_ACCUM_LINES else []
        if base is None:
            base = []
        if not isinstance(base, list):
            base = list(base)
    except Exception:
        base = []
    extra = _v92_wave_timing_lines_from_pkg(pkg)
    # 파란점선 뒤 또는 파동해석 뒤에 붙이면 읽기 쉽다.
    if not extra:
        return base
    joined = '\n'.join(base)
    if '🌊 파동타점:' in joined:
        return base
    out = []
    inserted = False
    for line in base:
        out.append(line)
        if (not inserted) and (str(line).startswith('🧭 파동해석') or str(line).startswith('🔵 파란점선')):
            out.extend(extra)
            inserted = True
    if not inserted:
        out.extend(extra)
    return out


