try:
    _V92_BASE_MATERIAL_SCORE = calc_material_survival_score
except Exception:
    _V92_BASE_MATERIAL_SCORE = None


def _v92_text_blob(item):
    d = _v92_row_dict(item)
    vals = []
    for k in ('뉴스', 'news', '뉴스제목', 'AI재료분류', '재료잔존코멘트', 'material_comment', '종목명', '테마', 'N구분', '태그', 'tags', '공시'):
        v = d.get(k)
        if v is not None:
            vals.append(str(v))
    return ' '.join(vals).lower()


def calc_material_survival_score(item) -> dict:
    d = _v92_row_dict(item)
    text = _v92_text_blob(d)
    try:
        base = _V92_BASE_MATERIAL_SCORE(d) if _V92_BASE_MATERIAL_SCORE else {}
        if not isinstance(base, dict):
            base = {}
    except Exception:
        base = {}

    # 신규성: 오늘/공시/신규/계약 등 새 정보 여부
    novelty_kw = ['오늘', '금일', '공시', '신규', '최초', '단독', '수주', '계약', '공급', '승인', '허가', '증설', '출시', '상장', 'mou']
    strength_kw = ['상한가', '급등', '수주', '계약', '공급', '흑자전환', '최대', '실적', '영업익', '매출', '정책', '정부', 'ai', '로봇', '반도체', '원전', '방산']
    sustain_kw = ['장기', '중장기', '정책', '수혜', '공급망', '증설', '투자', '수주잔고', '실적개선', '성장', '계속', '확대']
    spread_kw = ['섹터', '테마', '업종', '동반', '관련주', '대장주', '전반', '수혜주', '밸류체인']
    bad_kw = ['상장폐지', '관리종목', '거래정지', '감사의견', '적자', '소송', '압수수색', '횡령', '배임', '불성실', '감자', '유상증자', '전환사채']

    def count_score(words, unit=4, cap=20):
        return min(cap, sum(unit for w in words if w.lower() in text))

    novelty = count_score(novelty_kw, 4, 20)
    strength = count_score(strength_kw, 3, 20)
    sustain = count_score(sustain_kw, 4, 20)
    spread = count_score(spread_kw, 5, 20)

    # 수급결합: 거래량/외인/기관/쌍끌/OBV/매집과 결합될수록 가산
    flow = 0
    blob_orig = ' '.join(str(d.get(k, '')) for k in d.keys()).lower()
    for w, pts in [('쌍끌', 6), ('기관', 4), ('외인', 4), ('거래량', 4), ('obv', 3), ('매집', 4), ('수급', 3)]:
        if w.lower() in blob_orig:
            flow += pts
    try:
        vr = _v92_float(d.get('거래량배수') or d.get('vol_ratio') or d.get('Volume_Ratio') or 0, 0)
        if vr >= 2.0: flow += 6
        elif vr >= 1.3: flow += 3
    except Exception:
        pass
    flow = min(20, flow)

    negative = min(30, sum(6 for w in bad_kw if w.lower() in text))
    raw = novelty + strength + sustain + spread + flow - negative
    # 기존 점수가 있으면 완전히 버리지 않고 30% 반영
    old = _v92_int(base.get('material_score', base.get('재료점수', 0)), 0)
    score = int(max(0, min(100, round(raw * 0.7 + old * 0.3)))) if old else int(max(0, min(100, raw)))

    if negative >= 18:
        tag = '🚫재료위험'
        comment = '상장폐지/관리/소송/재무위험성 키워드가 있어 재료보다 리스크를 우선 확인해야 합니다.'
    elif score >= 80:
        tag = '🧨강재료'
        comment = '신규성·강도·지속성·수급결합이 함께 붙은 강한 재료입니다.'
    elif score >= 60:
        tag = '🔥중상재료'
        comment = '재료성은 유효하지만 지속성 또는 확산성 확인이 필요합니다.'
    elif score >= 35:
        tag = '⚪약재료'
        comment = '단기 재료성은 있으나 강한 후속성은 아직 약합니다.'
    else:
        tag = '⚠️재료소멸주의'
        comment = '재료가 약하거나 이미 가격에 반영됐을 가능성이 있습니다.'

    reasons = []
    for label, val in [('신규성', novelty), ('강도', strength), ('지속성', sustain), ('확산성', spread), ('수급결합', flow)]:
        if val >= 12:
            reasons.append(label)
    if negative:
        reasons.append(f'주의{negative}')
    reason_txt = '/'.join(reasons) if reasons else '뚜렷한 강재료 키워드 부족'
    detail = f"신규성{novelty}/20, 강도{strength}/20, 지속성{sustain}/20, 확산성{spread}/20, 수급결합{flow}/20, 주의-{negative} | {reason_txt}"

    out = dict(base)
    out.update({
        'material_score': score,
        'material_tag': tag,
        'material_comment': comment + ' | ' + detail,
        'material_positive_score': novelty + strength,
        'material_support_score': sustain + spread + flow,
        'material_negative_score': negative,
        'material_newness_score': novelty,
        'material_strength_score': strength,
        'material_sustain_score': sustain,
        'material_spread_score': spread,
        'material_flow_score': flow,
        'material_detail': detail,
    })
    return out


