def _v92_pick_wave_pullback_rows(frames, limit=3):
    picked = []
    used = set()
    try:
        import pandas as _pd
    except Exception:
        _pd = None
    for fr in frames:
        try:
            if fr is None:
                continue
            if hasattr(fr, 'iterrows'):
                rows = [r.to_dict() for _, r in fr.iterrows()]
            elif isinstance(fr, list):
                rows = [_v92_row_dict(x) for x in fr]
            else:
                rows = []
            rows = sorted(rows, key=lambda r: _v92_int(_v92_pick(r, '파동타점점수', 'wave_score', default=0)), reverse=True)
            for r in rows:
                code = str(_v92_pick(r, 'code', '종목코드', default='') or '')
                if code in used:
                    continue
                stage = str(_v92_pick(r, '파동타점상태', 'wave_stage', default='') or '')
                score = _v92_int(_v92_pick(r, '파동타점점수', 'wave_score', default=0))
                if score >= 70 or stage in ('눌림타점형', '눌림대기형'):
                    used.add(code)
                    picked.append(r)
                    if len(picked) >= limit:
                        return picked
        except Exception:
            continue
    return picked


def _v92_format_wave_bucket(rows):
    if not rows:
        return '- 해당 종목 없음'
    lines = []
    for i, r in enumerate(rows, 1):
        name = str(_v92_pick(r, '종목명', 'name', 'Name', default='') or '').strip()
        code = str(_v92_pick(r, 'code', '종목코드', 'Code', default='') or '').strip()
        stage = str(_v92_pick(r, '파동타점상태', 'wave_stage', default='') or '').strip()
        score = _v92_int(_v92_pick(r, '파동타점점수', 'wave_score', default=0), 0)
        low = _v92_float(_v92_pick(r, '파동최적하단', 'best_zone_low', default=0), 0)
        high = _v92_float(_v92_pick(r, '파동최적상단', 'best_zone_high', default=0), 0)
        invalid = _v92_float(_v92_pick(r, '파동무효화', 'invalid_price', default=0), 0)
        blue = str(_v92_pick(r, '파란점선상태', 'blue_line_state', default='') or '').strip()
        zone = f" / 최적:{_v92_price(low)}~{_v92_price(high)}" if low > 0 and high > 0 else ''
        inv = f" / 무효:{_v92_price(invalid)}" if invalid > 0 else ''
        lines.append(f"{i}) {name}({code}) - {stage} {score}/100 / 파란점선:{blue}{zone}{inv}")
    return '\n'.join(lines)


def build_trade_action_summary_block_from_frames(*args, **kwargs):
    try:
        base = _V92_BASE_TODAY_ACTION_BLOCK(*args, **kwargs) if _V92_BASE_TODAY_ACTION_BLOCK else ''
    except Exception as e:
        base = f"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n🎯 [오늘 매매관점 압축]\n- 생성 실패: {e}\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"
    try:
        frames = []
        for k in ('telegram_targets','wm_blue_top5','wm_red_top5','dante_pick_df','dante_watch_df','breakout_pick_df','breakout_watch_df','wm_pullback_top5'):
            if k in kwargs:
                frames.append(kwargs.get(k))
        rows = _v92_pick_wave_pullback_rows(frames, limit=3)
        insert = "\n🌊 파동 눌림타점 우선후보\n" + _v92_format_wave_bucket(rows) + "\n"
        if '🌊 파동 눌림타점 우선후보' not in base:
            if '🔥 조건부 실행 후보' in base:
                base = base.replace('🔥 조건부 실행 후보', insert + '\n🔥 조건부 실행 후보', 1)
            elif '🔥 재점화 우선관찰 후보' in base:
                base = base.replace('🔥 재점화 우선관찰 후보', insert + '\n🔥 재점화 우선관찰 후보', 1)
            else:
                base = base.rstrip() + '\n' + insert
        if '파동눌림/파란점선 기준' not in base:
            guide = (
                "\n📘 파동눌림/파란점선 기준\n"
                "- 1파발생형: 추격보다 첫 눌림 대기\n"
                "- 눌림대기형: 거래량 감소·파란점선/20일선 지지 확인\n"
                "- 눌림타점형: 재출발 양봉·거래량 재유입 시 실행 우선\n"
                "- 파란점선 이탈 또는 무효화 가격 이탈 시 관점 약화"
            )
            base = base.rstrip().replace('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━', guide + '\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━', 1) if base.count('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━') >= 2 else base.rstrip() + guide
    except Exception:
        pass
    return base

