    all_hits_df_for_pre = annotate_time_symmetry_df(all_hits_df_for_pre)
    # ✅ CONTEXT_TRACE_PATCH: 전체 수박/선취/돌파 블록에도 재료잔존·맥락보너스 반영
    all_hits_df_for_pre = apply_material_survival_to_df(all_hits_df_for_pre)

