def _env_flag(name: str, default: bool = False) -> bool:
    raw = str(os.environ.get(name, str(default))).strip().lower()
    return raw in ('1', 'true', 't', 'yes', 'y', 'on')


def _env_str(name: str, default: str = '') -> str:
    return str(os.environ.get(name, default)).strip()


def _normalize_test_profile(raw: str) -> str:
    profile = str(raw or '').strip().upper()
    alias = {
        'REAL': 'REAL_FULL',
        'REAL_FULL': 'REAL_FULL',
        'LIVE': 'REAL_FULL',
        'PROD': 'REAL_FULL',
        'PRODUCTION': 'REAL_FULL',
        'TEST': 'TEST_FULL',
        'TEST_FULL': 'TEST_FULL',
        'FULL': 'TEST_FULL',
        'TEST_FAST': 'TEST_FAST',
        'FAST': 'TEST_FAST',
        'QUICK': 'TEST_FAST',
    }
    return alias.get(profile, '')


def _parse_chat_ids(raw: str):
    return [x.strip() for x in str(raw or '').split(',') if x.strip()]


def get_target_chat_ids():
    real_ids = _parse_chat_ids(TELEGRAM_REAL_CHAT_ID)
    test_ids = _parse_chat_ids(TELEGRAM_TEST_CHAT_ID)
    override_ids = _parse_chat_ids(TELEGRAM_CHAT_ID_EFFECTIVE or TEST_CHAT_ID_OVERRIDE)

    if TEST_MODE:
        if override_ids:
            return override_ids, 'test_override'
        if test_ids:
            return test_ids, 'test'
        return [], 'test_missing'

    return real_ids, 'real'


