def _extract_gemini_text(gem_data: dict) -> str:
    """
    Gemini 응답에서 candidates/parts 전체를 합쳐 텍스트 추출.
    parts[0]만 읽어서 잘리는 문제를 방지한다.
    """
    try:
        candidates = gem_data.get("candidates", []) or []
        if not candidates:
            return ""

        chunks = []
        for idx, cand in enumerate(candidates):
            content = cand.get("content", {}) or {}
            parts = content.get("parts", []) or []

            texts = []
            for p in parts:
                t = p.get("text", "")
                if t:
                    texts.append(t)

            text = "\n".join(texts).strip()
            if text:
                if idx == 0 or text not in chunks:
                    chunks.append(text)

        return "\n\n".join(chunks).strip()
    except Exception as e:
        log_error(f"⚠️ _extract_gemini_text 실패: {e}")
        return ""

def _safe_int_ai(x, default=0):
    try:
        return int(float(x))
    except:
        return default

def _safe_float_ai(x, default=0.0):
    try:
        return float(x)
    except:
        return default

def classify_entry_phase(row) -> str:
    """
    종목이 초입/중간/후행/눌림 중 어디에 있는지 간단 분류
    """
    disparity = _safe_float_ai(row.get('이격', row.get('Disparity', 100)), 100.0)
    rsi = _safe_float_ai(row.get('RSI', 50), 50.0)
    bb40 = _safe_float_ai(row.get('BB40', row.get('BB40폭', 99)), 99.0)
    close_p = _safe_float_ai(row.get('현재가', row.get('Close', 0)), 0)
    target = _safe_float_ai(row.get('🎯목표타점', 0), 0)

    if disparity <= 98:
        return "눌림초입"
    if 98 < disparity <= 106 and rsi <= 62 and bb40 <= 15:
        return "초입"
    if 106 < disparity <= 112 and rsi <= 70:
        return "중간"
    if disparity > 112 or rsi >= 72:
        return "후행"
    if target > 0 and close_p > 0 and (target - close_p) / close_p < 0.03:
        return "후행"
    return "중간"

def build_judgment_packet(row) -> dict:
    """
    AI에게 숫자 원본 대신 판단용 압축 패킷 제공
    """
    name = str(row.get('종목명', ''))
    code = str(row.get('code', ''))
    combo = str(row.get('N조합', ''))
    grade = str(row.get('N등급', ''))
    tags = str(row.get('N구분', ''))
    story = str(row.get('📜서사히스토리', ''))
    supply = str(row.get('수급', ''))
    finance = str(row.get('재무', ''))
    news = str(row.get('news_sentiment', '')).strip()

    close_p = _safe_int_ai(row.get('현재가', 0))
    target1 = _safe_int_ai(row.get('🎯목표타점', 0))
    target2 = _safe_int_ai(row.get('🎯목표2차', 0))
    stop = _safe_int_ai(row.get('🚨손절가', 0))
    disparity = _safe_float_ai(row.get('이격', 100), 100)
    rsi = _safe_float_ai(row.get('RSI', 50), 50)
    bb40 = _safe_float_ai(row.get('BB40', row.get('BB40폭', 99)), 99)
    ma_conv = _safe_float_ai(row.get('MA수렴', 99), 99)
    obv_slope = _safe_float_ai(row.get('OBV기울기', 0), 0)
    rr = _safe_float_ai(row.get('RR비율', 0), 0)

    ultra = bool(row.get('초단기MA수렴', False))
    short = bool(row.get('단기MA수렴', False))
    struct = bool(row.get('구조MA수렴', False))
    super_ma = bool(row.get('초강력MA수렴', False))

    supply_turn = bool(row.get('수급전환', False))
    wm_prepare = bool(row.get('수박준비형', False))
    wm_launch = bool(row.get('수박발사형', False))
    dolbanzi = bool(row.get('돌반지', False))
    viper = bool(row.get('독사훅', False))
    golpagi = bool(row.get('골파기', False))
    jongbe = bool(row.get('종베', False))
    surge = bool(row.get('급등초동', False))
    force_pullback = bool(row.get('세력눌림', False))
    obv_acc = bool(row.get('OBV매집돌파', False))
    good_conv = bool(row.get('좋은수렴', False))
    explosion_ready = bool(row.get('폭발직전', False))
    stage = str(row.get('단계상태', 'DROP'))

    strengths = []
    risks = []

    if wm_launch:
        strengths.append("발사형 수급 전환이 확인돼서 당일 탄력이 붙을 가능성이 큼")
    elif wm_prepare:
        strengths.append("수박 준비형이라 응축 상태는 좋은데 아직 발사 전일 수 있음")
    elif supply_turn:
        strengths.append("수급 전환은 잡혀서 수급 측면 선행 신호는 있음")

    if super_ma:
        strengths.append("초강력 MA 수렴이라 자리 자체의 질이 높음")
    elif struct:
        strengths.append("구조 MA 수렴이라 중기 바닥 정리 가능성이 있음")
    elif ultra or short:
        strengths.append("단기 MA 수렴으로 초입 타점 성격이 있음")

    if dolbanzi:
        strengths.append("돌반지 계열이라 대시세 초입 가능성을 열어둘 수 있음")
    if viper:
        strengths.append("독사 계열이라 단기 전환 각도가 살아있음")
    if force_pullback:
        strengths.append("세력 눌림목 성격이라 눌림 재진입 관점이 가능함")
    if obv_acc:
        strengths.append("OBV 매집 돌파라 가격보다 수급이 먼저 움직였을 가능성이 있음")
    if surge:
        strengths.append("급등 초동형이라 재료성 탄력이 강할 수 있음")

    if disparity > 112:
        risks.append("이격이 커서 지금 진입은 추격 매수 위험이 있음")
    elif disparity < 97:
        risks.append("아직 완전히 방향이 확인된 자리는 아닐 수 있음")

    if rsi >= 72:
        risks.append("RSI가 높아 단기 과열 조정이 바로 나올 수 있음")
    elif rsi <= 38:
        risks.append("약한 구간에서 반등 시도일 수도 있어 확정 신호가 더 필요함")

    if bb40 >= 20:
        risks.append("BB40 폭이 넓어서 응축형보다는 이미 한 번 진행된 자리일 수 있음")
    elif bb40 <= 6:
        strengths.append("BB40 폭이 매우 좁아 한 번 방향이 나오면 크게 움직일 수 있음")

    if ma_conv >= 7:
        risks.append("MA 수렴이 약해서 예쁜 응축형이라고 보기엔 부족함")

    if obv_slope < 0:
        risks.append("OBV 기울기가 음수라 수급 누적 관점은 약함")

    if stage == 'DROP':
        risks.append("단계 시퀀스를 통과하지 못해서 구조적 신뢰도는 낮음")
    elif stage == 'PASS_B':
        strengths.append("재응축 후 재파동 성격이라 탄력 재개 가능성이 있음")
    elif stage == 'PASS_A':
        strengths.append("단계 시퀀스를 예쁘게 통과해 구조 신뢰도가 높은 편임")

    phase = classify_entry_phase(row)

    if phase == "초입":
        entry_style = "돌파 추격보다 시가 초반 과열 확인 후 1차 눌림이 더 유리"
    elif phase == "눌림초입":
        entry_style = "급하게 따라붙기보다 지지 확인 후 분할 진입이 유리"
    elif phase == "중간":
        entry_style = "지금은 애매한 중간 구간이라 재돌파 확인 또는 눌림 재확인이 필요"
    else:
        entry_style = "후행 구간일 가능성이 있어 신규 진입보다 보유자 대응이 더 중요"

    invalidation = []
    if stop > 0:
        invalidation.append(f"{stop:,}원 이탈")
    if _safe_float_ai(row.get('OBV기울기', 0), 0) < 0:
        invalidation.append("수급 회복 실패")
    if bb40 > 20:
        invalidation.append("장중 반등 후 거래량 감소")
    if not invalidation:
        invalidation.append("당일 돌파 실패 후 종가 약세 마감")

    return {
        "name": name,
        "code": code,
        "grade": grade,
        "combo": combo,
        "tags": tags,
        "story": story,
        "supply": supply,
        "finance": finance,
        "news": news,
        "close": close_p,
        "target1": target1,
        "target2": target2,
        "stop": stop,
        "rr": rr,
        "phase": phase,
        "entry_style": entry_style,
        "strengths": strengths[:4],
        "risks": risks[:4],
        "invalidation": invalidation[:2],
        "metrics": {
            "disparity": round(disparity, 1),
            "rsi": round(rsi, 1),
            "bb40": round(bb40, 1),
            "ma_conv": round(ma_conv, 1),
            "obv_slope": round(obv_slope, 1),
        }
    }

def get_hot_themes():
    try:
        res = requests.get("https://finance.naver.com/sise/theme.naver", headers=REAL_HEADERS)
        soup = BeautifulSoup(res.text, 'html.parser')
        themes = [t.text.strip() for t in soup.select('table.type_1 td.col_type1')[:3]]
        return ", ".join(themes)
    except: return "테마수집불가"

def get_market_briefing(issues):
    try:
        theme_info = get_hot_themes()
        comments = "특이사항 없음"
        if issues:
            comments = " | ".join([i["comment"] for i in issues])
        
        system_prompt, user_prompt = get_market_briefing_prompt(
        comments, theme_info, m_ndx, m_sp5, m_vix, m_fx
    )
        client = OpenAI(api_key=OPENAI_API_KEY)
        res = client.chat.completions.create(
        model="gpt-4o-mini",
        messages=[
            {"role": "system", "content": system_prompt},
            {"role": "user",   "content": user_prompt}
        ]
        )
        return f"🌇 [시황 브리핑]\n{res.choices[0].message.content.strip()}"
    except Exception as e: 
        return f"브리핑 생성 실패: {str(e)}"


def _gemini_sections_complete(text: str) -> bool:
    if not text or len(text.strip()) < 80:
        return False
    required = [
        "🏆 [단타 1위]",
        "🎯 [스윙 1위]",
        "⚠️ [주의 종목]",
        "💬 [오늘 장 한마디]",
    ]
    return all(x in text for x in required)

def run_ai_tournament(candidate_list, issues):
    if candidate_list.empty:
        return "종목 후보가 없어 토너먼트를 취소합니다."

    candidate_list = candidate_list.sort_values(by='안전점수', ascending=False).head(15)
    gemini_candidates = candidate_list.head(6).copy()

    def safe_int(x, default=0):
        try:
            return int(float(x))
        except:
            return default

    def safe_float(x, default=0.0):
        try:
            return float(x)
        except:
            return default

    comments = "특이 이슈 없음"
    if issues:
        comments = " | ".join([i.get("comment", "") for i in issues])

    prompt_data = "\n".join([
        f"- {row['종목명']}({row['code']}): "
        f"구분:{row.get('구분','N/A')}, 단계:{row.get('단계상태','')}, "
        f"등급:{row.get('N등급','')}, 조합:{row.get('N조합','')}, "
        f"수급:{row.get('수급',0)}, 재무:{row.get('재무','')}, N구분:{row.get('N구분','N/A')}, "
        f"이격:{safe_int(row.get('이격',0))}, 현재가:{safe_int(row.get('현재가',0))}, "
        f"거래대금:{safe_int(row.get('거래대금',0))}, 안전점수:{safe_int(row.get('안전점수',0))}, N점수:{safe_int(row.get('N점수',0))}, "
        f"BB40:{safe_float(row.get('BB40',0)):.1f}, "
        f"초단기MA:{safe_float(row.get('초단기MA수렴도',0)):.1f}, "
        f"단기MA:{safe_float(row.get('단기MA수렴도',0)):.1f}, "
        f"구조MA:{safe_float(row.get('구조MA수렴도',0)):.1f}, "
        f"초강력MA:{'Y' if row.get('초강력MA수렴', False) else 'N'}, "
        f"OBV기울기:{safe_int(row.get('OBV기울기',0))}, RSI:{safe_int(safe_float(row.get('RSI',0)))}, "
        f"예비돌반지:{'Y' if row.get('예비돌반지', False) else 'N'}, "
        f"신규Lite:{'Y' if row.get('신규예비돌반지Lite', False) else 'N'}, "
        f"HTS정확:{'Y' if row.get('예비돌반지HTS정확복제', False) else 'N'}"
        for _, row in candidate_list.iterrows()
    ])

    system_prompt, user_prompt = get_tournament_prompt(prompt_data, comments)

    gemini_prompt_data = "\n".join([
        f"- {row['종목명']}({row['code']}): 단계:{row.get('단계상태','')}, 조합:{row.get('N조합','N/A')}, "
        f"수급:{row.get('수급',0)}, 재무:{row.get('재무','')}, 이격:{safe_int(row.get('이격',0))}, "
        f"현재가:{safe_int(row.get('현재가',0))}, BB40:{safe_float(row.get('BB40',0)):.1f}, "
        f"안전점수:{safe_int(row.get('안전점수',0))}, N점수:{safe_int(row.get('N점수',0))}, "
        f"RSI:{safe_int(safe_float(row.get('RSI',0)))}, OBV기울기:{safe_int(row.get('OBV기울기',0))}"
        for _, row in gemini_candidates.iterrows()
    ])
    gemini_system_prompt, gemini_user_prompt = get_tournament_prompt(gemini_prompt_data, comments)
    gemini_user_prompt += "\n\n[Gemini 전용 강제 지시]\n- 응답 첫 줄은 반드시 '🏆 [단타 1위]'로 시작해.\n- 서론, 심사관 소개, 검토 과정 설명, 머리말을 절대 쓰지 마.\n- 4개 섹션을 반드시 모두 채워.\n- 각 섹션은 너무 짧지 않게 8~12줄 리포트형으로 작성해.\n- 선정 이유는 패턴 낭독이 아니라 차트 구조, 자리의 의미, 수급, 시황, 리스크를 실제 판단처럼 설명해.\n- 답변이 중간에 끊기지 않도록 군더더기 없이 바로 결과만 써."


    # ── GPT 호출 (실패해도 계속)
    gpt_text = ''
    if OPENAI_API_KEY:
        try:
            client = OpenAI(api_key=OPENAI_API_KEY)
            res_gpt = client.chat.completions.create(
                model="gpt-4o-mini",
                messages=[
                    {"role": "system", "content": system_prompt},
                    {"role": "user",   "content": user_prompt}
                ],
                timeout=60
            )
            gpt_text = res_gpt.choices[0].message.content or ''
            log_info("✅ GPT 토너먼트 완료")
        except Exception as e:
            gpt_text = ''
            log_error(f"⚠️ GPT 토너먼트 실패: {e}")
    else:
        log_info("⚠️ OPENAI_API_KEY 없음 — GPT 생략")

    # ── Claude 호출 (실패해도 계속)
    claude_text = ''
    if ANTHROPIC_API_KEY:
        try:
            res_claude = requests.post(
                'https://api.anthropic.com/v1/messages',
                headers={
                    'Content-Type':      'application/json',
                    'x-api-key':         ANTHROPIC_API_KEY,
                    'anthropic-version': '2023-06-01',
                },
                json={
                    'model':      'claude-sonnet-4-20250514',
                    'max_tokens': 1000,
                    'system':     system_prompt,
                    'messages':   [{'role': 'user', 'content': user_prompt}],
                },
                timeout=60
            )
            data = res_claude.json()
            if 'content' in data and data['content']:
                claude_text = data['content'][0].get('text', '').strip()
                log_info("✅ Claude 토너먼트 완료")
            else:
                log_error(f"⚠️ Claude 응답 오류: {data.get('error', data)}")
        except Exception as e:
            log_error(f"⚠️ Claude 토너먼트 실패: {e}")
    else:
        log_info("⚠️ Claude 비활성화 또는 ANTHROPIC_API_KEY 없음 — Claude 생략")

    # ── Gemini 호출 (실패해도 계속)
    gemini_text = ''
    if GEMINI_API_KEY:
        try:
            gem_url = (
                f"https://generativelanguage.googleapis.com/v1beta/models"
                f"/gemini-2.5-flash:generateContent?key={GEMINI_API_KEY}"
            )

            gem_body = {
                "system_instruction": {
                    "parts": [{"text": gemini_system_prompt}]
                },
                "contents": [{
                    "parts": [{"text": gemini_user_prompt}]
                }],
                "generationConfig": {
                    "maxOutputTokens": 8192,
                    "temperature": 0.4,
                    "candidateCount": 1
                }
            }

            res_gem = requests.post(gem_url, json=gem_body, timeout=90)

            if res_gem.status_code == 200:
                gem_data = res_gem.json()
                gemini_text = _extract_gemini_text(gem_data)

                cand = gem_data.get('candidates', [{}])[0]
                finish_reason = cand.get('finishReason', '')
                usage = gem_data.get('usageMetadata', {})
                log_info(f"✅ Gemini 토너먼트 완료 | finishReason={finish_reason} | usage={usage}")

                if finish_reason == 'MAX_TOKENS':
                    log_error("⚠️ Gemini 출력이 MAX_TOKENS로 잘렸을 가능성 있음")

                if (finish_reason == 'MAX_TOKENS') or (not _gemini_sections_complete(gemini_text)):
                    log_error("⚠️ Gemini 응답이 불완전하여 재시도합니다")
                    retry_candidates = candidate_list.head(4).copy()
                    gemini_prompt_data2 = "\n".join([
                        f"- {row['종목명']}({row['code']}): 조합:{row.get('N조합','N/A')}, 수급:{row.get('수급',0)}, 이격:{safe_int(row.get('이격',0))}, 현재가:{safe_int(row.get('현재가',0))}, BB40:{safe_float(row.get('BB40',0)):.1f}, RSI:{safe_int(safe_float(row.get('RSI',0)))}"
                        for _, row in retry_candidates.iterrows()
                    ])
                    gemini_system_prompt2, gemini_user_prompt2 = get_tournament_prompt(gemini_prompt_data2, comments)
                    gemini_user_prompt2 += "\n\n[Gemini 재시도 지시]\n- 이번에는 절대 서론 없이 바로 4개 섹션만 완성해.\n- 응답 첫 줄은 반드시 '🏆 [단타 1위]'로 시작해.\n- 단타/스윙/주의/오늘 장 한마디 4개를 모두 채워.\n- 각 섹션은 4~6줄로 충분히 설명하되 중간에 끊기지 마."

                    gem_body2 = {
                        "system_instruction": {
                            "parts": [{"text": gemini_system_prompt2}]
                        },
                        "contents": [{
                            "parts": [{"text": gemini_user_prompt2}]
                        }],
                        "generationConfig": {
                            "maxOutputTokens": 8192,
                            "temperature": 0.3,
                            "candidateCount": 1
                        }
                    }

                    res_gem_retry = requests.post(gem_url, json=gem_body2, timeout=90)
                    if res_gem_retry.status_code == 200:
                        gem_data_retry = res_gem_retry.json()
                        gemini_text_retry = _extract_gemini_text(gem_data_retry)
                        if _gemini_sections_complete(gemini_text_retry):
                            gemini_text = gemini_text_retry

            elif res_gem.status_code == 429:
                log_info("⚠️ Gemini 2.5-flash 쿼터 초과 → 2.0-flash 폴백 시도...")
                try:
                    gem_url_fb = (
                        f"https://generativelanguage.googleapis.com/v1beta/models"
                        f"/gemini-2.0-flash:generateContent?key={GEMINI_API_KEY}"
                    )
                    res_gem2 = requests.post(gem_url_fb, json=gem_body, timeout=90)

                    if res_gem2.status_code == 200:
                        gem_data2 = res_gem2.json()
                        gemini_text = _extract_gemini_text(gem_data2)

                        cand2 = gem_data2.get('candidates', [{}])[0]
                        finish_reason2 = cand2.get('finishReason', '')
                        usage2 = gem_data2.get('usageMetadata', {})
                        log_info(f"✅ Gemini 2.0-flash 폴백 성공 | finishReason={finish_reason2} | usage={usage2}")

                        if finish_reason2 == 'MAX_TOKENS':
                            log_error("⚠️ Gemini 2.0-flash 출력도 MAX_TOKENS로 잘렸을 가능성 있음")
                    else:
                        log_info(f"⚠️ Gemini 2.0-flash도 실패 ({res_gem2.status_code}) - {res_gem2.text[:300]}")
                except Exception as e2:
                    log_info(f"⚠️ Gemini 폴백 실패: {e2}")

            elif res_gem.status_code == 400:
                log_error(f"⚠️ Gemini 요청 오류 (400): {res_gem.text[:300]}")
            else:
                log_error(f"⚠️ Gemini 응답 오류: {res_gem.status_code} / {res_gem.text[:300]}")

        except Exception as e:
            log_error(f"⚠️ Gemini 토너먼트 실패: {e}")
    else:
        log_info("⚠️ GEMINI_API_KEY 없음 — Gemini 생략")

    # ── Groq 호출 (실패해도 계속)
    groq_text = ''
    if GROQ_API_KEY:
        try:
            res_groq = requests.post(
                "https://api.groq.com/openai/v1/chat/completions",
                json={
                    "model": "llama-3.3-70b-versatile",
                    "messages": [
                        {"role": "system", "content": system_prompt},
                        {"role": "user",   "content": user_prompt}
                    ]
                },
                headers={"Authorization": f"Bearer {GROQ_API_KEY}"},
                timeout=60
            )
            if res_groq.status_code == 200:
                groq_json = res_groq.json()
                groq_text = groq_json.get('choices', [{}])[0].get('message', {}).get('content', '') or ''
                log_info("✅ Groq 토너먼트 완료")
            else:
                log_error(f"⚠️ Groq 응답 오류: {res_groq.status_code} {res_groq.text[:200]}")
        except Exception as e:
            log_error(f"⚠️ Groq 토너먼트 실패: {e}")
    else:
        log_info("⚠️ GROQ_API_KEY 없음 — Groq 생략")

    # ── 결과 조합
    results_map = {
        '🧠 [GPT-4o]':        gpt_text,
        '🤖 [Claude-Sonnet]': claude_text,
        '♊ [Gemini-Flash]':   gemini_text,
        '⚡ [Groq-Llama]':    groq_text,
    }
    log_info(f"  GPT:{bool(gpt_text)} Claude:{bool(claude_text)} Gemini:{bool(gemini_text)} Groq:{bool(groq_text)}")

    if not any(results_map.values()):
        return "⚠️ 모든 AI 호출 실패 (API 키 확인 필요)"

    result = "🏆 [AI 토너먼트 결승]\n"
    result += "모델상태: GPT={} | Claude={} | Gemini={} | Groq={}\n".format(
        "응답" if bool(gpt_text) else "없음",
        "응답" if bool(claude_text) else "없음",
        "응답" if bool(gemini_text) else "없음",
        "응답" if bool(groq_text) else "없음",
    )

    for label, text in results_map.items():
        body = (text or "").strip()
        if not body:
            body = "⚙️ 응답 없음 또는 호출 실패"
        result += f"\n{label}:\n{body}\n"

    return result

def _call_claude_api(system_prompt: str, user_prompt: str,
                     max_tokens: int = 3000) -> str:
    """
    Anthropic Claude API 직접 호출.
    OpenAI와 동일한 입출력 구조로 교체 가능.
    """
    if not ANTHROPIC_API_KEY:
        return ''
    try:
        res = requests.post(
            'https://api.anthropic.com/v1/messages',
            headers={
                'Content-Type':      'application/json',
                'x-api-key':         ANTHROPIC_API_KEY,
                'anthropic-version': '2023-06-01',
            },
            json={
                'model':      'claude-sonnet-4-20250514',
                'max_tokens': max_tokens,
                'system':     system_prompt,
                'messages':   [{'role': 'user', 'content': user_prompt}],
            },
            timeout=60
        )
        data = res.json()
        if 'content' in data and data['content']:
            return data['content'][0].get('text', '').strip()
        log_error(f"[Claude API 오류] {data.get('error', data)}")
        return ''
    except Exception as e:
        log_error(f"[Claude API 호출 실패] {e}")
        return ''



def _call_gemini_api_generic(system_prompt: str, user_prompt: str, max_tokens: int = 3000) -> str:
    if not GEMINI_API_KEY:
        return ''
    try:
        gem_body = {
            "contents": [{
                "parts": [{
                    "text": f"{system_prompt}\n\n{user_prompt}"
                }]
            }],
            "generationConfig": {
                "temperature": 0.5,
                "maxOutputTokens": max_tokens,
            }
        }

        gem_url = (
            "https://generativelanguage.googleapis.com/v1beta/models"
            f"/gemini-2.5-flash:generateContent?key={GEMINI_API_KEY}"
        )
        res = requests.post(gem_url, json=gem_body, timeout=90)
        if res.status_code == 200:
            out = _extract_gemini_text(res.json())
            if out:
                log_debug("✅ Gemini API 사용")
                return out

        gem_url_fb = (
            "https://generativelanguage.googleapis.com/v1beta/models"
            f"/gemini-2.0-flash:generateContent?key={GEMINI_API_KEY}"
        )
        res2 = requests.post(gem_url_fb, json=gem_body, timeout=90)
        if res2.status_code == 200:
            out2 = _extract_gemini_text(res2.json())
            if out2:
                log_debug("✅ Gemini API 사용 (폴백)")
                return out2
        return ''
    except Exception as e:
        log_error(f"[Gemini 종목별 코멘트 실패] {e}")
        return ''


def _call_groq_api_generic(system_prompt: str, user_prompt: str, max_tokens: int = 3000) -> str:
    if not GROQ_API_KEY:
        return ''
    try:
        res = requests.post(
            "https://api.groq.com/openai/v1/chat/completions",
            headers={"Authorization": f"Bearer {GROQ_API_KEY}"},
            json={
                "model": "llama-3.3-70b-versatile",
                "messages": [
                    {"role": "system", "content": system_prompt},
                    {"role": "user",   "content": user_prompt},
                ],
                "temperature": 0.5,
                "max_tokens": max_tokens,
            },
            timeout=60
        )
        if res.status_code == 200:
            data = res.json()
            out = data.get("choices", [{}])[0].get("message", {}).get("content", "") or ""
            if out:
                log_debug("✅ Groq API 사용")
                return out.strip()
        else:
            log_error(f"[Groq 종목별 코멘트 실패] {res.status_code} {res.text[:200]}")
        return ''
    except Exception as e:
        log_error(f"[Groq 종목별 코멘트 예외] {e}")
        return ''


def parse_ai_summary_to_map(ai_result_text: str) -> dict:
    ai_map = {}
    current_key = None
    current_lines = []
    header_re = re.compile(r'^\s*(?:[#>\-\d\.\)]\s*)*\[?\s*([^\[\]\(\)]+?)\s*\(\s*(\d{6})\s*\)\s*\]?\s*$')

    for raw_line in str(ai_result_text or "").splitlines():
        line = raw_line.strip()
        if not line:
            if current_key:
                current_lines.append(raw_line)
            continue

        m = header_re.match(line)
        if m:
            if current_key and current_lines:
                ai_map[current_key] = "\n".join(current_lines).strip()
            name = m.group(1).strip()
            code = m.group(2).strip()
            current_key = f"{name}({code})"
            current_lines = []
        elif current_key:
            current_lines.append(raw_line)

    if current_key and current_lines:
        ai_map[current_key] = "\n".join(current_lines).strip()

    return ai_map


def _call_ai(system_prompt: str, user_prompt: str,
             max_tokens: int = 3000, prefer_claude: bool = True) -> str:
    """
    AI API 호출 — Claude/OpenAI 우선, 실패 시 Gemini/Groq까지 폴백.
    """
    if prefer_claude and ANTHROPIC_API_KEY:
        result = _call_claude_api(system_prompt, user_prompt, max_tokens)
        if result:
            log_debug("✅ Claude API 사용")
            return result

    if OPENAI_API_KEY:
        try:
            client = OpenAI(api_key=OPENAI_API_KEY)
            res = client.chat.completions.create(
                model='gpt-4o',
                messages=[
                    {'role': 'system', 'content': system_prompt},
                    {'role': 'user',   'content': user_prompt},
                ],
                max_tokens=max_tokens,
                temperature=0.5
            )
            out = (res.choices[0].message.content or '').strip()
            if out:
                log_debug("✅ OpenAI API 사용 (폴백)")
                return out
        except Exception as e:
            log_error(f"[OpenAI 폴백 실패] {e}")

    result = _call_gemini_api_generic(system_prompt, user_prompt, max_tokens=max_tokens)
    if result:
        return result

    result = _call_groq_api_generic(system_prompt, user_prompt, max_tokens=min(max_tokens, 4000))
    if result:
        return result

    return "AI 분석 불가 (API 키 없음 또는 호출 실패)"



def _call_openai_api_generic(system_prompt: str, user_prompt: str, max_tokens: int = 3000) -> str:
    if not OPENAI_API_KEY or OpenAI is None:
        return ''
    try:
        client = OpenAI(api_key=OPENAI_API_KEY)
        res = client.chat.completions.create(
            model='gpt-4o-mini',
            messages=[
                {'role': 'system', 'content': system_prompt},
                {'role': 'user',   'content': user_prompt},
            ],
            max_tokens=max_tokens,
            temperature=0.4
        )
        out = (res.choices[0].message.content or '').strip()
        return out
    except Exception as e:
        log_error(f"[OpenAI JSON 호출 실패] {e}")
        return ''


def _main7_llm_runner(system_prompt: str, user_prompt: str,
                      preferred_models=None, role_name: str = ''):
    model_order = list(preferred_models or ['anthropic', 'openai', 'gemini', 'groq'])
    tried = []

    for model_name in model_order:
        m = str(model_name).strip().lower()
        if m in tried:
            continue
        tried.append(m)

        try:
            if m in ('anthropic', 'claude'):
                out = _call_claude_api(system_prompt, user_prompt, max_tokens=2400)
                if out and 'AI 분석 불가' not in out:
                    log_info(f"✅ {role_name} LLM 성공: anthropic")
                    return out, 'anthropic'

            elif m in ('openai', 'gpt'):
                out = _call_openai_api_generic(system_prompt, user_prompt, max_tokens=2200)
                if out and 'AI 분석 불가' not in out:
                    log_info(f"✅ {role_name} LLM 성공: openai")
                    return out, 'openai'

            elif m in ('gemini', 'google'):
                out = _call_gemini_api_generic(system_prompt, user_prompt, max_tokens=2200)
                if out and 'AI 분석 불가' not in out:
                    log_info(f"✅ {role_name} LLM 성공: gemini")
                    return out, 'gemini'

            elif m == 'groq':
                out = _call_groq_api_generic(system_prompt, user_prompt, max_tokens=2200)
                if out and 'AI 분석 불가' not in out:
                    log_info(f"✅ {role_name} LLM 성공: groq")
                    return out, 'groq'
        except Exception as e:
            log_error(f"⚠️ {role_name} LLM 실패({m}): {e}")

    fallback = _call_ai(system_prompt, user_prompt, max_tokens=2200)
    return fallback, 'fallback'


def _coerce_news_headlines(news_text: str):
    txt = str(news_text or '').strip()
    if not txt:
        return []
    parts = [x.strip("-• 	") for x in re.split(r'\n+|\|', txt) if str(x).strip()]
    return parts[:3]


def _build_main7_debate_hits(ai_candidates_df: pd.DataFrame, top_k: int = 15):
    if ai_candidates_df is None or ai_candidates_df.empty:
        return []

    work = ai_candidates_df.head(top_k).copy()
    hits = []

    for _, row in work.iterrows():
        code = str(row.get('code', '')).strip()
        if code and code.isdigit():
            code = code.zfill(6)

        amount_b = safe_float(row.get('거래대금B', row.get('거래대금(억)', row.get('amount_b', 0))), 0.0)
        if amount_b <= 0:
            amount_raw = safe_float(row.get('거래대금', row.get('Amount', 0)), 0.0)
            if amount_raw > 0:
                amount_b = round(amount_raw / 100000000.0, 1)

        vol_ratio = safe_float(
            row.get('거래량배수',
                    row.get('매집거래량배율',
                            row.get('거래대금배수', 0))), 0.0
        )

        wick_pct = safe_float(row.get('윗꼬리비율', row.get('상꼬리비율', 0)), 0.0)

        nscore = safe_float(row.get('N점수', 0), 0.0)
        safe_score = safe_float(row.get('안전점수', 0), 0.0)
        merged_score = round((nscore * 0.6) + (safe_score * 0.4), 1)

        flow_grade = str(row.get('수급', '중립'))
        flow_status = 'missing'
        flow_grade_l = flow_grade.lower()
        if any(k in flow_grade for k in ['외인', '기관', '연기금', '프로그램']) or 'positive' in flow_grade_l:
            flow_status = 'positive'
        elif any(k in flow_grade for k in ['이탈', '매도']) or 'negative' in flow_grade_l:
            flow_status = 'negative'
        elif flow_grade.strip():
            flow_status = 'weak'

        mode = str(row.get('단계상태', '') or '').strip()
        if not mode:
            mode = 'MAIN'
        grade = str(row.get('N등급', row.get('grade', ''))).strip()
        rec_band = 'ENV' if 'ENV' in str(row.get('N구분', '')) else ('BB' if safe_float(row.get('BB40', 0), 0) > 0 else '')

        hits.append({
            'name': row.get('종목명', ''),
            'code': code,
            'mode': mode,
            'mode_label': str(row.get('N조합', mode)),
            'grade': grade,
            'recommended_band': rec_band,
            'universe_tag': str(row.get('구분', '')),
            'index_label': str(row.get('코스피200', '') or row.get('코스닥150', '') or ''),
            'close': safe_int(row.get('현재가', 0)),
            'open': safe_int(row.get('시가', row.get('Open', 0))),
            'high': safe_int(row.get('고가', row.get('High', 0))),
            'amount_b': amount_b,
            'vol_ratio': vol_ratio,
            'wick_pct': wick_pct,
            'target1': safe_int(row.get('🎯목표타점', 0)),
            'stoploss': safe_int(row.get('🚨손절가', 0)),
            'rr': safe_float(row.get('RR비율', 0), 0.0),
            'score': merged_score,
            'near20': safe_float(row.get('이격', 0), 0.0),
            'disp': safe_float(row.get('이격', 0), 0.0),
            'env20_pct': safe_float(row.get('Env20Pct', row.get('env20_pct', 0)), 0.0),
            'env40_pct': safe_float(row.get('Env40Pct', row.get('env40_pct', 0)), 0.0),
            'rsi': safe_float(row.get('RSI', 0), 0.0),
            'obv_rising': safe_float(row.get('OBV기울기', 0), 0.0) > 0,
            'maejip_5d': safe_int(row.get('매집일수_10일', row.get('매집일수_5일', 0))),
            'flow_status': flow_status,
            'flow_grade': flow_grade,
            'frgn3_sum_b': safe_float(row.get('외인3일합(억)', 0), 0.0),
            'inst3_sum_b': safe_float(row.get('기관3일합(억)', 0), 0.0),
            'fi3_sum_b': safe_float(row.get('외인기관3일합(억)', 0), 0.0),
            'flow_positive_days': safe_int(row.get('수급양수일수(3일)', 0)),
            'flow_min_ratio': safe_float(row.get('수급최대이탈비율', 0), 0.0),
            'sector': str(row.get('구분', '')),
            'theme': str(row.get('N조합', '')),
            'leader_name': str(row.get('대표종목', '')),
            'news_headlines': _coerce_news_headlines(row.get('news_sentiment', '')),
        })

    return hits


def _merge_debate_rows_into_candidates(ai_candidates_df: pd.DataFrame, debate_rows):
    if ai_candidates_df is None or ai_candidates_df.empty or not debate_rows:
        return ai_candidates_df

    out = ai_candidates_df.copy()
    if 'AI최종판정' not in out.columns:
        out['AI최종판정'] = ''
    if 'AI확신도' not in out.columns:
        out['AI확신도'] = 0
    if 'AI심판요약' not in out.columns:
        out['AI심판요약'] = ''
    if 'AI강한근거' not in out.columns:
        out['AI강한근거'] = ''
    if 'AI위험요인' not in out.columns:
        out['AI위험요인'] = ''
    if 'AI심판모델' not in out.columns:
        out['AI심판모델'] = ''
    if 'AI재료분류' not in out.columns:
        out['AI재료분류'] = ''

    row_map = {}
    for r in debate_rows:
        code = str(r.get('code', '')).strip()
        if code and code.isdigit():
            code = code.zfill(6)
        row_map[code] = r

    for idx, row in out.iterrows():
        code = str(row.get('code', '')).strip()
        if code and code.isdigit():
            code = code.zfill(6)
        r = row_map.get(code)
        if not r:
            continue
        out.at[idx, 'AI최종판정'] = str(r.get('AI최종판정', ''))
        out.at[idx, 'AI확신도'] = safe_int(r.get('AI확신도', 0))
        out.at[idx, 'AI심판요약'] = str(r.get('AI심판요약', ''))
        out.at[idx, 'AI강한근거'] = str(r.get('AI강한근거', ''))
        out.at[idx, 'AI위험요인'] = str(r.get('AI위험요인', ''))
        out.at[idx, 'AI심판모델'] = str(r.get('AI심판모델', ''))
        out.at[idx, 'AI재료분류'] = str(r.get('AI재료분류', ''))

    return out



def _main7_ai_first_clause(s: str, max_len: int = 52) -> str:
    s = re.sub(r'\s+', ' ', str(s or '')).strip(' |,-')
    if not s:
        return ''
    chunks = re.split(r'[|;/]|(?:\.|,)|(?: 하지만 )|(?: 그러나 )|(?: 다만 )', s)
    for c in chunks:
        c = re.sub(r'\s+', ' ', c).strip(' |,-')
        if 8 <= len(c) <= max_len:
            return c
    if len(s) <= max_len:
        return s
    return s[:max_len].rstrip(' |,-')

def _fallback_main7_role_text(row, role: str) -> str:
    vol_ratio = safe_float(row.get('vol_ratio', row.get('거래량배수', 0)), 0.0)
    wick = safe_float(row.get('wick_pct', row.get('윗꼬리비율', 0)), 0.0)
    rsi = safe_float(row.get('rsi', row.get('RSI', 0)), 0.0)
    rr = safe_float(row.get('rr', row.get('RR비율', 0)), 0.0)
    flow_status = str(row.get('flow_status', row.get('수급', ''))).strip()
    fr = safe_float(row.get('frgn3_sum_b', 0), 0.0)
    inst = safe_float(row.get('inst3_sum_b', 0), 0.0)
    sector = str(row.get('sector', row.get('구분', ''))).strip()
    theme = str(row.get('theme', row.get('N조합', ''))).strip()
    verdict = str(row.get('AI최종판정', '')).strip()

    if role == 'tech':
        parts = []
        if vol_ratio > 0:
            parts.append(f"거래량 {vol_ratio:.1f}배")
        if rsi > 0:
            parts.append(f"RSI {rsi:.0f}")
        if theme:
            parts.append(theme[:18])
        return " / ".join(parts[:3]) or "차트 재점검 필요"

    if role == 'flow':
        if fr > 0 or inst > 0:
            return f"외인 {fr:.0f}억 / 기관 {inst:.0f}억 흐름"
        if 'positive' in flow_status or '외인' in flow_status or '기관' in flow_status:
            return "수급은 우호적이나 강도 확인 필요"
        if 'negative' in flow_status or '이탈' in flow_status or '매도' in flow_status:
            return "이탈 흔적 있어 수급 재확인 필요"
        return "수급은 약하지만 거래 흐름은 확인"

    if role == 'theme':
        if sector and theme:
            return f"{sector} / {theme[:20]} 맥락 확인"
        if sector:
            return f"{sector} 섹터 동행성 확인 필요"
        return "개별 재료 중심으로 해석 필요"

    if role == 'risk':
        parts = []
        if wick > 0:
            parts.append(f"윗꼬리 {wick:.1f}%")
        if rsi >= 70:
            parts.append(f"RSI {rsi:.0f} 과열")
        if rr > 0:
            parts.append(f"RR {rr:.1f}")
        return " / ".join(parts[:3]) or "손절 기준과 갭 리스크 점검"

    if role == 'judge':
        if verdict:
            return f"{verdict} 판단이지만 추격 여부는 분리"
        return "종합 판단은 가능하나 확인 신호 더 필요"

    return "추가 확인 필요"

def _clean_main7_ai_text(text: str, max_len: int = 52, row=None, role: str = '') -> str:
    s = str(text or '').strip()
    replace_pairs = [
        ('시황 근거 부족', ''),
        ('수급 근거 부족', ''),
        ('리스크 정보 부족', ''),
        ('강한 근거 부족', ''),
        ('상승 이유 정보 부족', ''),
        ('정보 부족', ''),
        ('다음 날 ', '내일 '),
        ('종가배팅', ''),
        ('확인되어', ''),
        ('가능성이 있음', '가능성'),
        ('리스크가 존재', '리스크'),
        ('확신은 제한적', '확신 약함'),
    ]
    for a, b in replace_pairs:
        s = s.replace(a, b)
    s = re.sub(r'\s+', ' ', s).strip(' |,-')

    bland = {
        '거래량 증가 긍정적': '거래량은 좋지만 위치가 더 중요',
        '추세가 좋아 보임': '추세 유지지만 눌림 깊이 확인',
        '리스크 존재': '갭·윗꼬리 리스크 점검',
        '근거 부족': '',
    }
    s = bland.get(s, s)

    if not s:
        return _fallback_main7_role_text(row or {}, role)

    s = _main7_ai_first_clause(s, max_len=max_len)
    if not s:
        return _fallback_main7_role_text(row or {}, role)
    return s
MAIN7_AI_TELEGRAM_LAYOUT_VERSION = 'split_v1 | wm_tune_v25_resistance_cloud'


def _format_ai_multilist(text, max_len=46):
    items = []
    for line in str(text or "").splitlines():
        s = re.sub(r'\s+', ' ', str(line or "")).strip(" -")
        if not s:
            continue
        if len(s) > max_len:
            s = s[:max_len].rstrip() + "…"
        items.append(s)
    return items[:3]

def _format_main7_ai_debate_text(rows):
    if not rows:
        return ''

    top_rows = list(rows)[:5]
    first = top_rows[0]
    lines = [
        f"🧠 메인 후보 AI 심판 TOP{len(top_rows)}",
        f"버전: {MAIN7_AI_TELEGRAM_LAYOUT_VERSION}",
        "모델사용: 기술{} | 수급{} | 시황{} | 리스크{} | 심판{}".format(
            str(first.get('AI기술모델', '[Unknown]')),
            str(first.get('AI수급모델', '[Unknown]')),
            str(first.get('AI시황모델', '[Unknown]')),
            str(first.get('AI리스크모델', '[Unknown]')),
            str(first.get('AI심판모델', '[Unknown]')),
        ),
        "",
    ]

    for i, r in enumerate(top_rows, start=1):
        name = str(r.get('name', '') or '')
        code = str(r.get('code', '') or '')
        mode = str(r.get('구분', '') or r.get('mode', '') or '')
        grade = str(r.get('grade', '') or r.get('구분', '') or '')
        verdict = str(r.get('AI최종판정', '') or '관찰')
        conf = safe_int(r.get('AI확신도', 0))

        judge = _clean_main7_ai_text(r.get('AI심판요약', ''), 56, r, 'judge')
        strong = _clean_main7_ai_text(r.get('AI강한근거', ''), 56, r, 'judge')
        riskp = _clean_main7_ai_text(r.get('AI위험요인', ''), 56, r, 'risk')
        plan = _clean_main7_ai_text(r.get('AI실행계획', ''), 56, r, 'judge')

        tech = _clean_main7_ai_text(r.get('AI기술의견', ''), 52, r, 'tech')
        flow = _clean_main7_ai_text(r.get('AI수급의견', ''), 52, r, 'flow')
        theme = _clean_main7_ai_text(r.get('AI시황의견', ''), 52, r, 'theme')
        risk = _clean_main7_ai_text(r.get('AI리스크의견', ''), 52, r, 'risk')

        judge_list = _format_ai_multilist(r.get('AI심판의견목록', ''), 52)
        tech_list = _format_ai_multilist(r.get('AI기술의견목록', ''), 48)
        theme_list = _format_ai_multilist(r.get('AI시황의견목록', ''), 48)

        _time_tag = str(r.get('time_sym_tag', '')).strip()
        _time_comment = str(r.get('time_sym_comment', '')).strip()

        lines.extend([
            f"{i}. {name}({code}) [{mode}/{grade}] → {verdict} {conf}점",
            f"   심판대표{(r.get('AI심판대표모델', '') if str(r.get('AI심판대표모델', '')).strip() else '[자동선택]')}: {judge}",
            f"   근거: {strong}",
            f"   위험: {riskp}",
            f"   계획: {plan}",
            "   심판의견:",
            *([f"      {x}" for x in judge_list] if judge_list else [f"      {judge}"]),
            "   기술의견:",
            *([f"      {x}" for x in tech_list] if tech_list else [f"      기술{(r.get('AI기술모델', '') if str(r.get('AI기술모델', '')).strip() else '[자동선택]')}: {tech}"]),
            f"   수급{(r.get('AI수급모델', '') if str(r.get('AI수급모델', '')).strip() else '[자동선택]')}: {flow}",
            "   시황의견:",
            *([f"      {x}" for x in theme_list] if theme_list else [f"      시황{(r.get('AI시황모델', '') if str(r.get('AI시황모델', '')).strip() else '[자동선택]')}: {theme}"]),
            f"   리스크{(r.get('AI리스크모델', '') if str(r.get('AI리스크모델', '')).strip() else '[자동선택]')}: {risk}",
        ])
        if _time_tag:
            lines.append(f"   시간창: {_time_tag}" + (f" | {_time_comment}" if _time_comment else ""))
        lines.append("")

    return "\n".join(lines).strip()

def _run_main7_ai_debate(ai_candidates_df: pd.DataFrame, issues=None, market_news=None):
    if run_closing_bet_debate_pipeline is None:
        return ai_candidates_df, '', []

    if ai_candidates_df is None or ai_candidates_df.empty:
        return ai_candidates_df, '', []

    hits = _build_main7_debate_hits(ai_candidates_df, top_k=15)
    if not hits:
        return ai_candidates_df, '', []

    comments = "특이 이슈 없음"
    if issues:
        comments = " | ".join([str(i.get("comment", "분석 필요")) for i in issues[:5]])

    news_block = ""
    if market_news and isinstance(market_news, list):
        top_news = [str(n).strip() for n in market_news[:5] if str(n).strip()]
        if top_news:
            news_block = " | ".join(top_news)

    extra_context = f"메인 전략 사령부 후보 토론. 시장이슈: {comments}"
    if news_block:
        extra_context += f" | 주요뉴스: {news_block}"

    role_model_prefs = {
        'tech': ['anthropic', 'openai'],
        'flow': ['openai', 'groq', 'anthropic'],
        'theme': ['anthropic', 'gemini', 'openai'],
        'risk': ['openai', 'groq', 'anthropic'],
        'judge': ['anthropic', 'openai', 'gemini'],
    }

    try:
        now_dt = datetime.now(KST)
    except Exception:
        now_dt = datetime.now()

    try:
        result = run_closing_bet_debate_pipeline(
            hits=hits,
            llm_runner=_main7_llm_runner,
            now_dt=now_dt,
            mins_left=0,
            top_n=7,
            extra_market_context=extra_context,
            role_model_prefs=role_model_prefs,
        )
        debate_rows = result.get('rows', []) or []
        _unused_telegram_text = result.get('telegram_text', '') or ''
        telegram_text = _format_main7_ai_debate_text(debate_rows)
        merged_df = _merge_debate_rows_into_candidates(ai_candidates_df, debate_rows)
        log_info(f"🧠 메인후보 AI 토론 완료: {len(debate_rows)}개 | 레이아웃 {MAIN7_AI_TELEGRAM_LAYOUT_VERSION}")
        return merged_df, telegram_text, debate_rows
    except Exception as e:
        log_error(f"⚠️ 메인후보 AI 토론 실패: {e}")
        return ai_candidates_df, '', []

def get_ai_summary_batch(ai_candidates_df, issues=None, market_news=None):
    """
    판단형 종목 코멘트 생성.
    안정성을 위해 후보를 15개까지 보고, 3개씩 나눠서 배치 호출한다.
    """
    comments = "특이 이슈 없음"
    if issues:
        comments = " | ".join([i.get("comment", "분석 필요") for i in issues])

    market_news_block = ""
    if market_news and isinstance(market_news, list):
        top_news = [str(n) for n in market_news[:5] if n]
        if top_news:
            market_news_block = "\n\n## 오늘 시장 주요 뉴스\n" + "\n".join(f"- {n}" for n in top_news)

    work_df = ai_candidates_df.head(15).copy()
    if work_df is None or work_df.empty:
        return "브리핑 생성 중 오류가 발생했습니다."

    batch_size = 3
    outputs = []

    for start_idx in range(0, len(work_df), batch_size):
        batch_df = work_df.iloc[start_idx:start_idx + batch_size].copy()

        packets = []
        for _, row in batch_df.iterrows():
            packets.append(build_judgment_packet(row))

        system_prompt = f"""
너는 한국 주식 실전 트레이딩 보조 AI다.
역할은 '좋은 말로 소개'가 아니라 '지금 실제로 매매 가능한지 심사하는 것'이다.

{YEOK_MAE_CONTEXT}

판단 원칙:
1. 먼저 초입/중간/후행/눌림 중 어느 위치인지 판단할 것
2. 차트 구조를 먼저 보고, 그 다음 수급과 시황 적합성을 붙일 것
3. 장점보다 약점과 무효화 조건을 더 중요하게 볼 것
4. 패턴명을 반복하지 말고, 패턴이 만들어내는 자리의 의미를 설명할 것
5. 숫자를 그대로 읽지 말고, 그 숫자가 의미하는 해석을 말할 것
6. 시장/테마 흐름이 받쳐주는지 또는 역풍인지 반드시 1회 언급할 것
7. 각 종목의 첫 문장은 모두 다르게 시작할 것
8. 짧더라도 실전적인 문장으로 쓸 것
9. 확신이 없으면 관망이라고 명확히 말할 것

오늘 시장 이슈:
{comments}{market_news_block}
"""

        user_prompt = f"""
다음은 종목별 판단 패킷이다.
각 종목마다 아래 형식으로만 써라.

형식:
[종목명(코드)]
한 줄 결론: 1문장
차트 구조 해석: 2문장
수급/시황 적합성: 1~2문장
진입 방식: 1~2문장
무효화 조건: 1문장
총평: 1문장

종목 패킷(JSON):
{json.dumps(packets, ensure_ascii=False, indent=2)}

주의:
- 패턴명 낭독 금지
- 숫자 나열 금지
- 같은 문장 반복 금지
- 너무 장황하게 쓰지 말고, 종목당 6~8문장 정도의 리포트형 요약으로 작성
- 반드시 [종목명(코드)] 헤더를 정확히 써라
"""

        result = _call_ai(system_prompt, user_prompt, max_tokens=1800)
        if result and str(result).strip():
            outputs.append(str(result).strip())

    if not outputs:
        return "브리핑 생성 중 오류가 발생했습니다."
    return "\n\n".join(outputs)

def get_ai_summary_batch_back(stock_lines: list, issues: list = None):
    comments = "특이 이슈 없음"
    if issues:
        comments = " | ".join([i.get("comment", "분석 필요") for i in issues])
    
    system_prompt = get_summary_batch_system_prompt(comments)
    stock_text    = build_stock_lines_for_batch(ai_candidates)

    try:
        client = OpenAI(api_key=OPENAI_API_KEY)
        res = client.chat.completions.create(
        model="gpt-4o",
        messages=[
            {"role": "system", "content": system_prompt},
            {"role": "user",   "content": f"다음 종목들을 분석해줘:\n\n{stock_text}"}
        ],
        max_tokens=3000,
        temperature=0.5)   # 0.7 → 0.5로 낮춰 일관성 향상
        return res.choices[0].message.content.strip()

    except Exception as e:
        log_error(f"[AI 배치 요약 오류] {e}")
        return "브리핑 생성 중 오류가 발생했습니다."

def build_ai_candidates_for_macro(ai_candidates: pd.DataFrame):
    result = []

    for _, row in ai_candidates.iterrows():
        result.append({
            "name": row.get("종목명", ""),
            "code": row.get("code", ""),
            "sector": row.get("구분", ""),
            "n_grade": row.get("N등급", ""),
            "n_combo": row.get("N조합", ""),
            "n_score": row.get("N점수", 0),
            "safe_score": row.get("안전점수", 0),
            "current_price": row.get("현재가", 0),
            "disparity": row.get("이격", 0),
            "bb40": row.get("BB40", ""),
            "ma_conv": row.get("MA수렴", ""),
            "ma_ultra": row.get("초단기MA수렴도", ""),
            "ma_short": row.get("단기MA수렴도", ""),
            "ma_structure": row.get("구조MA수렴도", ""),
            "ma_comment": row.get("MA수렴코멘트", ""),
            "obv_slope": row.get("OBV기울기", 0),
            "rsi": row.get("RSI", 0),
            "supply": row.get("수급", ""),
            "finance": row.get("재무", ""),
            "story": row.get("📜서사히스토리", ""),
        })
    return result




def _macro_snapshot_item(item: dict):
    if not isinstance(item, dict) or not item.get("ok", False) or item.get("val") is None:
        return {
            "value": None,
            "change_pct": None,
            "status": "데이터부족",
            "ok": False,
            "source": item.get("source", "") if isinstance(item, dict) else "",
        }
    return {
        "value": item.get("val"),
        "change_pct": round(safe_float(item.get("chg"), 0.0), 2),
        "status": item.get("status", ""),
        "ok": True,
        "source": item.get("source", ""),
    }


def build_macro_snapshot(m_ndx, m_sp5, m_vix, m_fx, m_wti, issues, extended_macro_pack=None, sector_results=None):
    comments = "특이 이슈 없음"
    if issues:
        comments = " | ".join([i.get("comment", "") for i in issues])

    pack = extended_macro_pack or {}
    favorable = [s['sector'] for s in (sector_results or []) if s.get('verdict') == '추천'][:3]
    unfavorable = [s['sector'] for s in (sector_results or []) if s.get('verdict') == '회피'][:3]

    return {
        "nasdaq": _macro_snapshot_item(m_ndx),
        "sp500": _macro_snapshot_item(m_sp5),
        "vix": _macro_snapshot_item(m_vix),
        "usdkrw": _macro_snapshot_item(m_fx),
        "wti_oil": _macro_snapshot_item(m_wti),
        "russell2000": _macro_snapshot_item(pack.get("russell", {})),
        "us10y": _macro_snapshot_item(pack.get("us10y", {})),
        "copper": _macro_snapshot_item(pack.get("copper", {})),
        "gold": _macro_snapshot_item(pack.get("gold", {})),
        "sp500_fut": _macro_snapshot_item(pack.get("sp500_fut", {})),
        "nasdaq_fut": _macro_snapshot_item(pack.get("nasdaq_fut", {})),
        "dow_fut": _macro_snapshot_item(pack.get("dow_fut", {})),
        "russell_fut": _macro_snapshot_item(pack.get("russell_fut", {})),
        "nikkei_fut": _macro_snapshot_item(pack.get("nikkei_fut", {})),
        "hsi_fut": _macro_snapshot_item(pack.get("hsi_fut", {})),
        "favorable_sectors": favorable,
        "unfavorable_sectors": unfavorable,
        "issues": comments,
    }

def run_macro_candidate_briefing(
    ai_candidates,
    m_ndx, m_sp5, m_vix, m_fx,
    m_wti,
    sector_results,
    issues,
    extended_macro_pack=None,
):
    if ai_candidates is None or ai_candidates.empty:
        return {"error": "후보 종목 없음"}

    macro_data = build_macro_snapshot(
        m_ndx, m_sp5, m_vix, m_fx, m_wti, issues,
        extended_macro_pack=extended_macro_pack,
        sector_results=sector_results,
    )
    candidate_data = build_ai_candidates_for_macro(ai_candidates.head(15))
    sector_summary = build_sector_summary_for_prompt(sector_results, top_n=6)

    prompt = f"""
당신은 한국 주식시장 단기/스윙 트레이딩 보조 AI입니다.
사용자는 자동매매를 하지 않고 직접 매매합니다.
목표는 글로벌 시장 상황과 오늘 후보 종목의 궁합을 평가해 우선 검토 순서를 정하는 것입니다.

반드시 JSON만 출력하세요.
마크다운, 코드블록, 설명문 없이 JSON만 출력하세요.

출력 형식:
{{
  "market_briefing": {{
    "market_risk_score": 0,
    "market_state": "Risk On | Neutral | Risk Off",
    "korea_bias": "강세 | 강보합 | 혼조 | 약세 | 약세주의",
    "trading_stance": "공격적 | 선별적 | 방어적",
    "oil_impact": "",
    "summary": ""
  }},
  "sector_view": {{
    "favorable_sectors": ["", "", ""],
    "unfavorable_sectors": ["", "", ""]
  }},
  "candidate_ranking": [
    {{
      "rank": 1,
      "name": "",
      "code": "",
      "fit_score": 0,
      "action_type": "돌파형 | 눌림목형 | 관망형",
      "why": "",
      "risk": ""
    }}
  ],
  "top_pick": {{
    "name": "",
    "code": "",
    "reason": ""
  }},
  "avoid_first": {{
    "name": "",
    "code": "",
    "reason": ""
  }},
  "today_checkpoints": ["", "", ""]
}}

판단 원칙:
- VIX 상승, 나스닥/나스닥선물 약세, 러셀/러셀선물 약세면 Risk Off 성향 강화
- 환율 상승은 한국 성장주/외국인 수급에 부담
- 유가 상승 시 정유/화학/조선 수혜 가능, 단 실제 에너지 ETF/대표주 동행 여부를 확인
- 반도체/바이오/로봇/클라우드는 금리와 섹터 ETF, 대표주 breadth까지 같이 본다
- 대표 대장주가 급락했으면 해당 섹터를 바로 추천하지 말고 최소 관찰로 낮춰라
- N점수/안전점수는 참고, 시장 궁합을 더 중요하게 판단
- candidate_ranking에 반드시 모든 후보 종목 포함
- action_type은 반드시 돌파형 / 눌림목형 / 관망형 중 하나
- oil_impact는 유가 흐름이 오늘 한국 시장에 미치는 영향을 분석해서 1줄

글로벌 시장 데이터:
{json.dumps(macro_data, ensure_ascii=False, indent=2)}

확장 섹터 테이프 판정:
{sector_summary}

후보 종목 데이터:
{json.dumps(candidate_data, ensure_ascii=False, indent=2)}
"""

    try:
        client = OpenAI(api_key=OPENAI_API_KEY)
        res = client.chat.completions.create(
            model="gpt-4o-mini",
            messages=[
                {"role": "system", "content": "너는 보수적이고 실전적인 한국 주식 트레이딩 보조 AI다. 섹터 추천 전에는 반드시 대표주 테이프와 반대 근거를 먼저 검토해라."},
                {"role": "user", "content": prompt}
            ],
            temperature=0.3
        )

        text = res.choices[0].message.content.strip()
        try:
            return json.loads(text)
        except Exception:
            return {"error": "JSON 파싱 실패", "raw_response": text}

    except Exception as e:
        return {"error": f"OpenAI 호출 실패: {str(e)}"}

