def _tv_safe_str(value, default=''):
    if value is None:
        return default
    try:
        if isinstance(value, float) and _sh_math.isnan(value):
            return default
    except Exception:
        pass
    return str(value).strip()


def _tv_safe_float(value, default=0.0):
    if value is None:
        return default
    try:
        if isinstance(value, str):
            cleaned = (
                value.replace(',', '')
                .replace('%', '')
                .replace('원', '')
                .replace('억', '')
                .replace('배', '')
                .replace('⚠️', '')
                .strip()
            )
            m = _sh_re.search(r'[-+]?\d+(?:\.\d+)?', cleaned)
            if not m:
                return default
            return float(m.group(0))
        return float(value)
    except Exception:
        return default


def _tv_as_dict(row):
    if row is None:
        return {}
    if isinstance(row, dict):
        return row
    try:
        return row.to_dict()
    except Exception:
        return {}


def _tv_pick(row, *keys, default=''):
    data = _tv_as_dict(row)
    for k in keys:
        if k in data and data.get(k) is not None:
            v = data.get(k)
            try:
                if isinstance(v, float) and _sh_math.isnan(v):
                    continue
            except Exception:
                pass
            if _tv_safe_str(v) != '':
                return v
    return default


def _tv_join(items, sep=' / '):
    return sep.join([_tv_safe_str(x) for x in items if _tv_safe_str(x)])


def _tv_contains_any(text, words):
    s = _tv_safe_str(text)
    return any(w in s for w in words)


def _tv_detect_cloud(row):
    cloud_text = ' '.join([
        _tv_safe_str(_tv_pick(row, '저항구름상태', default='')),
        _tv_safe_str(_tv_pick(row, '저항구름태그', default='')),
        _tv_safe_str(_tv_pick(row, '저항구름코멘트', default='')),
        _tv_safe_str(_tv_pick(row, '저항구름', 'resistance_cloud', 'cloud', default='')),
    ])
    if '저항돌파' in cloud_text:
        return '저항돌파'
    if '저항테스트' in cloud_text:
        return '저항테스트'
    if '저항전' in cloud_text:
        return '저항전'
    if '저항혼합' in cloud_text:
        return '저항혼합'
    return '저항불명'


def _tv_detect_refine(row):
    refine_text = ' '.join([
        _tv_safe_str(_tv_pick(row, '수박정제태그', default='')),
        _tv_safe_str(_tv_pick(row, '수박정제코멘트', default='')),
        _tv_safe_str(_tv_pick(row, '정제', '정제상태', 'refine', default='')),
    ])
    if bool(_tv_pick(row, '수박정제주의', default=False)) or '가짜수박주의' in refine_text or '가짜' in refine_text:
        return '가짜수박주의'
    if bool(_tv_pick(row, '수박정제통과', default=False)) or '정제수박' in refine_text:
        return '정제수박'
    if bool(_tv_pick(row, '수박정제관찰', default=False)) or '관찰수박' in refine_text:
        return '관찰수박'
    return '정제불명'


def _tv_state_text(row):
    data = _tv_as_dict(row)
    keys = [
        '수박최종상태', '수박상태명', '상태', '최종상태', '추천단계', '유형', '돌파상태',
        '선취상태', '최종 판정', 'final_label', '판정', 'N조합', 'N구분', '태그', '돌파이유',
        '선취이유', '단계태그', '후행유형', '라운드넘버태그'
    ]
    return ' '.join(_tv_safe_str(data.get(k, '')) for k in keys if _tv_safe_str(data.get(k, '')))


def _tv_final_decision(row):
    return _tv_safe_str(_tv_pick(row, '최종 판정', 'final_label', '판정', 'AI최종판정', default=''))


def _tv_is_late(row):
    text = _tv_state_text(row)
    return bool(_tv_pick(row, '수박디버그_late', default=False)) or _tv_contains_any(text, ['후행수박', '후행형', '보유관리후행형', '과열후행형'])


def _tv_is_blue(row):
    text = _tv_state_text(row)
    return _tv_contains_any(text, ['Blue-1', 'Blue-2', 'Blue1', 'Blue2', '파란점선', '재점화', '2차파동'])


def _tv_has_reentry(row):
    text = _tv_state_text(row)
    return bool(_tv_pick(row, '5일재안착', default=False)) or _tv_contains_any(text, ['5일재안착', '재안착', '양봉', '거래량', 'OBV매집'])


def _tv_overheat_reasons(row):
    reasons = []
    disp = _tv_safe_float(_tv_pick(row, '이격', 'Disparity', default=0))
    rsi = _tv_safe_float(_tv_pick(row, 'RSI', 'RSI14', default=0))
    wick = _tv_safe_float(_tv_pick(row, '윗꼬리비율', '상꼬리비율', 'upper_wick_pct', default=0))
    text = _tv_state_text(row)
    if disp >= 120:
        reasons.append(f'이격 {disp:.0f} 과열권')
    elif disp >= 115:
        reasons.append(f'이격 {disp:.0f} 추격부담')
    if rsi >= 75:
        reasons.append(f'RSI {rsi:.0f} 과열권')
    elif rsi >= 70:
        reasons.append(f'RSI {rsi:.0f} 부담권')
    if wick >= 35:
        reasons.append(f'윗꼬리 {wick:.0f}% 부담')
    if '과열' in text:
        reasons.append('과열 태그')
    return reasons


def build_trade_clarity_view(row):
    """구조판정과 매매판정을 분리해서 반환한다."""
    cloud = _tv_detect_cloud(row)
    refine = _tv_detect_refine(row)
    state_text = _tv_state_text(row)
    final = _tv_final_decision(row)
    late = _tv_is_late(row)
    blue = _tv_is_blue(row)
    reentry = _tv_has_reentry(row)
    overheat = _tv_overheat_reasons(row)

    if cloud == '저항돌파':
        if late:
            structure = '저항구름 돌파 후행형'
        elif blue:
            structure = '저항구름 돌파 재점화형'
        else:
            structure = '저항구름 돌파확인형'
    elif cloud == '저항테스트':
        structure = '저항구름 돌파테스트형'
    elif cloud == '저항전':
        if _tv_contains_any(state_text, ['눌림수박', '눌림', '재안착']):
            structure = '저항 전 눌림선취형'
        else:
            structure = '저항 전 선취관찰형'
    elif blue:
        structure = '재점화 확인형'
    elif _tv_contains_any(state_text, ['초입수박', '눌림수박', '선취']):
        structure = '초입·눌림 구조관찰형'
    else:
        structure = '밴드외 구조관찰형'

    action = '관찰'
    level = 'observe'
    action_reasons = []

    if refine == '가짜수박주의':
        action_reasons.append('가짜수박주의')
        if late or overheat:
            action, level = '추격 금지', 'avoid_chase'
        else:
            action, level = '확인 대기', 'wait_confirm'
    elif late:
        action_reasons.append('후행 구간')
        if overheat or '과열후행형' in state_text:
            action, level = '추격 금지', 'avoid_chase'
        else:
            action, level = '보유자 대응', 'holder_manage'
    elif cloud == '저항돌파':
        action_reasons.append('돌파 구조')
        if overheat:
            action, level = '눌림 대기', 'wait_pullback'
            action_reasons.extend(overheat)
        elif blue and refine in ('정제수박', '관찰수박') and reentry and ('즉시 대응' in final or '즉시대응' in final):
            action, level = '조건부 실행', 'execute'
            action_reasons.append('재점화+재안착')
        else:
            action, level = '눌림 대기', 'wait_pullback'
    elif cloud == '저항테스트':
        action_reasons.append('저항 테스트')
        action, level = '돌파확인 대기', 'wait_confirm'
    elif cloud == '저항전':
        if _tv_contains_any(state_text, ['초입수박', '눌림수박', '선취', '재안착']):
            action, level = '선취 관찰', 'observe'
            action_reasons.append('저항 전 선취 가능')
        else:
            action, level = '관찰', 'observe'
    elif _tv_contains_any(state_text, ['눌림수박', '재안착']):
        action, level = '눌림 대기', 'wait_pullback'

    if level == 'execute':
        conditions = ['구름상단 위 종가 유지', '5일선 훼손 없음', '장중 눌림 후 재양봉', '거래량 재유입', '분할 진입']
        meaning = '구조는 돌파·재점화가 확인됐지만, 분할과 손절 기준을 전제로만 실행 가능한 자리입니다.'
    elif level == 'wait_pullback':
        conditions = ['구름상단 또는 5일선 눌림', '눌림 후 재양봉', '거래량 20일평균 1.3배 이상', '전일 저점 이탈 금지']
        meaning = '돌파확인형은 구조상 돌파가 보였다는 뜻이고, 매매는 눌림/안착/재양봉을 확인한 뒤 대응한다는 뜻입니다.'
    elif level == 'wait_confirm':
        conditions = ['구름상단 종가 돌파', '윗꼬리 축소', '다음날 구름상단 지지', '거래량 유지']
        meaning = '저항을 시험하는 구간이라 아직 매수 확정이 아니라 종가 돌파와 다음날 지지 확인이 먼저입니다.'
    elif level == 'holder_manage':
        conditions = ['신규 추격 금지', '보유자는 5일선/구름상단 이탈 관리', '과열 시 분할 익절', '눌림 재안착 후 추가 판단']
        meaning = '이미 한 박자 진행된 후행 구간이라 신규보다 보유자의 이탈선 관리와 분할 대응이 우선입니다.'
    elif level == 'avoid_chase':
        conditions = ['신규 매수 금지', '보유자는 분할 익절', '5일선 이탈 시 방어', '재안착 전까지 관찰']
        meaning = '좋아 보여도 타점이 늦었거나 위험 신호가 있어 신규 추격은 피하는 구간입니다.'
    else:
        conditions = ['거래량 보강', '양봉 마감', '5일선 재안착']
        meaning = '구조는 일부 보이지만 아직 매수보다 관찰과 확인이 우선인 자리입니다.'

    cautions = []
    if refine == '가짜수박주의':
        cautions.append('가짜수박주의')
    elif refine == '관찰수박':
        cautions.append('정제 추가 확인')
    cautions.extend(overheat)
    if level in ('wait_pullback', 'holder_manage'):
        cautions.append('돌파 직후 추격 부담')
    if cloud == '저항테스트':
        cautions.append('구름상단 안착 전 실패 가능')
    elif cloud == '저항돌파':
        cautions.append('구름상단 이탈 시 가짜돌파 가능')

    dedup_cautions = []
    for c in cautions:
        if c and c not in dedup_cautions:
            dedup_cautions.append(c)

    return {
        'structure': structure,
        'action': action,
        'level': level,
        'conditions': conditions,
        'cautions': dedup_cautions[:5],
        'meaning': meaning,
        'reasons': action_reasons,
    }


def build_trade_clarity_block(row, compact=True):
    v = build_trade_clarity_view(row)
    lines = [
        f"✅ 구조판정: {v['structure']}",
        f"⏳ 매매판정: {v['action']}",
    ]
    if v.get('conditions'):
        lines.append('📌 실행조건: ' + _tv_join(v['conditions'][:4]))
    if v.get('cautions'):
        lines.append('⚠️ 주의: ' + _tv_join(v['cautions'][:4]))
    lines.append('🧠 의미: ' + v['meaning'])
    if not compact and v.get('reasons'):
        lines.append('🧩 판정근거: ' + _tv_join(v['reasons']))
    return '\n'.join(lines)


def replace_ambiguous_trade_words(text):
    s = _tv_safe_str(text)
    replacements = [
        (
            '중간 구간으로 진입보다는 구름 상단 안착과 재돌파 확인이 필요하다.',
            '구조상 돌파/테스트는 보였지만 지금 매매는 추격이 아니라 구름상단·5일선 눌림 후 재양봉 확인입니다.',
        ),
        (
            '구름 상단 안착, 거래량 재유입, 재안착 신호가 나오는지 더 지켜봅니다.',
            '구름상단 지지 + 5일선 재안착 + 재양봉 + 거래량 재유입 중 2개 이상 확인될 때 대응합니다.',
        ),
        (
            '거래량 유지와 구름 상단 안착을 먼저 확인하고, 재돌파 또는 눌림 반등 때 대응합니다.',
            '돌파 자체보다 구름상단 지지와 눌림 후 재양봉이 핵심입니다. 그 확인 뒤 대응합니다.',
        ),
    ]
    for old, new in replacements:
        s = s.replace(old, new)
    s = s.replace('🧩 PASS 해석:', '🧩 구조 해석:')
    return s


def _recommendation_summary_line(row):
    """기존 추천 한 줄 결론을 매매판정 기준으로 더 명확하게 보정."""
    try:
        v = build_trade_clarity_view(row)
        if v['level'] == 'execute':
            return '조건부 실행 후보입니다. 단, 시가 추격보다 눌림 후 재양봉·거래량 유지 확인을 전제로 분할 대응합니다.'
        if v['level'] == 'wait_pullback':
            return '구조상 돌파는 확인됐지만 매매는 눌림 대기입니다. 구름상단/5일선 지지 후 재양봉이 핵심입니다.'
        if v['level'] == 'wait_confirm':
            return '저항을 시험하는 중입니다. 종가 돌파와 다음날 지지 확인 전까지는 돌파확인 대기입니다.'
        if v['level'] == 'holder_manage':
            return '후행 구간입니다. 신규 추격보다 보유자는 이탈선 관리, 신규는 눌림 재확인입니다.'
        if v['level'] == 'avoid_chase':
            return '위험/후행/가짜수박 요소가 있어 신규 추격 금지입니다. 재정비 후 다시 봅니다.'
        if v['action'] == '선취 관찰':
            return '저항 전 선취 관찰 후보입니다. 거래량·양봉·5일선 재안착 확인 후 접근합니다.'
    except Exception:
        pass
    if _BASE_RECOMMENDATION_SUMMARY_LINE:
        try:
            return replace_ambiguous_trade_words(_BASE_RECOMMENDATION_SUMMARY_LINE(row))
        except Exception:
            pass
    return '구조는 있으나 확인 신호가 더 필요합니다.'


def enrich_row_with_human_commentary(row):
    """기존 해석 블록에 매매관점 분리 블록을 추가."""
    if _BASE_ENRICH_ROW_WITH_HUMAN_COMMENTARY:
        try:
            base = _BASE_ENRICH_ROW_WITH_HUMAN_COMMENTARY(row)
        except Exception:
            base = _tv_as_dict(row).copy()
    else:
        base = _tv_as_dict(row).copy()

    try:
        view = build_trade_clarity_view(base)
        trade_block = build_trade_clarity_block(base, compact=True)
        base['구조판정'] = view['structure']
        base['매매판정'] = view['action']
        base['매매레벨'] = view['level']
        base['매매관점블록'] = trade_block
        old = replace_ambiguous_trade_words(str(base.get('interpretation_block', '') or '').strip())
        if trade_block and trade_block not in old:
            base['interpretation_block'] = (old + '\n' + trade_block).strip() if old else trade_block
        else:
            base['interpretation_block'] = old
        for key in ['easy_interpretation', 'action_summary', 'caution', 'need_check']:
            if key in base and isinstance(base.get(key), str):
                base[key] = replace_ambiguous_trade_words(base.get(key))
    except Exception as e:
        try:
            base['interpretation_block'] = str(base.get('interpretation_block', '') or '').strip() + f"\n⚠️ 매매관점 보정 실패: {e}"
        except Exception:
            pass
    return base


def append_interpretation_to_block(block, row):
    """모든 종목 카드 뒤에 구조판정/매매판정/실행조건을 중복 없이 추가."""
    if not isinstance(block, str):
        block = str(block or '')
    block = replace_ambiguous_trade_words(block)
    enriched = enrich_row_with_human_commentary(row)
    extra = str(enriched.get('interpretation_block', '') or '').strip()
    trade_block = str(enriched.get('매매관점블록', '') or '').strip()

    parts = []
    for src in [extra, trade_block]:
        for ln in [x.strip() for x in str(src or '').splitlines() if x.strip()]:
            if ln not in block and ln not in parts:
                parts.append(ln)

    if not parts:
        return block.rstrip()
    return block.rstrip() + '\n\n' + '\n'.join(parts) + '\n'


def build_integrated_stock_block(block, row):
    return append_interpretation_to_block(block, row)


def _normalize_judge_for_display(judge):
    j = _tv_safe_str(judge)
    if '즉시 대응' in j or '조건부 실행' in j:
        return '조건부 실행'
    if '돌파 확인' in j or '돌파확인' in j:
        return '돌파확인 대기'
    if '눌림' in j:
        return '눌림 대기'
    if '보유자' in j:
        return '보유자 대응'
    if '추격 금지' in j:
        return '추격 금지'
    if '선취' in j:
        return '선취 관찰'
    return j


def _format_stock_item(idx, item):
    """압축 블록의 판정 문구를 더 명확하게 표시."""
    code = f"({item.code})" if getattr(item, 'code', '') else ''
    judge_raw = getattr(item, 'judge', '')
    judge = _normalize_judge_for_display(judge_raw)
    judge_part = f" / 매매:{judge}" if judge else ''
    status = f" / 상태:{item.status}" if getattr(item, 'status', '') else ''
    reason = replace_ambiguous_trade_words(getattr(item, 'reason', ''))
    if judge == '돌파확인 대기':
        reason += ' | 돌파확인형은 구조명이며, 실행은 안착/눌림 확인 뒤'
    return f"{idx}) {item.name}{code}{judge_part}{status}\n   → {reason}"


def build_trading_view_compressed(report_text):
    """기존 압축 블록에 용어정리와 애매문구 보정을 추가."""
    try:
        if _BASE_BUILD_TRADING_VIEW_COMPRESSED:
            out = _BASE_BUILD_TRADING_VIEW_COMPRESSED(report_text)
        else:
            out = ''
    except Exception as e:
        out = f"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n🎯 [오늘의 매매관점 압축]\n- 생성 실패: {e}\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"

    out = replace_ambiguous_trade_words(out)
    guide = (
        "\n\n📘 용어정리\n"
        "- 구조판정: 차트가 어디까지 왔는지입니다. 예: 돌파확인형, 저항테스트형.\n"
        "- 매매판정: 지금 행동입니다. 예: 조건부 실행, 눌림 대기, 보유자 대응, 추격 금지.\n"
        "- 돌파확인형 + 눌림대기 = 이미 저항은 넘었지만 현재가 추격은 피하고, 구름상단/5일선 지지 후 재양봉을 기다린다는 뜻입니다."
    )
    if '📘 용어정리' not in out:
        out = out.rstrip() + guide
    return out


