def _news_block_keywords_for_stock(name: str, code: str = ''):
    blocks, noise = ([], [])
    if _BASE_NEWS_BLOCK_KEYWORDS_FOR_STOCK:
        try:
            blocks, noise = _BASE_NEWS_BLOCK_KEYWORDS_FOR_STOCK(name, code)
        except Exception:
            blocks, noise = [], []
    name_s = str(name or '')
    code_s = str(code or '').zfill(6) if code else ''
    if code_s in ('090430', '002790') or '아모레' in name_s:
        blocks += [
            '변압기', '전력기기', '전력설비', 'AI전력', '전선', '중전기', '구리',
            '효성중공업', 'HD현대일렉트릭', 'LS ELECTRIC', '일진전기', '제룡전기', '대한전선',
            '삼성전자', 'SK하이닉스', '하이닉스', 'HBM', 'SOXX', 'SMH', '엔비디아',
            '조선', '방산', '정유', '원유', '해운', '교육부', '논문', '김건희', '도이치모터스 의혹'
        ]
    return list(dict.fromkeys(blocks)), list(dict.fromkeys(noise))


def _is_stock_news_matched(name: str, code: str, title: str, summary: str = '', source: str = '') -> bool:
    raw = f"{title or ''} {summary or ''}"
    text = _news_compact_text(raw) if '_news_compact_text' in globals() else _tv_safe_str(raw).replace(' ', '').lower()
    if not text:
        return False
    blocks, _noise = _news_block_keywords_for_stock(name, code)
    for b in blocks:
        bb = _news_compact_text(b) if '_news_compact_text' in globals() else str(b).replace(' ', '').lower()
        if bb and bb in text:
            try:
                log_debug(f"📰 뉴스 오매칭 V4 차단({name}): {str(title)[:45]} | block={b}")
            except Exception:
                pass
            return False
    if _BASE_IS_STOCK_NEWS_MATCHED:
        try:
            return bool(_BASE_IS_STOCK_NEWS_MATCHED(name, code, title, summary=summary, source=source))
        except Exception:
            pass
    aliases = []
    try:
        aliases = _news_aliases_for_stock(name, code)
    except Exception:
        aliases = [name]
    for a in aliases:
        aa = _news_compact_text(a) if '_news_compact_text' in globals() else str(a).replace(' ', '').lower()
        if aa and aa in text:
            return True
    return False

