def _acc_safe_float(x, default=0.0):
    try:
        if x is None:
            return default
        if isinstance(x, str):
            x = x.replace(',', '').strip()
            if x == '':
                return default
        return float(x)
    except Exception:
        return default


def _acc_col(df, *names):
    for name in names:
        if name in df.columns:
            return name
    return None


def _acc_price_cols(df):
    return {
        'open': _acc_col(df, 'Open', '시가'),
        'high': _acc_col(df, 'High', '고가'),
        'low': _acc_col(df, 'Low', '저가'),
        'close': _acc_col(df, 'Close', '종가'),
        'volume': _acc_col(df, 'Volume', '거래량'),
    }




