def _v5_trade_safe_str(x, default=''):
    try:
        if x is None:
            return default
        return str(x).strip()
    except Exception:
        return default


def _v5_trade_replace_ambiguous(text):
    s = _v5_trade_safe_str(text)
    try:
        if 'replace_ambiguous_trade_words' in globals():
            s = replace_ambiguous_trade_words(s)
    except Exception:
        pass
    s = s.replace(
        '중간 구간으로 진입보다는 구름 상단 안착과 재돌파 확인이 필요하다.',
        '구조상 돌파/테스트는 보였지만 지금 매매는 추격이 아니라 구름상단·5일선 눌림 후 재양봉 확인입니다.'
    )
    s = s.replace(
        '구름 상단 안착, 거래량 재유입, 재안착 신호가 나오는지 더 지켜봅니다.',
        '구름상단 지지 + 5일선 재안착 + 재양봉 + 거래량 재유입 중 2개 이상 확인될 때 대응합니다.'
    )
    return s


def _v5_trade_block(row):
    try:
        if 'build_trade_clarity_block' in globals():
            block = build_trade_clarity_block(row, compact=True)
            if '✅ 구조판정' in str(block):
                return str(block).strip()
    except Exception:
        pass

    # 폴백: 최소한 구조판정/매매판정은 무조건 출력
    try:
        data = row.to_dict() if hasattr(row, 'to_dict') else dict(row or {})
    except Exception:
        data = {}
    text = ' '.join(str(data.get(k, '') or '') for k in [
        '수박최종상태', '수박상태명', '상태', '최종상태', '추천단계', '유형',
        '저항구름상태', '저항구름태그', '수박정제태그', 'final_label', '판정'
    ])
    structure = '구조관찰형'
    if '저항돌파' in text:
        structure = '저항구름 돌파확인형'
    elif '저항테스트' in text:
        structure = '저항구름 돌파테스트형'
    elif '저항전' in text:
        structure = '저항 전 선취관찰형'
    elif 'Blue-2' in text or '재점화' in text:
        structure = '재점화 확인형'

    action = '관찰'
    if '추격 금지' in text or '과열후행형' in text or '가짜수박주의' in text:
        action = '추격 금지' if '과열' in text else '확인 대기'
    elif '후행' in text or '보유자 대응' in text:
        action = '보유자 대응'
    elif '눌림' in text or '저항돌파' in text:
        action = '눌림 대기'
    elif '선취' in text or '초입' in text:
        action = '선취 관찰'

    return '\n'.join([
        f'✅ 구조판정: {structure}',
        f'⏳ 매매판정: {action}',
        '📌 실행조건: 구름상단 지지 / 5일선 재안착 / 재양봉 / 거래량 재유입',
        '⚠️ 주의: 돌파 직후 추격 부담 / 구름상단 이탈 시 가짜돌파 가능',
        '🧠 의미: 구조판정은 차트 위치이고, 매매판정은 지금 행동입니다. 돌파확인형이어도 매매는 눌림 확인 후 대응할 수 있습니다.',
    ])


def _v5_append_trade_block_once(text, row):
    out = _v5_trade_replace_ambiguous(text)
    tb = _v5_trade_block(row)
    if tb and '✅ 구조판정' not in out:
        out = out.rstrip() + '\n\n' + tb.strip()
    return out.rstrip() + '\n'


def enrich_row_with_human_commentary(row):
    if _V5_BASE_ENRICH_ROW_WITH_HUMAN_COMMENTARY:
        try:
            base = _V5_BASE_ENRICH_ROW_WITH_HUMAN_COMMENTARY(row)
        except Exception:
            try:
                base = row.to_dict() if hasattr(row, 'to_dict') else dict(row or {})
            except Exception:
                base = {}
    else:
        try:
            base = row.to_dict() if hasattr(row, 'to_dict') else dict(row or {})
        except Exception:
            base = {}

    try:
        tb = _v5_trade_block(base)
        if 'build_trade_clarity_view' in globals():
            view = build_trade_clarity_view(base)
            base['구조판정'] = view.get('structure', '')
            base['매매판정'] = view.get('action', '')
            base['매매레벨'] = view.get('level', '')
        base['매매관점블록'] = tb
        old = _v5_trade_replace_ambiguous(base.get('interpretation_block', ''))
        if tb and '✅ 구조판정' not in old:
            base['interpretation_block'] = (old.rstrip() + '\n' + tb).strip() if old else tb
        else:
            base['interpretation_block'] = old
        for key in ['easy_interpretation', 'action_summary', 'caution', 'need_check']:
            if isinstance(base.get(key), str):
                base[key] = _v5_trade_replace_ambiguous(base.get(key))
    except Exception as _v5_e:
        try:
            base['interpretation_block'] = (str(base.get('interpretation_block', '') or '').strip() + f'\n⚠️ 매매관점 V5 보정 실패: {_v5_e}').strip()
        except Exception:
            pass
    return base


