    out = _v5_trade_replace_ambiguous(out)
    guide = (
        '\n\n📘 용어정리\n'
        '- 구조판정: 차트가 어디까지 왔는지입니다. 예: 돌파확인형, 저항테스트형.\n'
        '- 매매판정: 지금 행동입니다. 예: 조건부 실행, 눌림 대기, 보유자 대응, 추격 금지.\n'
        '- 돌파확인형 + 눌림대기 = 이미 저항은 넘었지만 현재가 추격은 피하고, 구름상단/5일선 지지 후 재양봉을 기다린다는 뜻입니다.'
    )
    if '📘 용어정리' not in out:
        out = out.rstrip() + guide
    return out

