print("✅ TRADE_CLARITY_V8_8_BLUE_DOTTED_LINE_ACTIVE LOADED")
print("✅ EXPECT_V8_8 = 🔵 파란점선 기준가 1개 / 영역출력 제거 / 접촉·안착·과이격 분기")


def _v88_num(v, default=0.0):
    try:
        if '_v86_num' in globals():
            return _v86_num(v, default)
    except Exception:
        pass
    try:
        if v is None:
            return default
        try:
            if pd.isna(v):
                return default
        except Exception:
            pass
        s = str(v).replace(',', '').replace('%', '').strip()
        if not s:
            return default
        import re as _re
        m = _re.search(r'-?\d+(?:\.\d+)?', s)
        return float(m.group(0)) if m else default
    except Exception:
        return default


def _v88_int(v, default=0):
    try:
        return int(round(_v88_num(v, default)))
    except Exception:
        return default


def _v88_price(v):
    try:
        if '_v86_price' in globals():
            return _v86_price(v)
    except Exception:
        pass
    n = _v88_int(v, 0)
    return f"{n:,}" if n > 0 else '-'


def _v88_row_dict(row):
    try:
        if '_v86_row_dict' in globals():
            return _v86_row_dict(row)
    except Exception:
        pass
    try:
        if isinstance(row, dict):
            return dict(row)
        if hasattr(row, 'to_dict'):
            return row.to_dict()
        return dict(row or {})
    except Exception:
        return {}


def _v88_get_current_price(row_or_dict):
    d = _v88_row_dict(row_or_dict)
    for key in (
        '현재가', '현재가격', '현재가_raw', 'current_price', 'blue_current_price',
        'price', 'Close', 'close', '종가', '현재종가', 'last_close', 'Last', 'last'
    ):
        val = _v88_num(d.get(key), 0.0)
        if val > 0:
            return val
    return 0.0


def _v88_price_cols(df):
    try:
        if '_v85_price_cols' in globals():
            return _v85_price_cols(df)
    except Exception:
        pass
    def pick(*names):
        try:
            for n in names:
                if n in df.columns:
                    return n
        except Exception:
            return ''
        return ''
    return {
        'high': pick('High', '고가', 'high'),
        'low': pick('Low', '저가', 'low'),
        'close': pick('Close', '종가', 'close'),
        'open': pick('Open', '시가', 'open'),
    }


def _v88_select_blue_line(cur, low, high):
    """넓은 파란타점 영역을 실전용 단일 파란점선으로 축소한다.
    - 현재가 아래: 회복해야 하는 첫 기준선 = 영역 하단
    - 현재가 위: 눌림 때 확인할 가까운 지지선 = 영역 상단
    - 영역 내부: 현재가에 더 가까운 경계선을 기준선으로 선택
    """
    low = _v88_num(low, 0.0)
    high = _v88_num(high, 0.0)
    cur = _v88_num(cur, 0.0)
    if low <= 0 and high <= 0:
        return 0.0, '산출불가'
    if low <= 0:
        return high, '단일상단'
    if high <= 0:
        return low, '단일하단'
    if high < low:
        low, high = high, low
    if cur <= 0:
        return low, '현재가확인불가'
    if cur < low:
        return low, '아래'
    if cur > high:
        return high, '위'
    # 현재가가 구간 안에 있을 때는 원본 파란점선처럼 현재가와 맞닿는 가까운 선만 남긴다.
    if abs(cur - low) <= abs(high - cur):
        return low, '접촉하단'
    return high, '접촉상단'


def _v88_blue_state_and_action(cur, line):
    cur = _v88_num(cur, 0.0)
    line = _v88_num(line, 0.0)
    if line <= 0:
        return '산출불가', '파란점선 산출 실패, 소파동/중파동 박스를 먼저 확인'
    if cur <= 0:
        return '현재가 확인불가', '기준선만 참고하고 현재가 수집 상태 확인'
    gap = ((cur / line) - 1.0) * 100.0 if line > 0 else 0.0
    if gap < -1.0:
        return '아래', '회복·종가 안착 전까지 확인 대기'
    if abs(gap) <= 1.0:
        return '접촉', '오늘 판단선 접촉, 종가 유지와 다음 봉 저점 보존 확인'
    if gap <= 3.0:
        return '위안착', '점선 위 안착, 눌림 때 지지 확인'
    if gap <= 7.0:
        return '위확장', '점선 위 확장, 신규 추격보다 눌림 대기'
    return '과이격', '점선과 이격 큼, 신규 추격 금지 성격'


def _v88_blue_line_text(row_or_dict, low=None, high=None):
    d = _v88_row_dict(row_or_dict)
    cur = _v88_get_current_price(d)
    preset = _v88_num(d.get('파란점선기준가') or d.get('blue_line_price'), 0.0)
    if preset > 0:
        line = preset
    else:
        zlow = _v88_num(low if low is not None else d.get('파란타점영역하단') or d.get('blue_zone_low'), 0.0)
        zhigh = _v88_num(high if high is not None else d.get('파란타점영역상단') or d.get('blue_zone_high'), 0.0)
        line, _ = _v88_select_blue_line(cur, zlow, zhigh)
    if line <= 0:
        return '🔵 파란점선: 산출불가 | 소파동 박스 확인 필요'
    if cur > 0:
        gap = ((cur / line) - 1.0) * 100.0 if line > 0 else 0.0
        state, action = _v88_blue_state_and_action(cur, line)
        return f"🔵 파란점선: {_v88_price(line)} | 현재가 {_v88_price(cur)} | 이격 {gap:+.1f}% | {state} | {action}"
    return f"🔵 파란점선: {_v88_price(line)} | 현재가 확인불가 | 기준선만 참고"


def _v88_wave_interp_from_row(row_or_dict):
    d = _v88_row_dict(row_or_dict)
    try:
        cur = _v88_get_current_price(d)
        line = _v88_num(d.get('파란점선기준가') or d.get('blue_line_price'), 0.0)
        if line <= 0:
            zlow = _v88_num(d.get('파란타점영역하단') or d.get('blue_zone_low'), 0.0)
            zhigh = _v88_num(d.get('파란타점영역상단') or d.get('blue_zone_high'), 0.0)
            line, _ = _v88_select_blue_line(cur, zlow, zhigh)
        if cur > 0 and line > 0:
            gap = ((cur / line) - 1.0) * 100.0
            if gap < -1.0:
                return '파란점선 아래라 먼저 회복·종가 안착 확인이 필요합니다'
            if abs(gap) <= 1.0:
                return '파란점선 접촉 구간입니다. 돌파보다 종가 유지와 다음 봉 저점 보존을 확인합니다'
            if 1.0 < gap <= 3.0:
                return '파란점선 위 안착 초기입니다. 눌림 때 점선 지지 여부를 우선 확인합니다'
            if gap > 7.0:
                return '파란점선과 이격이 커져 신규 추격보다 눌림 재접근이 유리합니다'
    except Exception:
        pass
    try:
        if '_v86_wave_interp_from_row' in globals():
            return _v86_wave_interp_from_row(d)
    except Exception:
        pass
    return '파란점선 기준으로 회복·접촉·안착·과이격을 나누어 확인합니다'


try:
    _V88_BASE_BUILD_WAVE_LEVELS = build_wave_levels
except Exception:
    _V88_BASE_BUILD_WAVE_LEVELS = None


def build_wave_levels(df, accum_info=None, lookback=60):
    try:
        out = _V88_BASE_BUILD_WAVE_LEVELS(df, accum_info, lookback) if _V88_BASE_BUILD_WAVE_LEVELS else {}
    except Exception:
        out = {}
    try:
        if out is None:
            out = {}
        if not isinstance(out, dict):
            out = dict(out)
    except Exception:
        out = {}
    try:
        cur = 0.0
        if df is not None and len(df) > 0:
            cols = _v88_price_cols(df)
            ccol = cols.get('close') or ''
            if ccol and ccol in df.columns:
                cur = _v88_num(df.iloc[-1][ccol], 0.0)
        low = _v88_num(out.get('blue_zone_low'), 0.0)
        high = _v88_num(out.get('blue_zone_high'), 0.0)
        # 구간값이 없는 예외 상황에서는 소파동 박스 55/92%를 보조 산출한다.
        if (low <= 0 or high <= 0) and _v88_num(out.get('small_low'), 0.0) > 0 and _v88_num(out.get('small_high'), 0.0) > 0:
            sl = _v88_num(out.get('small_low'), 0.0)
            sh = _v88_num(out.get('small_high'), 0.0)
            if sh > sl:
                low = sl + (sh - sl) * 0.55
                high = sl + (sh - sl) * 0.92
                out['blue_zone_low'] = round(low, 2)
                out['blue_zone_high'] = round(high, 2)
        line, source = _v88_select_blue_line(cur, low, high)
        state, action = _v88_blue_state_and_action(cur, line)
        gap = ((cur / line) - 1.0) * 100.0 if cur > 0 and line > 0 else 0.0
        out['current_price'] = round(cur, 2) if cur > 0 else out.get('current_price', 0)
        out['blue_line_price'] = round(line, 2) if line > 0 else 0.0
        out['blue_line_state'] = state
        out['blue_line_gap_pct'] = round(gap, 2)
        out['blue_line_action'] = action
        out['blue_line_source'] = source
        out['debug_note'] = (str(out.get('debug_note', '') or '').strip() + ' / v8.8_blue_line').strip(' /')
    except Exception as e:
        try:
            out['debug_note'] = (str(out.get('debug_note', '') or '').strip() + f' / v8.8_blue_line_error:{e}').strip(' /')
        except Exception:
            pass
    return out


def _v88_wave_line(prefix, low, high, pct, label, direction, angle, slope):
    try:
        if '_v86_wave_line' in globals():
            return _v86_wave_line(prefix, low, high, pct, label, direction, angle, slope)
    except Exception:
        pass
    if _v88_num(low, 0) <= 0 or _v88_num(high, 0) <= 0:
        return f"{prefix}: 산출불가"
    line = f"{prefix}: 박스 {_v88_price(low)}~{_v88_price(high)}"
    if _v88_num(pct, -999) > -900:
        line += f" | 위치 {_v88_num(pct, 0):.0f}%({label or ''})"
    if direction:
        line += f" | {direction} {_v88_num(angle, 0):+.1f}°({_v88_num(slope, 0):+.2f}%/봉)"
    return line


def _v88_wave_lines_from_row(row, include_debug=False):
    d = _v88_row_dict(row)
    lines = []
    small_low = _v88_num(d.get('소파동저점'), 0)
    small_high = _v88_num(d.get('소파동전고점'), 0)
    mid_low = _v88_num(d.get('중파동저점'), 0)
    mid_high = _v88_num(d.get('중파동전고점'), 0)

    if small_low > 0 and small_high > 0:
        lines.append(_v88_wave_line(
            '〰️ 소파동', small_low, small_high,
            d.get('소파동위치퍼센트', 0), d.get('소파동위치권', ''),
            d.get('소파동박스방향', ''), d.get('소파동각도', 0), d.get('소파동기울기', 0)
        ))
    else:
        note = str(d.get('소파동디버그노트', '') or '').strip()
        lines.append('〰️ 소파동: 산출불가' + (f' | {note}' if note else ''))

    if mid_low > 0 and mid_high > 0:
        lines.append(_v88_wave_line(
            '📶 중파동', mid_low, mid_high,
            d.get('중파동위치퍼센트', 0), d.get('중파동위치권', ''),
            d.get('중파동박스방향', ''), d.get('중파동각도', 0), d.get('중파동기울기', 0)
        ))
    else:
        note = str(d.get('소파동디버그노트', '') or '').strip()
        lines.append('📶 중파동: 산출불가' + (f' | {note}' if note else ''))

    lines.append(_v88_blue_line_text(d))
    lines.append(f"🧭 파동해석: {_v88_wave_interp_from_row(d)}")

    if include_debug:
        lines.append(
            "🧪 파동디버그: "
            f"small={_v88_price(small_low)}~{_v88_price(small_high)} | "
            f"mid={_v88_price(mid_low)}~{_v88_price(mid_high)} | "
            f"blue_line={_v88_price(d.get('파란점선기준가') or d.get('blue_line_price'))} | "
            f"old_zone={_v88_price(d.get('파란타점영역하단') or d.get('blue_zone_low'))}~{_v88_price(d.get('파란타점영역상단') or d.get('blue_zone_high'))} | "
            f"note={str(d.get('소파동디버그노트', '') or '-') }"
        )
    return lines


def _v88_patch_existing_wave_text(text, row):
    try:
        import re as _re
        out = str(text or '')
        d = _v88_row_dict(row)
        blue_line = _v88_blue_line_text(d)
        interp_line = f"🧭 파동해석: {_v88_wave_interp_from_row(d)}"

        if '🔵 파란타점' in out or '🔵 파란점선' in out:
            out = _re.sub(r'🔵 파란(?:타점|점선)[^\n]*', blue_line, out, count=1)
        if '🧭 파동해석:' in out:
            out = _re.sub(r'🧭 파동해석:[^\n]*', interp_line, out, count=1)
        elif '🔵 파란점선' in out:
            out = _re.sub(r'(🔵 파란점선[^\n]*)(\n)', r'\1\2' + interp_line + '\n', out, count=1)
        elif '📶 중파동:' in out:
            out = _re.sub(r'(📶 중파동:[^\n]*)(\n)', r'\1\2' + blue_line + '\n' + interp_line + '\n', out, count=1)
        return out
    except Exception:
        return str(text or '')


def _v88_insert_or_patch_wave_text(text, row):
    out = str(text or '')
    try:
        if '〰️ 소파동:' in out or '📶 중파동:' in out or '🔵 파란타점' in out or '🔵 파란점선' in out:
            return _v88_patch_existing_wave_text(out, row)
        wave_text = '\n'.join(_v88_wave_lines_from_row(row, include_debug=False))
        if '\n✅ 최종 판정:' in out:
            out = out.replace('\n✅ 최종 판정:', '\n' + wave_text + '\n✅ 최종 판정:', 1)
        elif '\n🧮 점수 해석:' in out:
            out = out.replace('\n🧮 점수 해석:', '\n' + wave_text + '\n🧮 점수 해석:', 1)
        elif '\n✅ 구조판정:' in out:
            out = out.replace('\n✅ 구조판정:', '\n' + wave_text + '\n\n✅ 구조판정:', 1)
        elif '✅ 구조판정:' in out:
            out = out.replace('✅ 구조판정:', wave_text + '\n\n✅ 구조판정:', 1)
        else:
            out = out.rstrip() + '\n' + wave_text
        return out
    except Exception as e:
        return str(out).rstrip() + f"\n🌀 파동진단 표시 실패 | {e}"


