def _v89_num(v, default=0.0):
    try:
        return _v88_num(v, default)
    except Exception:
        try:
            if v is None:
                return default
            s = str(v).replace(',', '').replace('%', '').strip()
            if not s:
                return default
            import re as _re
            m = _re.search(r'-?\d+(?:\.\d+)?', s)
            return float(m.group(0)) if m else default
        except Exception:
            return default


def _v89_int(v, default=0):
    try:
        return int(round(_v89_num(v, default)))
    except Exception:
        return default


def _v89_price(v):
    try:
        return _v88_price(v)
    except Exception:
        n = _v89_int(v, 0)
        return f"{n:,}" if n > 0 else '-'


def _v89_row_dict(row):
    try:
        return _v88_row_dict(row)
    except Exception:
        try:
            if isinstance(row, dict):
                return dict(row)
            if hasattr(row, 'to_dict'):
                return row.to_dict()
            return dict(row or {})
        except Exception:
            return {}


# V8.8 함수를 같은 이름으로 재정의한다. _v88_blue_line_text/build_wave_levels가 런타임에 이 함수를 다시 참조한다.
def _v88_blue_state_and_action(cur, line):
    cur = _v89_num(cur, 0.0)
    line = _v89_num(line, 0.0)
    if line <= 0:
        return '산출불가', '파란점선 산출 실패, 소파동/중파동 박스를 먼저 확인'
    if cur <= 0:
        return '현재가 확인불가', '기준선만 참고하고 현재가 수집 상태 확인'
    gap = ((cur / line) - 1.0) * 100.0 if line > 0 else 0.0
    if gap < -1.0:
        return '아래', '회복·종가 안착 전까지 확인 대기'
    if abs(gap) <= 1.0:
        return '접촉', '오늘 판단선 접촉, 종가 유지와 다음 봉 저점 보존 확인'
    if gap <= 3.0:
        return '위안착', '점선 위 안착, 눌림 때 지지 확인'
    if gap <= 6.0:
        return '위확장', '점선 위 확장, 신규 추격보다 눌림 대기'
    return '과이격', '점선과 이격 큼, 신규 추격 금지 성격'


def _v89_blue_line_meta(row_or_dict):
    """파란점선 기준가/이격/상태를 행 기준으로 재계산한다."""
    d = _v89_row_dict(row_or_dict)
    try:
        cur = _v88_get_current_price(d) if '_v88_get_current_price' in globals() else _v89_num(d.get('현재가') or d.get('Close') or d.get('종가'), 0.0)
    except Exception:
        cur = _v89_num(d.get('현재가') or d.get('Close') or d.get('종가'), 0.0)
    line = _v89_num(d.get('파란점선기준가') or d.get('blue_line_price'), 0.0)
    source = 'preset'
    if line <= 0:
        low = _v89_num(d.get('파란타점영역하단') or d.get('blue_zone_low'), 0.0)
        high = _v89_num(d.get('파란타점영역상단') or d.get('blue_zone_high'), 0.0)
        try:
            line, source = _v88_select_blue_line(cur, low, high)
        except Exception:
            line, source = 0.0, '산출불가'
    state, action = _v88_blue_state_and_action(cur, line)
    gap = ((cur / line) - 1.0) * 100.0 if cur > 0 and line > 0 else 0.0
    return {
        'cur': cur,
        'line': line,
        'gap': gap,
        'state': state,
        'action': action,
        'source': source,
        'valid': bool(cur > 0 and line > 0),
    }


def _v89_blue_status_text(row_or_dict, compact=False):
    m = _v89_blue_line_meta(row_or_dict)
    if not m.get('valid'):
        return '파란점선: 산출불가'
    if compact:
        return f"파란점선 {m['state']} {m['gap']:+.1f}%"
    return f"파란점선:{_v89_price(m['line'])} / {m['state']} {m['gap']:+.1f}%"


