def _v89_is_hard_trade_level(view):
    try:
        return str(view.get('level', '')) in ('avoid_chase', 'holder_manage') or str(view.get('action', '')) in ('추격 금지', '보유자 대응')
    except Exception:
        return False


def _v89_apply_blue_filter_to_view(view, row):
    """기존 구조판정은 유지하되 매매판정만 파란점선 기준으로 재정렬한다."""
    v = dict(view or {})
    meta = _v89_blue_line_meta(row)
    if not meta.get('valid'):
        return v

    state = meta.get('state', '')
    gap = float(meta.get('gap', 0.0) or 0.0)
    blue_reason = f"파란점선 {state} {gap:+.1f}%"
    reasons = list(v.get('reasons') or [])
    if blue_reason not in reasons:
        reasons.append(blue_reason)
    cautions = list(v.get('cautions') or [])

    # 보유자 대응/추격금지는 이미 더 보수적인 판정이므로 유지한다. 단, 파란점선 설명만 추가한다.
    hard = _v89_is_hard_trade_level(v)

    if state == '과이격' or gap >= 6.0:
        v['action'] = '추격 금지'
        v['level'] = 'avoid_chase'
        v['conditions'] = ['신규 매수 금지', '보유자는 분할 익절', '파란점선 재접근 전까지 관찰', '5일선 이탈 시 방어']
        v['meaning'] = '파란점선과 현재가 이격이 커져 신규 추격보다 눌림 재접근을 기다리는 자리입니다.'
        if '파란점선 과이격' not in cautions:
            cautions.append('파란점선 과이격')
    elif not hard and state == '아래':
        v['action'] = '회복 대기'
        v['level'] = 'wait_blue_reclaim'
        v['conditions'] = ['파란점선 회복', '종가 안착', '다음 봉 저점 보존', '거래량 유지']
        v['meaning'] = '파란점선 아래에서는 돌파 확인보다 회복과 종가 안착 확인이 먼저입니다.'
        if '파란점선 아래' not in cautions:
            cautions.append('파란점선 아래')
    elif not hard and state == '접촉':
        v['action'] = '종가 유지 확인'
        v['level'] = 'wait_blue_hold'
        v['conditions'] = ['파란점선 종가 유지', '다음 봉 저점 보존', '윗꼬리 축소', '거래량 유지']
        v['meaning'] = '파란점선 접촉 구간이라 돌파 매수보다 종가 유지와 다음 봉 저점 보존 확인이 핵심입니다.'
    elif not hard and state == '위안착':
        # 이미 조건부 실행으로 확정된 경우는 유지하되, 일반 돌파확인은 눌림 지지 확인으로 낮춘다.
        if str(v.get('level', '')) != 'execute':
            v['action'] = '눌림 대기'
            v['level'] = 'wait_blue_support'
        v['conditions'] = ['파란점선 눌림 지지', '5일선 훼손 없음', '눌림 후 재양봉', '거래량 재유입']
        v['meaning'] = '파란점선 위 안착 초기라 추격보다 눌림 때 점선 지지 여부를 확인하는 자리입니다.'
    elif not hard and state == '위확장':
        v['action'] = '눌림 대기'
        v['level'] = 'wait_blue_pullback'
        v['conditions'] = ['신규 추격 자제', '파란점선 또는 5일선 눌림', '눌림 후 재양봉', '거래량 재유입']
        v['meaning'] = '파란점선 위로 확장된 상태라 신규 추격보다 눌림 재접근이 유리합니다.'
        if '파란점선 위확장' not in cautions:
            cautions.append('파란점선 위확장')

    # hard 유지 시에도 설명 문구에 파란점선 상태를 덧붙인다.
    if hard and state in ('아래', '접촉', '위안착', '위확장', '과이격'):
        if state == '아래' and '파란점선 회복 전' not in cautions:
            cautions.append('파란점선 회복 전')
        elif state == '접촉' and '파란점선 접촉' not in cautions:
            cautions.append('파란점선 접촉')
        elif state in ('위확장', '과이격') and '파란점선 추격부담' not in cautions:
            cautions.append('파란점선 추격부담')

    # 중복 제거
    dedup_cautions = []
    for c in cautions:
        if c and c not in dedup_cautions:
            dedup_cautions.append(c)
    v['cautions'] = dedup_cautions[:6]
    v['reasons'] = reasons[:8]
    v['blue_line_state'] = state
    v['blue_line_gap_pct'] = round(gap, 2)
    v['blue_line_price'] = meta.get('line', 0.0)
    return v


def build_trade_clarity_view(row):
    if _V89_BASE_BUILD_TRADE_CLARITY_VIEW:
        try:
            base = _V89_BASE_BUILD_TRADE_CLARITY_VIEW(row)
        except Exception:
            base = {'structure': '구조관찰형', 'action': '관찰', 'level': 'observe', 'conditions': [], 'cautions': [], 'meaning': '구조 확인이 더 필요합니다.', 'reasons': []}
    else:
        base = {'structure': '구조관찰형', 'action': '관찰', 'level': 'observe', 'conditions': [], 'cautions': [], 'meaning': '구조 확인이 더 필요합니다.', 'reasons': []}
    return _v89_apply_blue_filter_to_view(base, row)


def decide_final_label(row) -> str:
    try:
        base = _V89_BASE_DECIDE_FINAL_LABEL(row) if _V89_BASE_DECIDE_FINAL_LABEL else '관망'
    except Exception:
        base = '관망'
    meta = _v89_blue_line_meta(row)
    if not meta.get('valid'):
        return base
    state = meta.get('state', '')
    gap = float(meta.get('gap', 0.0) or 0.0)
    base_s = str(base or '')
    # 이미 후행/보유/추격금지면 유지. 과이격만 강제로 추격금지.
    if state == '과이격' or gap >= 6.0:
        return '추격 금지'
    if any(k in base_s for k in ('추격 금지', '보유자 대응')):
        return base_s
    if state == '아래':
        return '회복 대기'
    if state == '접촉':
        return '종가 유지 확인'
    if state == '위확장':
        return '눌림 대기'
    if state == '위안착' and base_s in ('돌파 확인', '즉시 관찰', '관망'):
        return '눌림 대기'
    return base_s


def _recommendation_summary_line(row):
    try:
        meta = _v89_blue_line_meta(row)
        if meta.get('valid'):
            st = meta.get('state')
            gap = float(meta.get('gap', 0.0) or 0.0)
            if st == '아래':
                return f"파란점선 아래({gap:+.1f}%)입니다. 돌파 확인보다 회복·종가 안착 확인이 먼저입니다."
            if st == '접촉':
                return f"파란점선 접촉({gap:+.1f}%) 구간입니다. 종가 유지와 다음 봉 저점 보존을 확인합니다."
            if st == '위안착':
                return f"파란점선 위 안착 초기({gap:+.1f}%)입니다. 눌림 때 점선 지지 여부가 핵심입니다."
            if st == '위확장':
                return f"파란점선 위확장({gap:+.1f}%) 상태입니다. 신규 추격보다 눌림 재접근이 유리합니다."
            if st == '과이격' or gap >= 6.0:
                return f"파란점선 과이격({gap:+.1f}%)입니다. 신규 추격 금지 성격으로 봅니다."
    except Exception:
        pass
    if _V89_BASE_RECOMMENDATION_SUMMARY_LINE:
        try:
            return _V89_BASE_RECOMMENDATION_SUMMARY_LINE(row)
        except Exception:
            pass
    return '구조는 있으나 확인 신호가 더 필요합니다.'


