def _v8_reason(row):
    try:
        meta = _v89_blue_line_meta(row)
        if meta.get('valid'):
            state = meta.get('state')
            gap = float(meta.get('gap', 0.0) or 0.0)
            if state == '아래':
                return f"파란점선 아래({gap:+.1f}%)라 회복·종가 안착 확인 전까지 매수 보류"
            if state == '접촉':
                return f"파란점선 접촉({gap:+.1f}%) 구간, 종가 유지와 다음 봉 저점 보존 확인"
            if state == '위안착':
                return f"파란점선 위 안착({gap:+.1f}%), 눌림 때 점선 지지 확인"
            if state == '위확장':
                return f"파란점선 위확장({gap:+.1f}%), 신규 추격보다 눌림 대기"
            if state == '과이격' or gap >= 6.0:
                return f"파란점선 과이격({gap:+.1f}%), 신규 추격 금지"
    except Exception:
        pass
    if _V89_BASE_V8_REASON:
        try:
            return _V89_BASE_V8_REASON(row)
        except Exception:
            pass
    return '구조·정제·저항구름 조합 기준'


def _v8_is_hard_excluded(row, strict=True):
    try:
        meta = _v89_blue_line_meta(row)
        if meta.get('valid'):
            if meta.get('state') == '과이격' or float(meta.get('gap', 0.0) or 0.0) >= 6.0:
                return True, f"파란점선과이격{float(meta.get('gap', 0.0) or 0.0):+.1f}%"
    except Exception:
        pass
    if _V89_BASE_V8_IS_HARD_EXCLUDED:
        try:
            return _V89_BASE_V8_IS_HARD_EXCLUDED(row, strict=strict)
        except TypeError:
            return _V89_BASE_V8_IS_HARD_EXCLUDED(row)
        except Exception:
            pass
    return False, ''


def _v8_format_bucket(rows):
    if not rows:
        return '- 해당 종목 없음'
    out = []
    for idx, row in enumerate(rows, 1):
        try:
            name = _v8_name(row)
            code = _v8_code(row)
            action, structure = _v8_trade_action(row)
            state = _v8_state(row)
            score = _v8_score_text(row)
            blue_txt = _v89_blue_status_text(row, compact=True)
            score_txt = f" | 점수:{score}" if score else ''
            link = _v8_stock_link_text(code)
            out.append(
                f"{idx}) {name}" + (f"({code})" if code else '') + f"{link}\n"
                f"   - 매매:{action} / 구조:{structure} / 상태:{state}{score_txt}\n"
                f"   - {blue_txt}\n"
                f"   → {_v8_reason(row)}"
            )
        except Exception:
            if _V89_BASE_V8_FORMAT_BUCKET:
                return _V89_BASE_V8_FORMAT_BUCKET(rows)
    return '\n'.join(out)


