def build_trade_action_summary_block_from_frames(
    telegram_targets=None,
    wm_red_top5=None,
    wm_blue_top5=None,
    dante_pick_df=None,
    dante_watch_df=None,
    breakout_pick_df=None,
    breakout_watch_df=None,
    wm_pullback_top5=None,
    wm_late_top5=None,
    dante_ex_df=None,
):
    """V8.9: 파란점선을 상위 필터로 반영한 오늘 매매관점 압축."""
    used = set()

    def action_of(row):
        return _v8_trade_action(row)[0]

    def level_of(row):
        try:
            return build_trade_clarity_view(row).get('level', '')
        except Exception:
            return ''

    def not_hard_bad(row):
        bad, _ = _v8_is_hard_excluded(row, strict=True)
        return not bad

    def blue_state(row):
        return _v89_blue_line_meta(row).get('state', '')

    run = _v8_pick_rows(
        [wm_blue_top5, wm_red_top5, breakout_pick_df, telegram_targets],
        lambda r: not_hard_bad(r) and action_of(r) == '조건부 실행' and blue_state(r) in ('접촉', '위안착'),
        used,
        limit=3,
    )

    pull = _v8_pick_rows(
        [breakout_pick_df, breakout_watch_df, wm_pullback_top5, telegram_targets],
        lambda r: not_hard_bad(r) and action_of(r) in ('눌림 대기', '돌파확인 대기', '확인 대기', '회복 대기', '종가 유지 확인')
                  or (not_hard_bad(r) and level_of(r) in ('wait_blue_reclaim', 'wait_blue_hold', 'wait_blue_support', 'wait_blue_pullback')),
        used,
        limit=4,
    )

    pre = _v8_pick_rows(
        [dante_pick_df, dante_watch_df, wm_pullback_top5, telegram_targets],
        lambda r: not_hard_bad(r) and (action_of(r) == '선취 관찰' or '선취' in _v8_text_blob(r) or '저항전' in _v8_text_blob(r)),
        used,
        limit=4,
    )

    avoid = _v8_pick_rows(
        [dante_ex_df, wm_late_top5, telegram_targets],
        lambda r: action_of(r) == '추격 금지' or _v8_is_hard_excluded(r, strict=True)[0],
        used,
        limit=5,
    )

    hold = _v8_pick_rows(
        [wm_late_top5, telegram_targets],
        lambda r: action_of(r) == '보유자 대응',
        used,
        limit=5,
    )

    top_run = _v8_name(run[0]) if run else '없음'
    top_pull = _v8_name(pull[0]) if pull else '없음'
    top_pre = _v8_name(pre[0]) if pre else '없음'

    link_note = 'HTML 링크와 검색 앵커는 사용하지 않고, 종목명과 코드만 표시합니다.'

    return f"""━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
🎯 [오늘 매매관점 압축]

📌 시장모드: 시장 통합 브리핑 기준 확인
📌 오늘 전략: 파란점선 기준으로 회복·접촉·안착·과이격을 먼저 구분
📌 넥스트 주의: 09:00 이전 신호는 거래량 부족으로 속임수 가능성 있음
📌 09:15~09:18 검색 결과는 1차 검증용, 확정 매수는 09:30 이후 재확인 우대
📌 링크안내: {link_note}

🔥 조건부 실행 후보
{_v8_format_bucket(run)}

👀 눌림·회복 대기 후보
{_v8_format_bucket(pull)}

🧭 선취 관찰 후보
{_v8_format_bucket(pre)}

⛔ 신규 추격 금지
{_v8_format_bucket(avoid)}

🛡️ 보유자 대응
{_v8_format_bucket(hold)}

🧠 오늘 핵심 한 줄
→ 파란점선 아래는 회복 대기, 접촉은 종가 유지 확인, 위안착은 눌림 지지 확인, 과이격은 신규 추격 금지입니다.

📌 오늘 우선순위
- 조건부 실행: {top_run}
- 눌림·회복 대기: {top_pull}
- 선취 관찰: {top_pre}
- 제외 원칙: 추격금지/보유자대응/후행형/가짜수박주의/파란점선 과이격/이격115↑/RSI70↑는 AI 1위 추천 금지
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"""


