    current_msg = f"📢 [오늘의 실시간 TOP 15]\n\n"

    def _build_readable_top15_entry(item, last_section_title=None):
        def _si(v, d=0):
            try:
                return int(float(v))
            except Exception:
                return d

        def _sf(v, d=0.0):
            try:
                return float(v)
            except Exception:
                return d

        name_str = str(item.get('종목명', '') or '').strip()
        code_str = str(item.get('code', '') or '').strip()
        price = _si(item.get('현재가', 0))
        n_grade_raw = item.get('N등급', '')
        n_grade = _cap_grade_label(n_grade_raw, _recommendation_max_grade(item))
        n_combo = str(item.get('N조합', '') or '').strip()
        safe_score = max(0, min(999, _si(item.get('안전점수', 0))))
        n_score = max(0, min(999, _si(item.get('N점수', 0))))
        rsi = _si(item.get('RSI', 0))
        disparity = _si(item.get('이격', 0))
        obv_slope = _si(item.get('OBV기울기', 0))
        bb40 = _sf(item.get('BB40', 0))
        stage = str(item.get('단계상태', 'DROP') or '').strip()
        supply = str(item.get('수급', '-') or '-').strip()
        finance = str(item.get('재무', '-') or '-').strip()
        energy = str(item.get('에너지', '') or '').strip()
        stage_str = describe_stage_status(stage) if stage in ('PASS_A', 'PASS_B') else ''
        rec_phase = str(item.get('추천단계', '') or '').strip()
        section_title = _recommendation_section_title(rec_phase)

        n_tags_raw = str(item.get('N구분', '')).split()
        priority_kw = ['🍉', '💍', '🐍', '🕳️', '💛', '🎯', '💎', '🟣', '📊OBV']
        n_tags_top = []
        for kw in priority_kw:
            for tag in n_tags_raw:
                if kw in tag and tag not in n_tags_top:
                    n_tags_top.append(tag)
                    break
        for tag in n_tags_raw:
            if tag not in n_tags_top and len(n_tags_top) < 4:
                n_tags_top.append(tag)
        key_tags = ' '.join(n_tags_top[:4])

        disp_warn = ''
        if disparity >= 120:
            disp_warn = ' ⚠️과열'
        elif disparity <= 95:
            disp_warn = ' 📍눌림'

        supply_summary = str(item.get('수급요약', '') or '').strip()
        supply_today = str(item.get('수급당일', '') or '').strip()
        supply_3d = str(item.get('수급3일누적', '') or '').strip()
        supply_5d = str(item.get('수급5일누적', '') or '').strip()
        supply_flow = str(item.get('수급판정', '') or '').strip()
        supply_warn = str(item.get('수급경고', '') or '').strip()
        supply_conf = str(item.get('수급신뢰도', '') or '').strip()
        supply_date = str(item.get('수급기준일', '') or '').strip()

        ai_verdict = str(item.get('AI최종판정', '') or '').strip()
        ai_conf = _si(item.get('AI확신도', 0))
        ai_judge = str(item.get('AI심판요약', '') or '').strip()
        ai_reason = str(item.get('AI강한근거', '') or '').strip()
        ai_short = _recommendation_summary_line(item)

        target_p = _si(item.get('🎯목표타점', 0))
        target2_p = _si(item.get('🎯목표2차', 0))
        if target_p > 0 and target2_p > 0 and target2_p < target_p:
            target_p, target2_p = target2_p, target_p
        stop_p = _si(item.get('🚨손절가', 0))
        rr_ratio = _sf(item.get('RR비율', 0))

        item2 = enrich_row_with_human_commentary(item)
        interp = str(item2.get('interpretation_block', '') or '').strip()
        ma5_tag = str(item.get('5일재안착태그', '') or '').strip()
        ma5_comment = str(item.get('5일재안착코멘트', '') or '').strip()
        cloud_tag = str(item.get('저항구름태그', '') or '').strip()
        cloud_comment = str(item.get('저항구름코멘트', '') or '').strip()
        refine_tag = str(item.get('수박정제태그', '') or '').strip()
        refine_comment = str(item.get('수박정제코멘트', '') or '').strip()

        lines = []
        if section_title != last_section_title:
            lines.append(f"\n{section_title}\n")

        lines.append('━━━━━━━━━━━━━━━━━━━━━━━━━━━━')
        lines.append(f"⭐ {n_grade} | {name_str}({code_str}) | {rec_phase}")
        lines.append(f"💰 현재가 {price:,}원 | 안전 {safe_score} | N {n_score}")
        if n_combo:
            lines.append(f"🧬 핵심조합: {n_combo}")
        if key_tags:
            lines.append(f"🏷 핵심태그: {key_tags}")
        tech_line = f"📊 기술: 이격 {disparity}{disp_warn} | RSI {rsi} | BB40 {bb40:.1f} | OBV {obv_slope:+}"
        if stage_str:
            tech_line += f" | {stage_str}"
        lines.append(tech_line)
        lines.append(f"🏦 기본판정: 수급 {supply} | 재무 {finance}" + (f" | {energy}" if energy else ''))
        if supply_summary:
            lines.append(f"📌 요약: {supply_summary}")
        if supply_today:
            lines.append(f"💵 {supply_today}")
        if supply_3d:
            lines.append(f"📦 {supply_3d}")
        if supply_5d:
            lines.append(f"🧲 {supply_5d}")
        if supply_flow:
            lines.append(f"📍 수급판정: {supply_flow}")
        if supply_warn:
            lines.append(f"🚨 수급경고: {supply_warn}")
        if supply_conf or supply_date:
            meta_bits = []
            if supply_conf:
                meta_bits.append(f"신뢰도 {supply_conf}")
            if supply_date:
                meta_bits.append(f"기준일 {supply_date}")
            lines.append('🗂 수급메타: ' + ' | '.join(meta_bits))

        if ma5_tag:
            lines.append(f"🔁 재안착: {ma5_tag}" + (f" | {ma5_comment[:24]}" if ma5_comment else ''))
        if cloud_tag:
            lines.append(f"☁ 저항구름: {cloud_tag}" + (f" | {cloud_comment[:24]}" if cloud_comment else ''))
        if refine_tag:
            lines.append(f"🧪 정제: {refine_tag}" + (f" | {refine_comment[:24]}" if refine_comment else ''))

        if target_p > 0 and stop_p > 0:
            target_line = f"📌 타점: 목표1 {target_p:,}"
            if target2_p > 0:
                target_line += f" → 목표2 {target2_p:,}"
            target_line += f" | 손절 {stop_p:,}"
            if rr_ratio > 0:
                target_line += f" | RR {rr_ratio:.1f}"
            lines.append(target_line)

        if ai_verdict:
            ai_line = f"🧠 AI판정: {ai_verdict}"
            if ai_conf > 0:
                ai_line += f" {ai_conf}점"
            if ai_judge:
                ai_line += f" | {ai_judge[:34]}"
            lines.append(ai_line)
        elif ai_short:
            lines.append(f"💡 한줄결론: {ai_short[:48]}")
        if ai_reason:
            lines.append(f"🪄 근거: {ai_reason[:46]}")
        if interp:
            lines.append(interp)

        entry = "\n".join([x for x in lines if str(x).strip()]) + "\n"
        return section_title, entry

    
    stage_block = ""
    pre_block = build_pre_dolbanji_block("예비돌반지 TOP 5", pre_top5, exact_mode=False)
    exact_block = build_pre_dolbanji_block("HTS 정확복제형 예비돌반지 TOP 5", exact_top5, exact_mode=True)
    lite_block = build_pre_dolbanji_block("신규예비돌반지 Lite TOP 5", lite_top5, exact_mode=False)

    if len(pre_top5) == 0:
        pre_block = ""
    if len(exact_top5) == 0:
        exact_block = ""
    if len(lite_top5) == 0:
        lite_block = ""
    show_pre_dolbanji = bool(len(pre_top5) > 0 or len(exact_top5) > 0 or len(lite_top5) > 0)
    if not show_pre_dolbanji:
        pre_block = ""
        exact_block = ""
        lite_block = ""

    wm_guide_block = build_watermelon_guide_block()
    wm_green_block = build_watermelon_summary_block(all_hits_df_for_pre)
    wm_red_block = build_watermelon_state_block("수박상태 빨강 TOP 5", wm_red_top5)
