def _v93_to_dict(row):
    try:
        return _v92_row_dict(row)
    except Exception:
        try:
            if isinstance(row, dict):
                return dict(row)
            if hasattr(row, "to_dict"):
                return row.to_dict()
        except Exception:
            pass
    return {}


def _v93_pick(d, *keys, default=None):
    try:
        return _v92_pick(d, *keys, default=default)
    except Exception:
        for k in keys:
            try:
                v = d.get(k)
                if v is not None and str(v).strip() != "":
                    return v
            except Exception:
                pass
    return default


def _v93_float(x, default=0.0):
    try:
        return _v92_float(x, default)
    except Exception:
        try:
            if x is None:
                return default
            if isinstance(x, str):
                x = x.replace(",", "").replace("%", "").strip()
            v = float(x)
            if v != v:
                return default
            return v
        except Exception:
            return default


def _v93_int(x, default=0):
    try:
        return int(round(_v93_float(x, default)))
    except Exception:
        return default


def _v93_price(x):
    try:
        return _v92_price(x)
    except Exception:
        v = _v93_float(x, 0)
        return f"{int(round(v)):,}" if v > 0 else "0"


def _v93_text_blob(item):
    d = _v93_to_dict(item)
    keys = [
        '뉴스', 'news', '최근뉴스', '뉴스제목', 'AI재료분류', '재료잔존코멘트',
        'material_comment', '종목명', '테마', 'N구분', '태그', 'tags', '공시',
        '공시태그', '공시내용', '수급요약', '수급판정'
    ]
    vals = []
    for k in keys:
        try:
            v = d.get(k)
            if v is not None and str(v).strip() not in ("", "nan", "None", "null"):
                vals.append(str(v))
        except Exception:
            pass
    return " ".join(vals).lower()


def _v93_count_kw(text, kw_score_map, cap):
    score = 0
    hits = []
    for k, pts in kw_score_map.items():
        try:
            if str(k).lower() in text:
                score += int(pts)
                hits.append(f"{k}+{pts}")
        except Exception:
            pass
    return min(cap, score), hits


