# V9.3: 섹터 레이더 vs 뉴스 테마 충돌 경고
# ─────────────────────────────────────────────────────────────
def _v93_add_theme_conflict_warning(news_text, sector_report=''):
    try:
        nt = str(news_text or '')
        sr = str(sector_report or '')
        warnings = []
        if ('반도체' in nt or 'AI' in nt or 'ai' in nt.lower()) and (
            ('반도체' in sr and ('회피' in sr or '약세' in sr)) or '📉나스닥' in sr
        ):
            warnings.append('반도체/AI 뉴스 키워드는 있으나 섹터 레이더 또는 나스닥 흐름이 약해 오늘 단기 추격은 보수적으로 봅니다.')
        if ('정유' in nt or '에너지' in nt or '유가' in nt) and ('🛢️↑유가' not in sr and '정유/에너지' in sr and '회피' in sr):
            warnings.append('에너지 뉴스 키워드와 실제 섹터테이프가 엇갈립니다. 유가와 XLE/OIH 동행 확인이 필요합니다.')
        if not warnings:
            return nt
        block = '\n\n⚠️ [테마충돌 체크]\n' + '\n'.join(f'- {w}' for w in warnings)
        if '테마충돌 체크' in nt:
            return nt
        return nt.rstrip() + block
    except Exception:
        return news_text


